// Ref helpers (solo se usan si CLOUD_ENABLED)
function _userRef(uid)     { return _db.collection('users').doc(uid).collection('data').doc('main'); }
function _profileRef(uid)  { return _db.collection('users').doc(uid).collection('data').doc('profile'); }
// Documento raíz users/{uid} — almacena is_pro, role, trial_ends_at, stripe_customer_id, fcm_token
function _authDocRef(uid)  { return _db.collection('users').doc(uid); }
// Sub-colección de actividad — alimenta el XP Chart real
function _activityRef(uid) { return _db.collection('users').doc(uid).collection('user_activity'); }

// ── Debounce para guardar en Firestore sin saturar escrituras ──
let _saveTimer = null;
function _scheduleFSsave() {
  if (!CLOUD_ENABLED || !_auth?.currentUser) return;
  clearTimeout(_saveTimer);
  _saveTimer = setTimeout(_saveToFirestore, 2000);
}
async function _saveToFirestore() {
  if (!CLOUD_ENABLED || !_auth?.currentUser) return;
  try {
    await _userRef(_auth.currentUser.uid).set(_buildSavePayload(), { merge: true });
  } catch(e) {
    console.warn('[Life OS] Firestore save error:', e);
  }
}
function _buildSavePayload() {
  const p = {
    xp:S.xp, level:S.level, coins:S.coins,
    tasks:S.tasks, habits:S.habits, routines:S.routines,
    transactions:S.transactions, debts:S.debts, cards:S.cards,
    goals:S.goals, completedGoals:S.completedGoals, calEvents:S.calEvents,
    gymDays:S.gymDays,
    dailyCheckIn:S.dailyCheckIn, checkInStreak:S.checkInStreak,
    healthStats:S.healthStats, saludXP:S.saludXP,
    biblioteca:S.biblioteca, xpMental:S.xpMental,
    bitacora:S.bitacora, aliados:S.aliados,
    pomoMinutos:S.pomoMinutos, pomoSesiones:S.pomoSesiones,
    muscleMap:S.muscleMap, muscleLastUpdate:S.muscleLastUpdate,
    claridad:S.claridad, energia:S.energia, productividad:S.productividad,
    xpHistory:S.xpHistory, dark:S.dark, accent:S.accent,
    lastCalibDate:S.lastCalibDate,
    poderUsage:S.poderUsage,
    saldos:S.saldos||[],
    agencyTab0:(S.agencyTabs||[[],[],[]])[0]||[],
    agencyTab1:(S.agencyTabs||[[],[],[]])[1]||[],
    agencyTab2:(S.agencyTabs||[[],[],[]])[2]||[],
    primeraSesion:S.primeraSesion!==false, onboardingDone:S.onboardingDone||false,
    socialPlans:S.socialPlans||[],
    socialPlanXPBonus:S.socialPlanXPBonus||0,
    modoRecuperacion:S.modoRecuperacion||false,
    modoRecuperacionFecha:S.modoRecuperacionFecha||'',
    ideas:S.ideas||[],
    claudeApiKey:S.claudeApiKey||'',
    gemelo:S.gemelo||{state:'idle',startDate:null,dataPoints:0,lastAnalysis:null,survivalTasks:{}},
  };
  if (CLOUD_ENABLED && _db) {
    p._updatedAt = firebase.firestore.FieldValue.serverTimestamp();
  }
  return p;
}

