const ACCENT_PRESETS = [
  {name:'Cyan',v:'#00e5ff'},{name:'Verde',v:'#4ade80'},{name:'Violeta',v:'#a855f7'},
  {name:'Naranja',v:'#fb923c'},{name:'Rosa',v:'#f472b6'},{name:'Oro',v:'#ffd700'},
  {name:'Coral',v:'#ff6b35'},{name:'Azul',v:'#60a5fa'}
];

function buildAccentPresets() {
  const el = document.getElementById('accent-presets');
  if (!el) return;
  el.innerHTML = ACCENT_PRESETS.map(p => `
    <div class="acc-dot ${S.accent===p.v?'sel':''}" style="background:${p.v}" title="${p.name}" onclick="applyAccent('${p.v}')"></div>`).join('');
}

/** Construye el selector de color en el formulario de registro — usa las mismas clases que ajustes */
function buildRegAccentPicker() {
  const el = document.getElementById('reg-accent-dots'); if (!el) return;
  const cur = document.getElementById('reg-accent')?.value || '#00e5ff';
  el.innerHTML = ACCENT_PRESETS.map(p => `
    <div class="acc-dot ${cur===p.v?'sel':''}" style="background:${p.v}" title="${p.name}" onclick="selectRegAccent('${p.v}')"></div>`).join('');
}

function selectRegAccent(color) {
  const inp = document.getElementById('reg-accent');
  if (inp) inp.value = color;
  // Previsualizar en tiempo real
  applyAccent(color);
  buildRegAccentPicker();
}

function applyAccent(c) {
  S.accent = c;
  const r=parseInt(c.slice(1,3),16),g=parseInt(c.slice(3,5),16),b=parseInt(c.slice(5,7),16);
  const dk = v => Math.max(0, Math.round(v * 0.68));
  document.documentElement.style.setProperty('--accent', c);
  document.documentElement.style.setProperty('--accent-rgb', `${r},${g},${b}`);
  document.documentElement.style.setProperty('--accent-dark', `rgb(${dk(r)},${dk(g)},${dk(b)})`);
  document.documentElement.style.setProperty('--accent-dim', `rgba(${r},${g},${b},.15)`);
  document.documentElement.style.setProperty('--accent-glow', `0 0 20px rgba(${r},${g},${b},.4)`);
  buildAccentPresets();
  document.getElementById('custom-hex') && (document.getElementById('custom-hex').value = c);
  document.getElementById('custom-color') && (document.getElementById('custom-color').value = c);
  setTimeout(()=>{ initRadarChart(); initVolumeChart(); updatePieCharts(); syncHeatmapColors(); }, 100);
  guardarDatos();
  // Persistir color en Firebase profile para sincronía entre dispositivos
  if (CLOUD_ENABLED && _auth?.currentUser) {
    _profileRef(_auth.currentUser.uid).update({ accent: c }).catch(() => {});
  }
}

function applyCustomAccent() {
  const v = document.getElementById('custom-hex').value.trim();
  if (/^#[0-9a-fA-F]{6}$/.test(v)) applyAccent(v);
}

document.getElementById('custom-color')?.addEventListener('input', e=>{
  document.getElementById('custom-hex').value = e.target.value;
});

