function _addTaskOriginal() {
  const name = document.getElementById('t-name').value.trim();
  if (!name) return;
  S.tasks.unshift({ id:uid(), name, desc:document.getElementById('t-desc').value, date:document.getElementById('t-date').value, time:document.getElementById('t-time').value, done:false });
  ['t-name','t-desc'].forEach(id=>document.getElementById(id).value='');
  renderTasks();
}

function renderTasks() {
  const el = document.getElementById('task-list');
  if (!el) return;
  if (!S.tasks.length) { el.innerHTML='<div style="text-align:center;padding:20px;font-size:13px;color:var(--text3)">No hay tareas. ¡Agrega una!</div>'; return; }
  el.innerHTML = S.tasks.map(t=>`
    <div class="task-item ${t.done?'done':''}">
      <div class="task-cb ${t.done?'checked':''}" onclick="toggleTask('${t.id}')">${t.done?'✓':''}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;text-decoration:${t.done?'line-through':'none'};opacity:${t.done?.5:1}">${escHtml(t.name)}</div>
        ${t.desc?`<div style="font-size:11px;color:var(--text3);margin-top:2px">${escHtml(t.desc)}</div>`:''}
        <div style="display:flex;gap:8px;margin-top:4px;flex-wrap:wrap">
          ${t.date?`<span style="font-size:10px;color:var(--accent);font-family:'JetBrains Mono',monospace">📅 ${t.date}</span>`:''}
          ${t.time?`<span style="font-size:10px;color:var(--purple);font-family:'JetBrains Mono',monospace">🕐 ${t.time}</span>`:''}
          ${t.done?`<span class="badge badge-xp" style="font-size:10px">+50 XP ✓</span>`:''}
        </div>
      </div>
      <div style="display:flex;gap:6px;flex-shrink:0">
        ${!t.done?`<button class="btn btn-g btn-sm" onclick="openEditTask('${t.id}')" title="Editar">✏️</button>`:''}
        ${!t.done?`<button class="btn btn-sm" onclick="startTaskPomodoro('${t.id}')" title="Iniciar Pomodoro" style="background:rgba(168,85,247,.1);border:1px solid rgba(168,85,247,.3)!important;color:#a855f7;padding:5px 10px!important;font-size:11px!important;border-radius:8px!important">⏱</button>`:''}
        <button class="btn btn-d" onclick="deleteTask('${t.id}')">🗑</button>
      </div>
    </div>`).join('');
}

function toggleTask(id) {
  const t = S.tasks.find(x=>x.id===id);
  if (!t || t.done) return;
  t.done = true;
  gainXP(50);
  _logActivity('task', 50, t.name || 'Tarea completada');
  spawnConfetti();
  showToast('🎉 +50 XP ganado!');
  renderTasks();
  updateDashboardTaskCount();
}

function deleteTask(id) { S.tasks = S.tasks.filter(x=>x.id!==id); renderTasks(); updateDashboardTaskCount(); renderUpcomingList && renderUpcomingList(); }

function openEditTask(id) {
  const t = S.tasks.find(x=>x.id===id); if (!t) return;
  S.editingTask = id;
  document.getElementById('et-name').value = t.name;
  document.getElementById('et-desc').value = t.desc||'';
  document.getElementById('et-date').value = t.date||'';
  document.getElementById('et-time').value = t.time||'';
  openModal('modal-edit-task');
}

function saveTaskEdit() {
  const t = S.tasks.find(x=>x.id===S.editingTask); if (!t) return;
  t.name = document.getElementById('et-name').value||t.name;
  t.desc = document.getElementById('et-desc').value;
  t.date = document.getElementById('et-date').value;
  t.time = document.getElementById('et-time').value;
  closeModal('modal-edit-task');
  renderTasks();
}

/* ═══════════════════════════════════════════
   HABITS
═══════════════════════════════════════════ */
/* ── Detecta emoji según el nombre del hábito (tolerante a errores ortográficos) ── */
function habitEmoji(name) {
  const n = name.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g,'') // quita acentos
    .replace(/[^a-z0-9\s]/g,'');

  const rules = [
    // Agua / hidratación
    [/agua|hidratar|hidrat|tomar.*vaso|beber/,'💧'],
    // Ejercicio / gym
    [/gym|gimnasio|pesas|entrena|workout|ejerci|lift|fuerza/,'🏋️'],
    // Correr / cardio
    [/corr|trotar|cardio|jogging|run/,'🏃'],
    // Caminar
    [/camin|walk|pasear/,'🚶'],
    // Meditación / respiración
    [/medita|mindful|respira|zen|calma/,'🧘'],
    // Dormir / sueño
    [/dorm|sueno|descanso|sleep|cama.*temprano|acosta/,'😴'],
    // Leer
    [/leer|lectura|libro|read|pag|hojas/,'📖'],
    // Escribir / diario / bitacora
    [/escrib|diario|bitacora|journal|nota/,'📓'],
    // Proteína / suplementos
    [/protein|suplement|vitamina|creatina|colage/,'💊'],
    // Comer sano / fruta / verdura
    [/fruta|verdura|ensalada|comer.*(sano|bien)|dieta|vegetal/,'🥗'],
    // Desayuno / comida
    [/desayun|almuez|cena|comida|meal/,'🍽️'],
    // No azúcar / no alcohol / no comida chatarra
    [/sin.*azucar|sin.*alcohol|sin.*chatarra|evitar.*dulce|no.*refresco/,'🚫'],
    // Celular / pantalla / redes
    [/celular|telefono|pantalla|redes.*social|instagram|tiktok|twitter/,'📵'],
    // Trabajo / productividad
    [/trabaj|productiv|tarea|proyecto|deadlin/,'💼'],
    // Estudiar / aprender
    [/estudi|aprender|curso|clase|idioma|ingles|frances/,'🎓'],
    // Finanzas / ahorro
    [/ahorr|finanza|dinero|invert|gasto|presupuest/,'💰'],
    // Yoga / stretching
    [/yoga|stretch|estir|flexibil|movilidad/,'🤸'],
    // Ciclismo
    [/bicileta|bici|cicl|cycling/,'🚴'],
    // Natación
    [/nata|nadar|swim|alberca|piscina/,'🏊'],
    // Fútbol / deporte equipo
    [/futbol|soccer|basquet|tenis|padel|deporte/,'⚽'],
    // Vitaminas / salud
    [/salud|bienestar|wellness|checkup|doctor/,'🏥'],
    // Gratitud
    [/gratitud|agradec|gracias/,'🙏'],
    // Sol / mañana temprano
    [/madrugar|amanecer|sol de|manana temprano|levant.*temprano/,'🌅'],
    // No fumar / no vicios
    [/fumar|cigarro|vicio|alcohol|licor/,'🚭'],
    // Organización / limpieza
    [/orden|limpiar|organiz|tend.*cama|habitacion/,'🧹'],
    // Pasos / movimiento
    [/pasos|steps|movimient|activ.*fisic/,'👟'],
    // Música / instrumento
    [/guitar|piano|musica|instrumen|tocar/,'🎸'],
    // Código / programar
    [/program|codigo|develop|software|app/,'💻'],
    // Familia / amigos / social
    [/familia|amigo|social|llam.*a|hablar.*con/,'👨‍👩‍👧'],
    // Postura
    [/postura|espalda|columna/,'🪑'],
  ];

  for (const [re, emoji] of rules) {
    if (re.test(n)) return emoji;
  }
  return '⭐'; // fallback genérico
}

function addHabit() {
  const raw = document.getElementById('new-habit').value.trim(); if (!raw) return;
  const emoji = habitEmoji(raw);
  const name  = emoji + ' ' + raw;
  S.habits.push({ id:uid(), name, streak:0, completedToday:false, lastCompletedDate:'' });
  document.getElementById('new-habit').value='';
  renderHabits();
  guardarDatos();
}

function renderHabits() {
  const el = document.getElementById('habit-list');
  if (!el) return;
  const maxStreak = S.habits.reduce((a, h) => Math.max(a, h.streak), 0);
  document.getElementById('h-streak') && (document.getElementById('h-streak').textContent = maxStreak + ' días');
  document.getElementById('h-count')  && (document.getElementById('h-count').textContent  = S.habits.length);
  if (!S.habits.length) {
    el.innerHTML = '<div style="text-align:center;padding:20px;font-size:13px;color:var(--text3)">Agrega tu primer hábito arriba</div>';
    return;
  }
  el.innerHTML = S.habits.map(h => {
    ensureHabitBattery(h);
    const bState = getBatteryState(h.battery);
    const bColor = { high: 'var(--accent)', med: '#fb923c', low: 'var(--red)', dead: 'rgba(248,113,113,.4)' }[bState];
    return `
    <div class="habit-item ${h.completedToday ? 'done-h' : ''}" data-battery="${bState}">
      <div class="habit-check ${h.completedToday ? 'on' : ''}" onclick="toggleHabit('${h.id}')">${h.completedToday ? '✓' : ''}</div>
      <div style="flex:1">
        <div style="font-size:13px;font-weight:600;text-decoration:${h.completedToday ? 'line-through' : 'none'};opacity:${h.completedToday ? .6 : 1}">${escHtml(h.name)}</div>
        <div style="font-size:11px;color:#ff6b35;margin-top:2px;font-family:'JetBrains Mono',monospace">🔥 Racha: ${h.streak} días</div>
      </div>
      <div class="habit-battery" title="Batería del hábito">
        <div class="battery-bar-wrap">
          <div class="battery-bar-fill" style="width:${h.battery}%;background:${bColor}"></div>
        </div>
        <span class="battery-pct">${h.battery}%</span>
      </div>
      <button class="btn btn-g btn-sm" onclick="openEditHabit('${h.id}')">✏️</button>
      <button class="btn btn-d" onclick="deleteHabit('${h.id}')">🗑</button>
    </div>`;
  }).join('');
  updateGlobalCore();
  renderMorningBriefing();
}

function toggleHabit(id) {
  const h = S.habits.find(x => x.id === id); if (!h) return;
  ensureHabitBattery(h);

  const todayKey = today();
  const wasCompleted = h.completedToday;

  // Alternar estado SOLO de este hábito — nunca toca los demás
  h.completedToday = !wasCompleted;

  if (h.completedToday) {
    // Completando: solo incrementar racha si no se había completado hoy ya
    if (h.lastCompletedDate !== todayKey) {
      h.streak = (h.streak || 0) + 1;
      h.lastCompletedDate = todayKey;
    }
    h.battery = Math.min(100, (h.battery || 0) + 25);
    // Historial para heatmap
    if (!h.history) h.history = [];
    if (!h.history.includes(todayKey)) h.history.push(todayKey);
    gainXP(25);
    _logActivity('habit', 25, h.name || 'Hábito completado');
  } else {
    // Desmarcando: revertir racha solo si se completó hoy mismo
    if (h.lastCompletedDate === todayKey) {
      h.streak = Math.max(0, (h.streak || 1) - 1);
      h.lastCompletedDate = '';
    }
    h.battery = Math.max(0, (h.battery || 25) - 25);
    // Quitar del historial de hoy
    if (h.history) h.history = h.history.filter(d => d !== todayKey);
  }

  // Gym tracking
  const isGym = /gym|gimnasio|entreno|workout|ejercicio|lift/i.test(h.name);
  if (isGym) {
    if (h.completedToday) { if (!S.gymDays[todayKey]) S.gymDays[todayKey] = 1; }
    else delete S.gymDays[todayKey];
    if (document.getElementById('page-physical')?.classList.contains('active')) buildFreqHeatmap();
  }

  showToast(h.completedToday ? `✅ Hábito completado! 🔋 +25% · 🔥 Racha: ${h.streak}d` : '↩️ Hábito desmarcado');
  renderHabits();
  guardarDatos();
}

function deleteHabit(id) { S.habits = S.habits.filter(x=>x.id!==id); renderHabits(); }

function openEditHabit(id) {
  S.editingHabit = id;
  const h = S.habits.find(x=>x.id===id);
  document.getElementById('eh-name').value = h?.name||'';
  openModal('modal-edit-habit');
}

function saveHabitEdit() {
  const h = S.habits.find(x=>x.id===S.editingHabit); if (!h) return;
  const raw = (document.getElementById('eh-name').value || h.name).trim();
  // Quitar emoji anterior si ya tenía uno al inicio, para no duplicar
  const stripped = raw.replace(/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})\s*/u, '');
  const emoji = habitEmoji(stripped);
  h.name = emoji + ' ' + stripped;
  closeModal('modal-edit-habit');
  renderHabits();
  guardarDatos();
}

/* ═══════════════════════════════════════════
   HEATMAP — Accent-synced, real habit data, time ranges
═══════════════════════════════════════════ */
let _heatmapRange = 'week';

function setHeatmapRange(range) {
  _heatmapRange = range;
  document.querySelectorAll('.hm-range-btn').forEach(btn => {
    const isOn = btn.dataset.range === range;
    btn.style.background = isOn ? 'var(--accent)' : 'transparent';
    btn.style.color      = isOn ? '#000' : 'var(--text3)';
  });
  buildHeatmap();
}

/* Shared grid renderer used by both heatmap functions */
function _buildHeatmapGrid(el, dataMap, totalItems, totalDays, cols, opts) {
  if (!el) return;
  opts = opts || {};
  el.style.gridTemplateColumns = `repeat(${cols}, 1fr)`;
  const now = new Date();
  let html = '';
  const weeks = Math.ceil(totalDays / 7);
  for (let w = weeks - 1; w >= 0; w--) {
    for (let d = 0; d < 7; d++) {
      const dayIndex = w * 7 + d;
      if (dayIndex >= totalDays) { html += '<div></div>'; continue; }
      const dt = new Date(now);
      dt.setDate(dt.getDate() - dayIndex);
      const key = dt.toISOString().split('T')[0];
      const count = dataMap[key] || 0;
      const isToday = key === today();
      let lvl;
      if (opts.binaryMode) {
        lvl = count > 0 ? 4 : 0;
      } else {
        const pct = count / (totalItems || 1);
        lvl = count === 0 ? 0 : pct < 0.25 ? 1 : pct < 0.5 ? 2 : pct < 0.85 ? 3 : 4;
      }
      const title = opts.binaryMode
        ? `${key}${count > 0 ? ' — 🏋️ Entrenado' : ''}`
        : `${key}: ${Math.round((count / (totalItems || 1)) * 100)}% completado`;
      html += `<div class="hm-cell hm${lvl}" title="${title}" style="${isToday ? 'outline:1px solid var(--accent);' : ''}"></div>`;
    }
  }
  el.innerHTML = html;
  syncHeatmapColors();
}

function buildHeatmap() {
  const el = document.getElementById('heatmap'); if (!el) return;
  const habitCompletionMap = {};
  (S.habits || []).forEach(h => {
    (h.history || []).forEach(dateStr => {
      habitCompletionMap[dateStr] = (habitCompletionMap[dateStr] || 0) + 1;
    });
  });
  let totalDays, cols;
  switch (_heatmapRange) {
    case 'week':    totalDays = 7;   cols = 7;  break;
    case 'month':   totalDays = 35;  cols = 7;  break;
    case '3months': totalDays = 91;  cols = 13; break;
    default:        totalDays = 180; cols = 18; break;
  }
  _buildHeatmapGrid(el, habitCompletionMap, S.habits.length || 1, totalDays, cols);
}

function syncHeatmapColors() {
  const accent = S.accent || '#00e5ff';
  const hex = accent.replace('#','');
  const r = parseInt(hex.slice(0,2),16), g = parseInt(hex.slice(2,4),16), b = parseInt(hex.slice(4,6),16);
  const styleId = 'hm-accent-style';
  let styleEl = document.getElementById(styleId);
  if (!styleEl) { styleEl = document.createElement('style'); styleEl.id = styleId; document.head.appendChild(styleEl); }
  styleEl.textContent = `
    .hm1{background:rgba(${r},${g},${b},.18)!important}
    .hm2{background:rgba(${r},${g},${b},.4)!important}
    .hm3{background:rgba(${r},${g},${b},.68)!important}
    .hm4{background:rgba(${r},${g},${b},1)!important}
  `;
}

/* ═══════════════════════════════════════════
   PHYSICAL
═══════════════════════════════════════════ */
const MUSCLE_DATA = [
  {name:'Pecho',pct:65,color:'#00e5ff'},{name:'Espalda',pct:80,color:'#a855f7'},
  {name:'Piernas',pct:45,color:'#ffd700'},{name:'Hombros',pct:55,color:'#ff6b35'},
  {name:'Bíceps',pct:72,color:'#4ade80'},{name:'Tríceps',pct:68,color:'#f472b6'},
  {name:'Abdomen',pct:30,color:'#fb923c'},{name:'Glúteos',pct:20,color:'#60a5fa'}
];

function buildMuscleMap() {
  const el = document.getElementById('muscle-bars'); if (!el) return;
  el.innerHTML = MUSCLE_DATA.slice(0,6).map(m=>`
    <div style="margin-bottom:8px">
      <div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text2);margin-bottom:3px">
        <span>${m.name}</span><span style="color:${m.color};font-weight:700">${m.pct}%</span>
      </div>
      <div style="height:7px;border-radius:4px;background:rgba(255,255,255,.06);overflow:hidden">
        <div class="m-bar" style="width:${m.pct}%;background:${m.color}"></div>
      </div>
    </div>`).join('');

  // Illuminate active SVG elements based on muscleMap values
  const isFemale = (typeof _bodyGender!=='undefined') && _bodyGender==='f';
  const prefix = isFemale ? 'npc-ff-' : 'npc-fm-';
  const muscleToId = {
    pecho: prefix+'pecho',
    piernas: prefix+'piernas',
    hombros: prefix+'hombros',
    biceps: prefix+'biceps',
    abdomen: prefix+'abdomen'
  };
  const muscleColors = {pecho:'#00e5ff',piernas: isFemale?'#ffb4c8':'#ffd700',hombros:'#ff6b35',biceps:'#4ade80',abdomen:'#d4a017'};
  Object.entries(muscleToId).forEach(([muscle, id])=>{
    const el = document.getElementById(id);
    if(!el) return;
    const pct = S.muscleMap[muscle] || 30;
    const alpha = 0.15 + (pct/100)*0.65;
    const color = muscleColors[muscle];
    const r=parseInt(color.slice(1,3),16),g=parseInt(color.slice(3,5),16),b=parseInt(color.slice(5,7),16);
    el.setAttribute('fill', `rgba(${r},${g},${b},${alpha.toFixed(2)})`);
    el.setAttribute('filter', pct>60?`drop-shadow(0 0 4px ${color}88)`:'none');
  });
}

// Alias used by setBodyGender
function renderMuscleBars() { buildMuscleMap(); }

function buildFreqHeatmap() {
  const el = document.getElementById('freq-heatmap'); if (!el) return;
  const now = new Date();
  const totalDays = 63; // ~9 weeks
  const cols = 9;

  // Update stat card entrenos count
  const y = now.getFullYear(), m = now.getMonth();
  const prefix = `${y}-${String(m+1).padStart(2,'0')}-`;
  const gymCount = Object.keys(S.gymDays).filter(k => k.startsWith(prefix)).length;
  document.getElementById('bio-entrenos') && (document.getElementById('bio-entrenos').textContent = gymCount);

  _buildHeatmapGrid(el, S.gymDays, 1, totalDays, cols, { binaryMode: true });
}

