/**
 * renderXPChart — dibuja el XP ganado en los últimos 7 días desde Firestore user_activity.
 * NOTA: Esta colección se puebla a partir de la implementación de user_activity.
 * Usuarios registrados antes de esta versión verán el chart vacío hasta acumular nuevos datos.
 */
async function renderXPChart(uid) {
  const canvas   = document.getElementById('xpRealChart');
  const emptyEl  = document.getElementById('xp-chart-empty');
  if (!canvas) return;

  // Sin Firebase o sin usuario autenticado: ocultar canvas
  if (!CLOUD_ENABLED || !_auth?.currentUser) {
    canvas.style.display = 'none';
    if (emptyEl) emptyEl.style.display = 'block';
    return;
  }

  try {
    const hace7dias = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
    const snap      = await _activityRef(uid)
      .where('completed_at', '>=', firebase.firestore.Timestamp.fromDate(hace7dias))
      .orderBy('completed_at', 'asc')
      .get();

    // Agrupar XP por día
    const xpPorDia = {};
    snap.forEach(doc => {
      const data = doc.data();
      const fecha = data.completed_at?.toDate
        ? data.completed_at.toDate().toLocaleDateString('es-MX', { weekday:'short', day:'numeric' })
        : '';
      if (fecha) xpPorDia[fecha] = (xpPorDia[fecha] || 0) + (data.xp_earned || 0);
    });

    const labels = Object.keys(xpPorDia);
    const data   = Object.values(xpPorDia);

    // Sin datos: mostrar estado vacío
    if (!labels.length) {
      canvas.style.display = 'none';
      if (emptyEl) emptyEl.style.display = 'block';
      return;
    }
    canvas.style.display = '';
    if (emptyEl) emptyEl.style.display = 'none';

    // Destruir instancia anterior si existe
    if (S.charts && S.charts.xpReal) { S.charts.xpReal.destroy(); }
    if (!S.charts) S.charts = {};

    // Crear gradiente
    const ctx      = canvas.getContext('2d');
    const gradient = ctx.createLinearGradient(0, 0, 0, canvas.height);
    gradient.addColorStop(0,   'rgba(99,102,241,0.4)');
    gradient.addColorStop(1,   'rgba(99,102,241,0)');

    S.charts.xpReal = new Chart(ctx, {
      type: 'line',
      data: {
        labels,
        datasets: [{
          data,
          borderColor:      'rgba(99,102,241,1)',
          backgroundColor:  gradient,
          borderWidth:      2,
          pointBackgroundColor: 'rgba(99,102,241,1)',
          tension:          0.4,
          fill:             true,
        }],
      },
      options: {
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: ctx => `${ctx.parsed.y} XP`,
            },
          },
        },
        scales: {
          x: { grid:{ color:'rgba(0,229,255,.06)' }, ticks:{ color:'rgba(200,200,255,.5)', font:{ family:'Syne' } } },
          y: { grid:{ color:'rgba(0,229,255,.06)' }, ticks:{ color:'rgba(200,200,255,.5)', font:{ family:'Syne' } }, beginAtZero:true },
        },
      },
    });

  } catch(e) {
    console.warn('[Life OS] renderXPChart error:', e);
    canvas.style.display = 'none';
    if (emptyEl) emptyEl.style.display = 'block';
  }
}

