function addRoutine() {
  const name = document.getElementById('new-routine-name').value.trim(); if (!name) return;
  S.routines.push({ id:uid(), name, active:true, exercises:[] });
  document.getElementById('new-routine-name').value='';
  renderRoutines();
}

function renderRoutines() {
  const el = document.getElementById('routines-container'); if (!el) return;
  if (!S.routines.length) { el.innerHTML='<div style="text-align:center;padding:30px;font-size:13px;color:var(--text3)">No hay rutinas. ¡Crea una!</div>'; renderRutinasFrecuentes(); return; }
  el.innerHTML = S.routines.map(r=>`
    <div class="card">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;flex-wrap:wrap;gap:8px">
        <div>
          <div class="f-display" style="font-size:14px;color:${r.active?'var(--accent)':'var(--text3)'};margin-bottom:4px">${escHtml(r.name)}</div>
          <span style="font-size:11px;color:${r.active?'var(--green)':'var(--red)'}">${r.active?'● Activa':'○ Inactiva'}</span>
        </div>
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          <button class="btn btn-a" onclick="enterGymMode('${r.id}')">🏋️ Modo Gym</button>
          <button class="btn btn-g btn-sm" onclick="openEditRoutine('${r.id}')">✏️</button>
          <button class="btn btn-g btn-sm" onclick="toggleRoutineActive('${r.id}')">${r.active?'Pausar':'Activar'}</button>
          <button class="btn btn-d" onclick="deleteRoutine('${r.id}')">🗑</button>
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-bottom:12px">
        <input class="inp f1" id="ex-inp-${r.id}" placeholder="Agregar ejercicio (Enter)" onkeydown="if(event.key==='Enter')addExercise('${r.id}')"/>
        <button class="btn btn-g btn-sm" onclick="addExercise('${r.id}')">+</button>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:8px">
        ${(r.exercises||[]).map(ex=>`
          <div style="background:rgba(0,229,255,.06);border:1px solid rgba(0,229,255,.15);border-radius:10px;padding:6px 12px;font-size:12px;display:flex;align-items:center;gap:8px">
            <span>${escHtml(ex.name)}</span>
            <span style="color:var(--accent);font-family:'JetBrains Mono',monospace;font-size:10px">${ex.sets.length} sets</span>
            <span onclick="removeExercise('${r.id}','${ex.id}')" style="cursor:pointer;color:var(--red);font-size:14px">×</span>
          </div>`).join('')}
      </div>
    </div>`).join('');
  renderRutinasFrecuentes();
}

function addExercise(routineId) {
  const inp = document.getElementById('ex-inp-'+routineId); if (!inp) return;
  const name = inp.value.trim(); if (!name) return;
  const r = S.routines.find(x=>x.id===routineId); if (!r) return;
  r.exercises.push({ id:uid(), name, sets:[] });
  inp.value='';
  renderRoutines();
}

function removeExercise(rId, exId) {
  const r = S.routines.find(x=>x.id===rId); if (!r) return;
  r.exercises = r.exercises.filter(e=>e.id!==exId);
  renderRoutines();
}

function toggleRoutineActive(id) {
  const r = S.routines.find(x=>x.id===id); if (!r) return;
  r.active = !r.active; renderRoutines();
}

function deleteRoutine(id) {
  S.routines = S.routines.filter(x=>x.id!==id); renderRoutines();
}

function openEditRoutine(id) {
  S.editingRoutine = id;
  const r = S.routines.find(x=>x.id===id);
  document.getElementById('er-name').value = r?.name||'';
  openModal('modal-edit-routine');
}

function saveRoutineEdit() {
  const r = S.routines.find(x=>x.id===S.editingRoutine); if (!r) return;
  r.name = document.getElementById('er-name').value||r.name;
  closeModal('modal-edit-routine'); renderRoutines();
}

function enterGymMode(routineId) {
  const r = S.routines.find(x=>x.id===routineId); if (!r) return;
  S.gymActiveRoutine = routineId; S.gymActiveExIdx = 0;
  document.getElementById('routine-list-view').style.display='none';
  document.getElementById('gym-mode-view').style.display='block';
  document.getElementById('gym-routine-name').textContent = r.name;
  renderGymMode();
}

function renderGymMode() {
  const r = S.routines.find(x=>x.id===S.gymActiveRoutine); if (!r) return;
  const tabs = document.getElementById('gym-ex-tabs');
  const tracker = document.getElementById('gym-ex-tracker');
  if (!r.exercises.length) { tabs.innerHTML=''; tracker.innerHTML='<div class="card" style="text-align:center;padding:30px;font-size:13px;color:var(--text3)">Esta rutina no tiene ejercicios. Agrégalos primero.</div>'; return; }
  tabs.innerHTML = r.exercises.map((ex,i)=>`
    <button class="tab-btn ${i===S.gymActiveExIdx?'on':'off'}" onclick="setGymEx(${i})">${escHtml(ex.name)}</button>`).join('');
  const ex = r.exercises[S.gymActiveExIdx];
  if (!ex) return;
  const maxW = ex.sets.length ? Math.max(...ex.sets.map(s=>s.weight)) : 0;
  tracker.innerHTML = `
    <div class="card">
      <div class="f-display c-accent" style="font-size:16px;font-weight:900;margin-bottom:4px">${escHtml(ex.name)}</div>
      <div style="font-size:12px;color:var(--text2);margin-bottom:16px">${ex.sets.length} series registradas${maxW>0?' — Máx: '+maxW+' kg':''}</div>
      <div id="sets-log" style="display:flex;flex-direction:column;gap:6px;margin-bottom:16px">
        ${!ex.sets.length?'<div style="font-size:12px;color:var(--text3)">No hay series. ¡Agrega tu primera!</div>':''}
        ${ex.sets.map((s,i)=>`
          <div class="set-row ${s.isPR?'set-pr':'set-normal'}">
            <span class="f-display" style="font-size:11px;color:var(--text3);width:28px">S${i+1}</span>
            <span class="f-mono" style="font-size:14px;font-weight:700;color:${s.isPR?'var(--gold)':'var(--accent)'}">${s.weight} kg</span>
            <span style="font-size:12px;color:var(--text2)">× ${s.reps} reps</span>
            ${s.isPR?'<span style="font-size:10px;background:rgba(255,215,0,.18);color:var(--gold);padding:2px 8px;border-radius:20px;font-weight:700">🏆 PR</span>':''}
          </div>`).join('')}
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr auto;gap:10px;align-items:flex-end">
        <div>
          <div style="font-size:10px;color:var(--text3);margin-bottom:4px">PESO (kg)</div>
          <input class="inp" id="gym-weight" type="number" placeholder="Ej: 80"/>
        </div>
        <div>
          <div style="font-size:10px;color:var(--text3);margin-bottom:4px">REPS</div>
          <input class="inp" id="gym-reps" type="number" value="10"/>
        </div>
        <button class="btn btn-a" onclick="addGymSet('${r.id}','${ex.id}')">+ Serie</button>
      </div>
    </div>`;
}

function setGymEx(idx) { S.gymActiveExIdx=idx; renderGymMode(); }

function addGymSet(rId, exId) {
  const w = parseFloat(document.getElementById('gym-weight').value);
  const reps = parseInt(document.getElementById('gym-reps').value)||10;
  if (!w||isNaN(w)) return;
  const r = S.routines.find(x=>x.id===rId); if (!r) return;
  const ex = r.exercises.find(x=>x.id===exId); if (!ex) return;
  const prevMax = ex.sets.length ? Math.max(...ex.sets.map(s=>s.weight)) : 0;
  const isPR = w>prevMax && prevMax>0;
  ex.sets.push({ id:uid(), weight:w, reps, isPR });
  if (isPR) {
    S.coins++;
    updateXP();
    openModal('coin-modal');
    _logActivity('workout', 30, '🏆 PR — ' + (ex.name || 'Ejercicio') + ' ' + w + 'kg × ' + reps + ' reps');
  } else {
    _logActivity('workout', 10, (ex.name || 'Ejercicio') + ' ' + w + 'kg × ' + reps + ' reps');
  }
  renderGymMode();
}

