let personalBalance = 0;
let piePChart=null, pieAChart=null;

function toggleCuotas() {
  const v = document.getElementById('tx-cuotas').checked;
  document.getElementById('tx-num-cuotas').style.display = v?'block':'none';
}

function openTxModal() {
  // Poblar dropdown de saldos dinámicamente
  const saldoSel  = document.getElementById('tx-saldo-select');
  const scopeSel  = document.getElementById('tx-scope');
  const saldos    = S.saldos || [];
  if (saldos.length > 1 && saldoSel) {
    saldoSel.innerHTML = saldos.map(s =>
      `<option value="${s.id}">${escHtml(s.nombre)} (${fmt(s.monto)})</option>`
    ).join('');
    saldoSel.style.display = '';
    scopeSel.style.display  = 'none';
  } else {
    saldoSel.style.display  = 'none';
    scopeSel.style.display  = '';
  }
  openModal('modal-tx');
}

function addTransaction() {
  const amount = parseFloat(document.getElementById('tx-amount').value); if (!amount||amount<=0) return;
  // Determinar saldo destino: si hay dropdown de saldos visible, usarlo; si no, el scope hidden
  const saldoSel = document.getElementById('tx-saldo-select');
  const scopeVal = (saldoSel && saldoSel.style.display !== 'none')
    ? saldoSel.value
    : document.getElementById('tx-scope').value;
  const tx = {
    id:uid(), type:document.getElementById('tx-type').value, scope:scopeVal,
    category:document.getElementById('tx-cat').value, amount, desc:document.getElementById('tx-desc').value,
    date:document.getElementById('tx-date').value||today(), cuotas:document.getElementById('tx-cuotas').checked,
    numCuotas:document.getElementById('tx-num-cuotas').value
  };
  S.transactions.unshift(tx);
  _logActivity('finance', 5, (tx.type === 'entrada' ? 'Ingreso' : 'Gasto') + ': ' + (tx.desc || tx.category || 'transacción'));
  // Actualizar saldo correspondiente
  const saldoObj = (S.saldos||[]).find(s => s.id === tx.scope);
  if (saldoObj) {
    saldoObj.monto += tx.type === 'entrada' ? amount : -amount;
  } else if (tx.scope === 'personal') {
    personalBalance += tx.type === 'entrada' ? amount : -amount;
  }
  document.getElementById('tx-amount').value='';
  document.getElementById('tx-desc').value='';
  closeModal('modal-tx');
  updateFinancialDisplay();
}

function updateFinancialDisplay() {
  document.getElementById('fin-personal-bal').textContent = fmt(personalBalance);
  document.getElementById('db-personal-bal').textContent = fmt(personalBalance);
  const pIn  = S.transactions.filter(t=>t.scope==='personal'&&t.type==='entrada').reduce((a,t)=>a+t.amount,0);
  const pOut = S.transactions.filter(t=>t.scope==='personal'&&t.type==='salida').reduce((a,t)=>a+t.amount,0);
  document.getElementById('fin-p-in').textContent = fmt(pIn);
  document.getElementById('fin-p-out').textContent = fmt(pOut);
  updatePieCharts();
  renderTransactions();
  renderDebts();
  renderCards();
}

function updatePieCharts() {
  const pExp = S.transactions.filter(t=>t.scope==='personal'&&t.type==='salida');
  buildPie('piePersonal','pie-p-empty','pie-p-legend',pExp);
}

function buildPie(canvasId, emptyId, legendId, txs) {
  const canvas = document.getElementById(canvasId); if (!canvas) return;
  const emptyEl = document.getElementById(emptyId);
  const legendEl = document.getElementById(legendId);
  if (!txs.length) {
    if (emptyEl) emptyEl.style.display='flex';
    canvas.style.display='none';
    if (legendEl) legendEl.innerHTML='<div style="font-size:11px;color:var(--text3);padding:8px">Agrega transacciones para ver el gráfico</div>';
    return;
  }
  if (emptyEl) emptyEl.style.display='none';
  canvas.style.display='block';
  const map={};
  txs.forEach(t=>{ map[t.category]=(map[t.category]||0)+t.amount; });
  const labels=Object.keys(map), data=Object.values(map);
  const key = canvasId==='piePersonal'?'pieP':'pieA';
  if (S.charts[key]) S.charts[key].destroy();
  S.charts[key] = new Chart(canvas, {
    type:'doughnut',
    data:{ labels, datasets:[{ data, backgroundColor:PIE_COLORS, borderWidth:0, hoverOffset:4 }] },
    options:{ plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>`${ctx.label}: ${fmt(ctx.parsed)}`}}}, cutout:'60%' }
  });
  if (legendEl) {
    legendEl.innerHTML = labels.slice(0,5).map((l,i)=>`
      <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px">
        <div style="width:8px;height:8px;border-radius:2px;background:${PIE_COLORS[i]};flex-shrink:0"></div>
        <span style="font-size:10px;flex:1;color:var(--text2);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${l}</span>
        <span style="font-size:10px;font-family:'JetBrains Mono',monospace;color:${PIE_COLORS[i]}">${fmt(data[i])}</span>
      </div>`).join('');
  }
}

function renderTransactions() {
  const el = document.getElementById('tx-list'); if (!el) return;
  if (!S.transactions.length) { el.innerHTML='<div style="text-align:center;padding:20px;font-size:13px;color:var(--text3)">Sin transacciones</div>'; return; }
  el.innerHTML = S.transactions.map(t=>`
    <div style="display:flex;align-items:center;gap:10px;padding:8px 12px;background:var(--bg3);border-radius:10px;border:1px solid rgba(0,229,255,.07)">
      <span style="font-size:18px">${t.type==='entrada'?'▲':'▼'}</span>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escHtml(t.desc||t.category)}</div>
        <div style="font-size:10px;color:var(--text3);font-family:'JetBrains Mono',monospace">${t.date} · ${t.scope} · ${t.category}${t.cuotas?' · '+t.numCuotas+' cuotas':''}</div>
      </div>
      <span class="f-display" style="font-size:13px;font-weight:700;color:${t.type==='entrada'?'var(--green)':'var(--red)'};flex-shrink:0">
        ${t.type==='entrada'?'+':'-'}${fmt(t.amount)}
      </span>
      <div style="display:flex;gap:6px;flex-shrink:0">
        <button class="btn btn-g btn-sm" onclick="openEditTx('${t.id}')">✏️</button>
        <button class="btn btn-d" onclick="deleteTx('${t.id}')">🗑</button>
      </div>
    </div>`).join('');
}

function deleteTx(id) {
  const t = S.transactions.find(x=>x.id===id); if (!t) return;
  if (t.scope==='personal') personalBalance += t.type==='entrada'?-t.amount:t.amount;
  S.transactions=S.transactions.filter(x=>x.id!==id);
  updateFinancialDisplay();
}

function openEditTx(id) {
  S.editingTx=id;
  const t=S.transactions.find(x=>x.id===id);
  document.getElementById('etx-amount').value=t?.amount||'';
  document.getElementById('etx-desc').value=t?.desc||'';
  openModal('modal-edit-tx');
}

function saveTxEdit() {
  const t=S.transactions.find(x=>x.id===S.editingTx); if (!t) return;
  const newAmt=parseFloat(document.getElementById('etx-amount').value)||t.amount;
  const diff=newAmt-t.amount;
  if (t.scope==='personal') personalBalance += t.type==='entrada'?diff:-diff;
  t.amount=newAmt; t.desc=document.getElementById('etx-desc').value||t.desc;
  closeModal('modal-edit-tx'); updateFinancialDisplay();
}

function addCard() {
  const last4=document.getElementById('card-last4').value.trim();
  const bank=document.getElementById('card-bank').value.trim();
  if (!last4||!bank) return;
  S.cards.push({ id:uid(), last4, bank, type:document.getElementById('card-type').value });
  document.getElementById('card-last4').value='';
  document.getElementById('card-bank').value='';
  closeModal('modal-card'); renderCards();
}

function renderCards() {
  const el=document.getElementById('cards-container'); if (!el) return;
  el.innerHTML=S.cards.map(c=>`
    <div class="bank-card" style="background:linear-gradient(135deg,${c.type==='personal'?'rgba(0,229,255,.12),rgba(0,80,170,.1)':'rgba(168,85,247,.12),rgba(100,50,200,.1)'});border:1px solid ${c.type==='personal'?'rgba(0,229,255,.3)':'rgba(168,85,247,.3)'}">
      <div style="font-size:10px;color:var(--text3);margin-bottom:6px">${'💳 PERSONAL'}</div>
      <div class="f-display" style="font-size:16px;font-weight:700;letter-spacing:.1em;color:rgba(255,255,255,.8)">•••• ${escHtml(c.last4)}</div>
      <div style="font-size:11px;color:var(--text3);margin-top:4px">${escHtml(c.bank)}</div>
      <button class="btn btn-d" onclick="deleteCard('${c.id}')" style="position:absolute;top:8px;right:8px">×</button>
    </div>`).join('');
}

function deleteCard(id) { S.cards=S.cards.filter(x=>x.id!==id); renderCards(); }

function addDebt() {
  const creditor=document.getElementById('debt-creditor').value.trim();
  const amount=parseFloat(document.getElementById('debt-amount').value);
  if (!creditor||!amount) return;
  S.debts.push({ id:uid(), creditor, amount, paid:parseFloat(document.getElementById('debt-paid').value)||0 });
  document.getElementById('debt-creditor').value='';
  document.getElementById('debt-amount').value='';
  document.getElementById('debt-paid').value='';
  closeModal('modal-debt'); renderDebts();
}

function renderDebts() {
  const el=document.getElementById('debt-list'); if (!el) return;
  if (!S.debts.length) { el.innerHTML='<div style="font-size:13px;color:var(--text3);text-align:center;padding:16px">Sin deudas registradas</div>'; return; }
  el.innerHTML=S.debts.map(d=>{
    const pct=Math.min(100,(d.paid/d.amount)*100);
    return `<div class="debt-card">
      <div style="display:flex;justify-content:space-between;margin-bottom:8px">
        <span style="font-weight:600;font-size:13px">${escHtml(d.creditor)}</span>
        <div style="display:flex;gap:8px;align-items:center">
          <span class="f-mono c-red" style="font-size:12px">${fmt(d.amount)}</span>
          <button class="btn btn-d" onclick="deleteDebt('${d.id}')">🗑</button>
        </div>
      </div>
      <div class="prog-wrap xs mb14"><div class="prog-fill" style="width:${pct}%;background:var(--green)"></div></div>
      <div style="font-size:10px;color:var(--text3)">${fmt(d.paid)} pagado · ${pct.toFixed(0)}%</div>
    </div>`;
  }).join('');
}

function deleteDebt(id) { S.debts=S.debts.filter(x=>x.id!==id); renderDebts(); }

