const CHAT_MSGS = [
  {role:'ai', text:'Hola. Soy tu Segundo Cerebro — IA integrada a Life OS. Puedo analizar hábitos, resumir tu semana, calcular proyecciones financieras, sugerirte rutinas y mucho más. ¿Por dónde empezamos?'}
];
const CHAT_RESPONSES = {
  'analiz':'📊 Basándome en tu actividad reciente: tus hábitos de ejercicio muestran 78% de constancia. Racha más larga: 8 días. Te sugiero agregar hidratación y meditación para mejorar tu score mental.',
  'progres':'💪 Tu progresión de fuerza: +12% en 6 semanas. Tu PR más reciente fue en Press de Banca. Continúa con sobrecarga progresiva — estás en excelente camino.',
  'financ':'💰 Este mes: Ingresos +$31,200 MXN · Gastos $18,450 MXN · Ahorro neto $12,750 MXN (41%). Principales gastos: Alimentación 35%, Tecnología 22%. Recomiendo reducir 10% en entretenimiento.',
  'rutin':'🏋️ Upper Body recomendado:\n• Press de Banca 4×8 · Remo con Barra 4×10\n• Press Militar 3×10 · Jalones 3×12\n• Curl Bíceps 3×12 · Extensión Tríceps 3×12',
  'enfoc':'🧠 Para mejorar tu enfoque: 1) Bloques Pomodoro 45 min. 2) Redes sociales máx 30 min/día. 3) Meditación matutina 10 min. 4) Sueño consistente 7-8 horas.',
  'meta':'🎯 Estás al 34% de tus metas anuales. A este ritmo: objetivos físicos en ~3 meses, financieros en ~5 meses. Divide metas grandes en hitos semanales.',
};
const SUGGESTIONS = ['Analiza mi semana de hábitos','¿Cuál es mi progresión de fuerza?','Resumen financiero del mes','Sugiere rutina Upper Body','¿Cómo mejorar mi enfoque?','Calcula mi proyección de metas'];
let chatMsgs = [...CHAT_MSGS];
let chatLoading = false;

function initChat() {
  renderChat();
  const sugEl = document.getElementById('chat-suggestions'); if (!sugEl) return;
  sugEl.innerHTML = SUGGESTIONS.map(s=>`<button class="btn btn-g" style="font-size:12px" onclick="sendChatMsg('${s}')">${s}</button>`).join('');
}

function sendChat() {
  const inp=document.getElementById('chat-input'); if (!inp||chatLoading) return;
  const txt=inp.value.trim(); if (!txt) return;
  inp.value=''; sendChatMsg(txt);
}

function sendChatMsg(txt) {
  chatMsgs.push({role:'user',text:txt});
  renderChat(); chatLoading=true;
  setTimeout(()=>{
    const key=Object.keys(CHAT_RESPONSES).find(k=>txt.toLowerCase().includes(k));
    const reply=key?CHAT_RESPONSES[key]:`Entendido: "${txt}". Procesando con los datos de Life OS... Esta función conecta con todos tus módulos para darte insights personalizados.`;
    chatMsgs.push({role:'ai',text:reply});
    chatLoading=false; renderChat();
  },1100);
}

function renderChat() {
  const el=document.getElementById('chat-messages'); if (!el) return;
  el.innerHTML=chatMsgs.map(m=>`
    <div style="display:flex;justify-content:${m.role==='user'?'flex-end':'flex-start'}">
      <div class="${m.role==='ai'?'bubble-ai':'bubble-user'}">
        ${m.role==='ai'?'<span class="ai-label">🧠 CEREBRO IA</span>':''}
        <span style="white-space:pre-wrap">${escHtml(m.text)}</span>
      </div>
    </div>`).join('');
  if (chatLoading) el.innerHTML+=`<div style="display:flex;justify-content:flex-start"><div class="bubble-ai"><span class="f-mono c-accent">▋▋▋</span></div></div>`;
  el.scrollTop=el.scrollHeight;
}

/* ═══════════════════════════════════════════
   GOALS
═══════════════════════════════════════════ */
function addGoal() {
  const title=document.getElementById('goal-title').value.trim(); if (!title) return;
  const dueDate=document.getElementById('goal-due')?.value || '';
  S.goals.push({ id:uid(), title, desc:document.getElementById('goal-desc').value, category:document.getElementById('goal-cat').value, objectives:[], createdAt:today(), dueDate });
  document.getElementById('goal-title').value='';
  document.getElementById('goal-desc').value='';
  if (document.getElementById('goal-due')) document.getElementById('goal-due').value='';
  closeModal('modal-goal'); renderGoals();
}

function renderGoals() {
  const el=document.getElementById('goals-list'); if (!el) return;
  const totalObj=S.goals.reduce((a,g)=>a+(g.objectives?.length||0),0);
  const doneObj=S.goals.reduce((a,g)=>a+(g.objectives?.filter(o=>o.done).length||0),0);
  const globalPct=totalObj>0?Math.round((doneObj/totalObj)*100):0;
  document.getElementById('global-pct') && (document.getElementById('global-pct').textContent=globalPct+'%');
  document.getElementById('global-bar') && (document.getElementById('global-bar').style.width=globalPct+'%');
  document.getElementById('global-dot') && (document.getElementById('global-dot').style.display=globalPct>2?'block':'none');
  document.getElementById('global-sub') && (document.getElementById('global-sub').textContent=doneObj+'/'+totalObj+' objetivos completados');
  document.getElementById('global-goals-count') && (document.getElementById('global-goals-count').textContent=S.goals.length+' metas activas');
  if (!S.goals.length) { el.innerHTML='<div style="text-align:center;padding:40px;font-size:13px;color:var(--text3)">Crea tu primera meta para comenzar tu viaje</div>'; renderCompletedGoals(); return; }
  el.innerHTML=S.goals.map(g=>{
    const done=g.objectives?.filter(o=>o.done).length||0;
    const total=g.objectives?.length||0;
    const pct=total>0?Math.round((done/total)*100):0;
    const color=CAT_COLORS[g.category]||'var(--accent)';
    return `<div class="card" data-goal-id="${g.id}">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:12px;flex-wrap:wrap;gap:8px">
        <div style="flex:1">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">
            <div style="width:8px;height:8px;border-radius:2px;background:${color};flex-shrink:0"></div>
            <span style="font-size:10px;color:${color};font-weight:700">${g.category}</span>
          </div>
          <div class="f-display" style="font-size:15px;font-weight:700;margin-bottom:${g.desc?'4px':'0'}">${escHtml(g.title)}</div>
          ${g.desc?`<div style="font-size:12px;color:var(--text2)">${escHtml(g.desc)}</div>`:''}
        </div>
        <div style="display:flex;align-items:center;gap:8px">
          <span class="f-display" style="font-size:20px;font-weight:900;color:${color}">${pct}%</span>
          <button class="btn btn-g btn-sm" onclick="openEditGoal('${g.id}')">✏️</button>
          <button class="btn btn-g btn-sm" onclick="completeGoal('${g.id}')" title="Marcar como completada" style="border-color:rgba(74,222,128,.4)!important;color:#4ade80">✅</button>
          <button class="btn btn-d" onclick="deleteGoal('${g.id}')">🗑</button>
        </div>
      </div>
      <div class="prog-wrap sm" style="margin-bottom:12px">
        <div class="prog-fill" style="width:${pct}%;background:${color}"></div>
      </div>
      <div style="display:flex;flex-direction:column;gap:6px;margin-bottom:12px">
        ${(g.objectives||[]).map(o=>`
          <div class="goal-obj">
            <div class="obj-cb ${o.done?'done-o':''}" onclick="toggleObj('${g.id}','${o.id}')">${o.done?'✓':''}</div>
            <span style="flex:1;font-size:12px;text-decoration:${o.done?'line-through':'none'};opacity:${o.done?.5:1}">${escHtml(o.text)}</span>
            <span onclick="deleteObj('${g.id}','${o.id}')" style="cursor:pointer;color:var(--red);font-size:14px">×</span>
          </div>`).join('')}
      </div>
      <div style="display:flex;gap:8px">
        <input class="inp f1" id="obj-inp-${g.id}" placeholder="Agregar objetivo específico..." onkeydown="if(event.key==='Enter')addObjective('${g.id}')" style="font-size:12px"/>
        <button class="btn btn-g btn-sm" onclick="addObjective('${g.id}')">+</button>
      </div>
    </div>`;
  }).join('');
  renderCompletedGoals();
  // Recalc: mark overdue goals inline (no separate patch needed)
  const todayStr = today();
  (S.goals || []).forEach(g => {
    const cardEl = document.querySelector(`[data-goal-id="${g.id}"]`);
    if (!cardEl) return;
    const total = g.objectives?.length || 0;
    const done  = g.objectives?.filter(o => o.done).length || 0;
    const pct   = total > 0 ? Math.round((done / total) * 100) : 0;
    const isOverdue = g.dueDate && g.dueDate < todayStr && pct < 100;
    const hasOverdueObj = (g.objectives || []).some(o => !o.done && o.dueDate && o.dueDate < todayStr);
    if (isOverdue || hasOverdueObj) {
      const progWrap = cardEl.querySelector('.prog-wrap');
      if (progWrap) {
        progWrap.classList.add('recalc');
        const fill = progWrap.querySelector('.prog-fill');
        if (fill) fill.classList.add('recalc');
        if (!cardEl.querySelector('.recalc-label')) {
          const lbl = document.createElement('div');
          lbl.className = 'recalc-label';
          lbl.style.cssText = 'margin-top:6px;animation:recalcBlink 1.4s ease-in-out infinite';
          lbl.textContent = '⟳ Recalculando ruta...';
          progWrap.parentNode.insertBefore(lbl, progWrap.nextSibling);
        }
      }
    }
  });
}

function addObjective(goalId) {
  const inp=document.getElementById('obj-inp-'+goalId); if (!inp) return;
  const text=inp.value.trim(); if (!text) return;
  const g=S.goals.find(x=>x.id===goalId); if (!g) return;
  g.objectives.push({ id:uid(), text, done:false });
  inp.value=''; renderGoals(); showToast('🎯 Objetivo agregado');
}

function toggleObj(goalId, objId) {
  const g=S.goals.find(x=>x.id===goalId); if (!g) return;
  const o=g.objectives.find(x=>x.id===objId); if (!o) return;
  o.done=!o.done; renderGoals();
}

function deleteObj(goalId, objId) {
  const g=S.goals.find(x=>x.id===goalId); if (!g) return;
  g.objectives=g.objectives.filter(x=>x.id!==objId); renderGoals();
}

function deleteGoal(id) { S.goals=S.goals.filter(x=>x.id!==id); renderGoals(); }

function openEditGoal(id) {
  S.editingGoal=id;
  const g=S.goals.find(x=>x.id===id);
  document.getElementById('eg-title').value=g?.title||'';
  document.getElementById('eg-desc').value=g?.desc||'';
  document.getElementById('eg-cat').value=g?.category||'Personal';
  openModal('modal-edit-goal');
}

function saveGoalEdit() {
  const g=S.goals.find(x=>x.id===S.editingGoal); if (!g) return;
  g.title=document.getElementById('eg-title').value||g.title;
  g.desc=document.getElementById('eg-desc').value;
  g.category=document.getElementById('eg-cat').value;
  closeModal('modal-edit-goal'); renderGoals();
}

/* ═══════════════════════════════════════════
   CALENDAR
═══════════════════════════════════════════ */
/* Map task name keywords → emoji */
function getTaskEmoji(name) {
  const n = (name||'').toLowerCase();
  if (/come|almuerz|cena|desayun|food|meal|café|cafe|pizza|taco|burguer|burger|sushi|ensalad|fruta|cocin|restauran|taquer|lunch|dinner|breakfast/.test(n)) return '🍽️';
  if (/gym|entrena|ejercicio|workout|run|corr|cardio|pesas|fitness|yoga|pilates|crossfit|spinning|natac|nadar|biciclet|fut|fútbol|tennis|tenis|deport/.test(n)) return '💪';
  if (/medicin|pastill|vitamina|doctor|médico|medico|cita medic|salud|farmac|hospital|consulta/.test(n)) return '💊';
  if (/estudi|tarea|escuela|clase|curso|libro|leer|lección|leccion|universidad|examen/.test(n)) return '📚';
  if (/trabajo|trabaj|reunión|reunion|junta|meet|cliente|proyecto|ofici|presentac|informe/.test(n)) return '💼';
  if (/pago|factura|banco|dinero|transf|cobr|renta|deuda|cred|hipotec/.test(n)) return '💳';
  if (/call|llam|whatsapp|telegram|mensaje|correo|email|zoom|teams|videollamad/.test(n)) return '📞';
  if (/compra|mercado|tienda|superm|shoppin|walmart|costco/.test(n)) return '🛒';
  if (/cumpleaños|fiesta|evento|celebr|boda|party|graduac|quinceañ/.test(n)) return '🎉';
  if (/viaje|vuelo|hotel|trip|vacacion|aeropuert|pasaport/.test(n)) return '✈️';
  if (/medita|relax|descanso|dormir|sueño|spa|masaje/.test(n)) return '🧘';
  if (/peluquer|barbero|estétic|estetica|salon|cabello|pelo|manicur|uñas/.test(n)) return '💈';
  if (/cine|pelicul|película|teatro|concierto|evento|espectáculo|espectaculo/.test(n)) return '🎬';
  if (/café|cafeter|coffe|star.*bucks|starbucks/.test(n)) return '☕';
  if (/bar|cerveza|copa|tragos|cantina|mezcal|vino/.test(n)) return '🍺';
  if (/dentist|ortod|braces|diente/.test(n)) return '🦷';
  if (/perro|gato|mascota|vet|veterinario/.test(n)) return '🐾';
  if (/iglesia|misa|templo|orar|rezo/.test(n)) return '🙏';
  return '📌';
}

function renderCalendar() {
  const { calYear:y, calMonth:m } = S;
  document.getElementById('cal-title').textContent = MONTHS[m]+' '+y;
  const firstDay=new Date(y,m,1).getDay();
  const daysInMonth=new Date(y,m+1,0).getDate();
  const todayStr=`${new Date().getFullYear()}-${String(new Date().getMonth()+1).padStart(2,'0')}-${String(new Date().getDate()).padStart(2,'0')}`;
  let html='';
  for(let i=0;i<firstDay;i++) html+='<div></div>';
  for(let d=1;d<=daysInMonth;d++) {
    const key=`${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    const isToday=key===todayStr, isSel=S.calSelectedDay===key;
    const evts=(S.calEvents[key]||[]);
    // Tasks with this date (pending only)
    const dayTasks=(S.tasks||[]).filter(t=>t.date===key&&!t.done);
    // Build emoji set: task types first, then 📌 for manual events
    const emojiSet=[];
    dayTasks.forEach(t=>{ const e=getTaskEmoji(t.name); if(!emojiSet.includes(e)) emojiSet.push(e); });
    evts.forEach(e=>{ const em=getTaskEmoji(e.text); if(!emojiSet.includes(em)) emojiSet.push(em); });
    // Plan social terminando ese día
    const hasplan=(S.socialPlans||[]).some(p=>p.fechaFin===key&&p.estado!=='terminado');
    if(hasplan && !emojiSet.includes('🤝')) emojiSet.push('🤝');
    const hasActivity=emojiSet.length>0;
    html+=`<div class="cal-day ${isToday?'today':''} ${isSel?'selected':''} ${hasActivity?'has-tasks':''}" onclick="selectCalDay('${key}')">
      <div class="cal-day-num" style="color:${isToday?'var(--accent)':''}">${d}</div>
      ${hasActivity?`<div class="cal-task-dots">${emojiSet.slice(0,3).map(e=>`<span class="cal-task-dot">${e}</span>`).join('')}${emojiSet.length>3?'<span class="cal-task-dot" style="opacity:.5">+</span>':''}</div>`:''}
    </div>`;
  }
  document.getElementById('cal-grid').innerHTML=html;
  if(S.calSelectedDay){ document.getElementById('cal-event-panel').style.display='block'; renderCalEvents(); }
  renderUpcomingList();
}

function renderUpcomingList() {
  const el=document.getElementById('upcoming-list'); if(!el) return;
  const todayStr=today();
  // Collect tasks with future/today dates, not done
  const items=[];
  (S.tasks||[]).forEach(t=>{
    if(!t.done && t.date) items.push({ date:t.date, time:t.time||'', label:escHtml(t.name), emoji:getTaskEmoji(t.name), type:'task' });
  });
  // Calendar events: flatten all date-keyed events
  Object.entries(S.calEvents||{}).forEach(([date,evts])=>{
    (evts||[]).forEach(e=>{ items.push({ date, time:'', label:escHtml(e.text), emoji:getTaskEmoji(e.text), type:'event' }); });
  });
  // Sort by date asc, then time
  items.sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time));
  // Show: overdue (up to 3) + upcoming 30 days
  const cutoff=new Date(); cutoff.setDate(cutoff.getDate()+30);
  const cutStr=cutoff.toISOString().split('T')[0];
  const filtered=items.filter(i=>i.date<=cutStr);
  if(!filtered.length){
    el.innerHTML='<div style="text-align:center;padding:16px;font-size:13px;color:var(--text3)">No hay actividades próximas</div>';
    return;
  }
  el.innerHTML=filtered.map(i=>{
    const isToday=i.date===todayStr;
    const isOverdue=i.date<todayStr;
    const cls=isOverdue?'upcoming-overdue':isToday?'upcoming-today':'';
    const dateLabel=isToday?'Hoy':isOverdue?`Vencida ${i.date}`:i.date;
    const timeLabel=i.time?` · ${i.time}`:'';
    return `<div class="upcoming-item ${cls}">
      <span style="font-size:16px">${i.emoji}</span>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${i.label}</div>
        <div class="upcoming-date">${dateLabel}${timeLabel}</div>
      </div>
    </div>`;
  }).join('');
}

function selectCalDay(key) {
  S.calSelectedDay = S.calSelectedDay === key ? null : key;
  renderCalendar();
  if (S.calSelectedDay) {
    renderCalendarActivityPanel(S.calSelectedDay); // Feature 5: unified activity log
  } else {
    document.getElementById('cal-event-panel').style.display = 'none';
  }
}

function renderCalEvents() {
  const el=document.getElementById('cal-events-list'); if (!el) return;
  const evts=S.calEvents[S.calSelectedDay]||[];
  if (!evts.length) { el.innerHTML='<div style="font-size:12px;color:var(--text3);text-align:center;padding:12px">Sin eventos para este día</div>'; return; }
  el.innerHTML=evts.map(e=>`
    <div style="display:flex;align-items:center;gap:10px;padding:8px 12px;background:rgba(0,229,255,.05);border-radius:8px;border:1px solid rgba(0,229,255,.1);margin-bottom:6px">
      <span style="font-size:16px">${getTaskEmoji(e.text)}</span>
      <span style="flex:1;font-size:13px">${escHtml(e.text)}</span>
      <button class="btn btn-d" onclick="deleteCalEvent('${e.id}')">🗑</button>
    </div>`).join('');
}

function addCalEvent() {
  const txt=document.getElementById('cal-event-input').value.trim(); if (!txt||!S.calSelectedDay) return;
  if (!S.calEvents[S.calSelectedDay]) S.calEvents[S.calSelectedDay]=[];
  S.calEvents[S.calSelectedDay].push({ id:uid(), text:txt });
  document.getElementById('cal-event-input').value='';
  renderCalendar(); renderCalEvents();
}

function deleteCalEvent(id) {
  if (!S.calSelectedDay) return;
  S.calEvents[S.calSelectedDay]=S.calEvents[S.calSelectedDay].filter(e=>e.id!==id);
  renderCalEvents(); renderCalendar();
}

function calPrev() { if(S.calMonth===0){S.calMonth=11;S.calYear--;}else S.calMonth--; renderCalendar(); }
function calNext() { if(S.calMonth===11){S.calMonth=0;S.calYear++;}else S.calMonth++; renderCalendar(); }

/* ═══════════════════════════════════════════
   SETTINGS
═══════════════════════════════════════════ */
function updateSettingsDisplay() {
  buildAccentPresets();
  // ── Claude API key ──
  const ckInp = document.getElementById('claude-api-key-input');
  if (ckInp && S.claudeApiKey) ckInp.value = S.claudeApiKey;
  const ckStatus = document.getElementById('claude-key-status');
  if (ckStatus) {
    if (S.claudeApiKey?.startsWith('sk-ant-')) {
      ckStatus.textContent='✓ IA semántica activa'; ckStatus.style.color='var(--green)';
    } else if (S.claudeApiKey) {
      ckStatus.textContent='⚠ Formato incorrecto'; ckStatus.style.color='var(--red)';
    } else {
      ckStatus.textContent='Sin clave — analizador local activo'; ckStatus.style.color='var(--text3)';
    }
  }
  document.getElementById('set-level') && (document.getElementById('set-level').textContent='Nv. '+S.level);
  document.getElementById('set-xp') && (document.getElementById('set-xp').textContent=S.xp+' XP');
  document.getElementById('set-coins') && (document.getElementById('set-coins').textContent='🪙 '+S.coins);
  // — Nombre / email
  const _sess = JSON.parse(localStorage.getItem('lifeos_session')||'{}');
  const _nomEl = document.getElementById('settings-nombre');
  const _realName = (_auth&&_auth.currentUser&&_auth.currentUser.displayName) || _sess.nombre || (S.userName !== 'Usuario' ? S.userName : '') || 'Usuario';
  if (_nomEl) _nomEl.textContent = _realName;
  const _emailEl = document.getElementById('settings-email');
  if (_emailEl) _emailEl.textContent = _sess.email || (_auth&&_auth.currentUser&&_auth.currentUser.email) || '—';
  // — User ID
  const _uidEl = document.getElementById('settings-uid');
  if (_uidEl) {
    const _userId = S.userId || (_auth&&_auth.currentUser&&_auth.currentUser.uid) || _sess.userId || localStorage.getItem('lifeos_uid') || '—';
    _uidEl.textContent = _userId;
    _uidEl.onclick = copyUserId;
  }
  // — Plan badge
  const _planBadge = document.getElementById('settings-plan-badge');
  if (_planBadge) {
    if (S.plan === 'pro') {
      _planBadge.textContent = '⭐ LIFE OS PRO';
      _planBadge.style.cssText += ';background:rgba(0,229,255,.15);color:var(--accent);border-color:rgba(0,229,255,.3)';
    } else if (S.trialExpired) {
      _planBadge.textContent = '⚠️ PRUEBA EXPIRADA';
      _planBadge.style.cssText += ';background:rgba(251,146,60,.12);color:#fb923c;border-color:rgba(251,146,60,.3)';
    }
  }
  // — Avatar
  const _avatarEl = document.getElementById('settings-avatar');
  if (_avatarEl) _avatarEl.textContent = _realName.charAt(0).toUpperCase();
}

let resetConfirm=false;
function handleReset() {
  const btn=document.getElementById('reset-btn');
  const warn=document.getElementById('reset-warning');
  if (!resetConfirm) {
    resetConfirm=true;
    btn.style.background='#ef4444'; btn.style.color='#fff'; btn.textContent='⚠️ Confirmar Reinicio';
    warn.style.display='block';
  } else {
    // ── MOTOR DE GAMIFICACIÓN — reset absoluto ──
    S.xp = 0;
    S.level = 1;
    S.coins = 0;
    S.xpHistory = {};
    S.pomoSesiones = 0;
    S.checkInStreak = 0;
    S.dailyCheckIn = {};
    S.xpMental = 0;
    S.saludXP = 0;
    // ── DATOS DE USUARIO ──
    S.tasks = [];
    S.habits = [];
    S.routines = [];
    S.transactions = [];
    S.debts = [];
    S.cards = [];
    S.goals = [];
    S.completedGoals = [];
    S.bitacora = [];
    S.biblioteca = [];
    S.aliados     = [];
    S.aliadosUids = [];
    S.gymDays = {};
    S.calEvents = {};
    S.saldos = [];
    window._extraSaldos = [];
    // ── PERSIST ──
    guardarDatos();
    updateXP();
    renderTasks();
    renderHabits();
    updateFinancialDisplay();
    renderExtraSaldos();
    buildHeatmap();
    resetConfirm=false; btn.style.background='rgba(239,68,68,.12)'; btn.style.color='#f87171';
    btn.textContent='🔄 Reiniciar Datos'; warn.style.display='none';
    showToast('✅ Datos reiniciados — Nivel 1 · 0 XP');
  }
}

/* ═══════════════════════════════════════════
   UTILS
═══════════════════════════════════════════ */
function escHtml(s) {
  if (!s) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

