// ── Internal state ────────────────────────────────────
let _fabChipTimer = null;
let _fabLastResult = null;

const MODULE_LABELS = {
  calendar:  { icon:'📅', label:'Calendario'   },
  financial: { icon:'💰', label:'Finanzas'      },
  task:      { icon:'✅', label:'Tareas'        },
  idea:      { icon:'💡', label:'Ideas Rápidas' },
};

// ── Claude NLP (async, optional) ─────────────────────
async function callClaudeNLP(text) {
  const key = S.claudeApiKey || '';
  if (!key || !key.startsWith('sk-ant-')) return null;
  try {
    const todayStr = today();
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': key,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true'
      },
      body: JSON.stringify({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 350,
        messages: [{ role: 'user', content:
`Analiza este texto en español y extrae la intención. Responde SOLO con JSON válido, sin texto adicional.

Texto: "${text.replace(/"/g,"'")}"
Fecha de hoy: ${todayStr}
Sábado próximo: ${getNextWeekday(6)}
Domingo próximo: ${getNextWeekday(0)}

Devuelve:
{"modules":["calendar","financial","task","idea"],"correctedText":"texto con ortografía corregida","calendar":{"text":"nombre evento","date":"YYYY-MM-DD","time":"HH:MM o vacío"},"financial":{"amount":número,"desc":"descripción","type":"salida"},"task":{"name":"nombre tarea"},"idea":{"text":"texto idea"}}

Reglas:
- modules puede incluir múltiples valores si el texto combina intenciones (ej: gasto + fecha → calendar+financial)
- ideas: textos que comienzan con "idea:", "nota:", o que son reflexiones/sugerencias sobre la app
- Usa solo los campos relevantes según modules
- Para fechas relativas calcula la fecha YYYY-MM-DD correcta` }]
      })
    });
    if (!res.ok) return null;
    const data = await res.json();
    const raw = data.content?.[0]?.text || '';
    const match = raw.match(/\{[\s\S]*\}/);
    return match ? JSON.parse(match[0]) : null;
  } catch(e) { return null; }
}

// ── Date helpers ──────────────────────────────────────
function getNextWeekday(target) {
  const d = new Date();
  let diff = target - d.getDay();
  if (diff <= 0) diff += 7;
  d.setDate(d.getDate() + diff);
  return d.toISOString().split('T')[0];
}

function parseRelativeDate(text) {
  const t = text.toLowerCase();
  const d = new Date();
  if (/mañana/.test(t))               { d.setDate(d.getDate()+1); return d.toISOString().split('T')[0]; }
  if (/\bhoy\b/.test(t))              return today();
  if (/sábado|sabado/.test(t))        return getNextWeekday(6);
  if (/domingo/.test(t))              return getNextWeekday(0);
  if (/\blunes\b/.test(t))            return getNextWeekday(1);
  if (/martes/.test(t))               return getNextWeekday(2);
  if (/miércoles|miercoles/.test(t))  return getNextWeekday(3);
  if (/jueves/.test(t))               return getNextWeekday(4);
  if (/viernes/.test(t))              return getNextWeekday(5);
  const dayM = t.match(/el\s+(\d{1,2})(?:ro|er|avo|°)?/);
  if (dayM) {
    const day = parseInt(dayM[1]);
    const nd = new Date(d.getFullYear(), d.getMonth(), day);
    if (nd <= d) nd.setMonth(nd.getMonth()+1);
    return nd.toISOString().split('T')[0];
  }
  return today();
}

function formatChipDate(dateStr) {
  if (!dateStr || dateStr === today()) return 'Hoy';
  const d = new Date(dateStr + 'T12:00:00');
  const days = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
  return `${days[d.getDay()]} ${d.getDate()}`;
}

// ── Local NLP fallback ────────────────────────────────
const _TYPOS = {
  cosina:'cocina',cosinando:'cocinando',cosinar:'cocinar',
  aser:'hacer',acer:'hacer',jym:'gym',gimnacio:'gimnasio',
  tarea:'tarea',apuntar:'apuntar',recordar:'recordar'
};
function fixTypos(text) {
  return text.split(/\s+/).map(w => _TYPOS[w.toLowerCase()] || w).join(' ');
}

function parseLocalNLP(raw) {
  const text = raw.trim();
  const fixed = fixTypos(text);
  const lower = fixed.toLowerCase();
  const result = { modules:[], correctedText:fixed };

  // IDEAS
  if (/^(idea|nota|apunta|sugerencia)[:\s]/i.test(lower)) {
    result.modules.push('idea');
    result.idea = { text: fixed.replace(/^(idea|nota|apunta|sugerencia)[:\s]+/i,'').trim() };
    return result;
  }

  // FINANCIAL signals
  const hasFinKw = /gasté|gaste|pagué|pague|costó|costo|gasto|compré|compre|cobré|cobre|\$\d/.test(lower);
  const amountRE = /\$?([\d,]+\.?\d*)\s*(?:pesos|mxn|mx)?/i;
  const hasAmount = amountRE.test(lower);

  // CALENDAR signals
  const hasCalKw = /\b(agendar|reunion|reunión|meeting|cita|evento|call|llamada|comer|cenar|dentista|doctor|vuelo|viaje|partido|concierto|ir al|gym)\b/i.test(lower);
  const hasDate  = /\b(hoy|mañana|sábado|sabado|domingo|lunes|martes|miércoles|miercoles|jueves|viernes|el \d{1,2}|próximo|proximo)\b/i.test(lower);
  const timeRE   = /(?:a las?|at)\s+(\d{1,2})(?::(\d{2}))?\s*(am|pm|hrs?)?/i;
  const timeM    = lower.match(timeRE);

  // MULTI: financial + calendar (e.g. "pagar renta el 1ro, 4500 pesos")
  if (hasFinKw && hasAmount && hasDate) {
    const amtM  = lower.match(amountRE);
    const amount = parseFloat((amtM[1]||'0').replace(/,/g,''));
    const desc  = fixed.replace(amountRE,'').replace(/pagar|el \d+\S*|mañana|hoy|pesos|mxn/gi,'').trim() || 'pago';
    const date  = parseRelativeDate(fixed);
    result.modules.push('calendar','financial');
    result.calendar  = { text:desc, date, time:'' };
    result.financial = { amount, desc, type:'salida' };
    return result;
  }

  // Pure financial
  if (hasFinKw && hasAmount) {
    const amtM  = lower.match(amountRE);
    const amount = parseFloat((amtM[1]||'0').replace(/,/g,''));
    const desc  = fixed.replace(amountRE,'').replace(/gasté|gaste|pagué|pague|en|de|por|pesos|mxn/gi,'').trim() || 'gasto';
    result.modules.push('financial');
    result.financial = { amount, desc, type:'salida' };
    return result;
  }

  // Calendar (with or without time)
  if (hasCalKw || (hasDate && timeM)) {
    let eventText = fixed;
    let timeStr = '';
    if (timeM) {
      let h = parseInt(timeM[1]);
      const min = timeM[2]||'00';
      const mer = (timeM[3]||'').toLowerCase();
      if (mer==='pm'&&h<12) h+=12;
      if (mer==='am'&&h===12) h=0;
      timeStr = `${String(h).padStart(2,'0')}:${min}`;
      eventText = fixed.replace(timeM[0],'').trim();
    }
    const date = parseRelativeDate(fixed);
    result.modules.push('calendar');
    result.calendar = { text:eventText, date, time:timeStr };
    return result;
  }

  // Default: task
  result.modules.push('task');
  result.task = { name:fixed };
  return result;
}

// ── FAB visibility: oculto hasta completar check-in + onboarding ──
function updateFABVisibility() {
  const btn = document.getElementById('fab-btn');
  if (!btn) return;
  const checkedIn   = !!S.dailyCheckIn?.[today()];
  const onboarded   = !!(S.onboardingDone || S.tasks?.length > 0);
  const shouldShow  = checkedIn && onboarded;
  btn.classList.toggle('fab-hidden', !shouldShow);
}

// ── Open / Preview ────────────────────────────────────
function openFABConsole() {
  openModal('modal-fab-console');
  setTimeout(()=>{
    const inp = document.getElementById('fab-input');
    if (inp) { inp.value=''; inp.focus(); }
    const prev = document.getElementById('fab-preview');
    if (prev) { prev.style.display='none'; prev.className='fab-preview'; prev.style.borderColor=''; prev.style.color=''; }
  }, 80);
}

function parseFABPreview(raw) {
  const prev = document.getElementById('fab-preview');
  if (!raw.trim()) { prev.style.display='none'; return; }
  const p = parseLocalNLP(raw);
  prev.style.display='block';
  prev.style.borderColor=''; prev.style.color='';

  if (p.modules.includes('financial') && p.modules.includes('calendar')) {
    prev.className='fab-preview financial';
    prev.textContent=`📅💰 Calendario + Finanzas — $${(p.financial?.amount||0).toLocaleString()} · "${p.calendar?.text||''}"`;
  } else if (p.modules.includes('financial')) {
    prev.className='fab-preview financial';
    prev.textContent=`💰 Finanzas: $${(p.financial?.amount||0).toLocaleString()} — "${p.financial?.desc||''}"`;
  } else if (p.modules.includes('calendar')) {
    prev.className='fab-preview task';
    prev.style.borderColor='rgba(168,85,247,.3)'; prev.style.color='#a855f7';
    const d = p.calendar?.date ? ` · ${formatChipDate(p.calendar.date)}` : '';
    const t = p.calendar?.time ? ` ${p.calendar.time}` : '';
    prev.textContent=`📅 "${p.calendar?.text||''}"${d}${t} → Calendario`;
  } else if (p.modules.includes('idea')) {
    prev.className='fab-preview idea';
    prev.textContent=`💡 "${p.idea?.text||''}" → Ideas Rápidas`;
  } else {
    prev.className='fab-preview task';
    prev.textContent=`✅ Tarea: "${p.task?.name||''}" → Tareas`;
  }
}

// ── Execute (async) ───────────────────────────────────
async function executeFAB() {
  const raw = document.getElementById('fab-input').value.trim();
  if (!raw) return;

  const btn = document.getElementById('fab-exec-btn');
  if (btn) { btn.textContent='⏳ Analizando...'; btn.disabled=true; }

  let p = null;
  try { p = await callClaudeNLP(raw); } catch(e) {}
  if (!p || !p.modules?.length) p = parseLocalNLP(raw);

  _fabLastResult = p;
  closeModal('modal-fab-console');
  if (btn) { btn.textContent='⚡ Ejecutar'; btn.disabled=false; }

  _applyFABResult(p);
  guardarDatos();
  updateGlobalCore();
  if (typeof renderMorningBriefing === 'function') renderMorningBriefing();
}

function _applyFABResult(p) {
  const routed = [];
  for (const mod of (p.modules||[])) {
    if (mod==='financial' && p.financial) {
      S.transactions.unshift({ id:uid(), type:'salida', scope:'personal',
        category:'Otro', amount:p.financial.amount,
        desc:p.financial.desc, date:today(), cuotas:false });
      if (typeof updateFinancialDisplay==='function') updateFinancialDisplay();
      routed.push({ mod:'financial', detail:`$${(p.financial.amount||0).toLocaleString()}` });
    }
    if (mod==='calendar' && p.calendar) {
      const d = p.calendar.date || today();
      if (!S.calEvents[d]) S.calEvents[d]=[];
      const txt = p.calendar.time ? `${p.calendar.text} — ${p.calendar.time}` : p.calendar.text;
      S.calEvents[d].push({ id:uid(), text:txt });
      routed.push({ mod:'calendar', detail:formatChipDate(p.calendar.date) });
    }
    if (mod==='task' && p.task) {
      S.tasks.unshift({ id:uid(), name:p.task.name, desc:'', date:today(), time:'', done:false });
      if (typeof renderTasks==='function') renderTasks();
      if (typeof updateDashboardTaskCount==='function') updateDashboardTaskCount();
      routed.push({ mod:'task', detail:(p.task.name||'').substring(0,22) });
    }
    if (mod==='idea') {
      if (!S.ideas) S.ideas=[];
      const ideaText = p.idea?.text || p.correctedText || '';
      S.ideas.unshift({ id:uid(), text:ideaText, date:today() });
      routed.push({ mod:'idea', detail:ideaText.substring(0,24) });
    }
  }
  showFABChip(routed, p.modules||[]);
}

// ── Confirmation Chip ─────────────────────────────────
function showFABChip(routed, modules) {
  const chip = document.getElementById('fab-confirm-chip');
  const labelEl = document.getElementById('chip-label');
  const menu = document.getElementById('chip-menu');
  if (!chip || !routed.length) return;

  clearTimeout(_fabChipTimer);
  menu.classList.remove('open');

  // Label
  const parts = routed.map(r => {
    const m = MODULE_LABELS[r.mod];
    return `${m.icon} ${m.label}${r.detail ? ' — ' + r.detail : ''}`;
  });
  labelEl.innerHTML = `${parts.join(' · ')} <span class="chip-check">✓</span>`;

  // Correction options
  const allMods = ['task','calendar','financial','idea'];
  const opts = allMods.filter(m => !modules.includes(m));
  menu.innerHTML = opts.map(m => {
    const info = MODULE_LABELS[m];
    return `<button class="chip-correct-opt" onclick="correctFABRouting('${m}')">${info.icon} Mover a ${info.label}</button>`;
  }).join('');

  chip.classList.add('show');
  _fabChipTimer = setTimeout(dismissFABChip, 5500);
}

function dismissFABChip() {
  document.getElementById('fab-confirm-chip')?.classList.remove('show');
  document.getElementById('chip-menu')?.classList.remove('open');
}

function toggleChipMenu() {
  const menu = document.getElementById('chip-menu');
  menu.classList.toggle('open');
  if (menu.classList.contains('open')) clearTimeout(_fabChipTimer);
  else _fabChipTimer = setTimeout(dismissFABChip, 3000);
}

function correctFABRouting(newMod) {
  if (!_fabLastResult) return;
  dismissFABChip();
  const prev = _fabLastResult;

  // Undo previous insertions
  for (const m of (prev.modules||[])) {
    if (m==='task'     && S.tasks.length)        S.tasks.shift();
    if (m==='financial'&& S.transactions.length) S.transactions.shift();
    if (m==='idea'     && S.ideas?.length)       S.ideas.shift();
    if (m==='calendar') {
      const d = prev.calendar?.date || today();
      if (S.calEvents[d]?.length) S.calEvents[d].pop();
    }
  }

  // Build corrected result
  const raw = prev.correctedText || '';
  const newP = { ...prev, modules:[newMod] };
  if (newMod==='task'     && !newP.task)      newP.task      = { name:raw };
  if (newMod==='idea'     && !newP.idea)      newP.idea      = { text:raw };
  if (newMod==='financial'&& !newP.financial) newP.financial = { amount:0, desc:raw, type:'salida' };
  if (newMod==='calendar' && !newP.calendar)  newP.calendar  = { text:raw, date:today(), time:'' };

  _fabLastResult = newP;
  _applyFABResult(newP);
  guardarDatos();
  updateGlobalCore();
}

// ── Save Claude API key ───────────────────────────────
function saveClaudeKey() {
  const inp = document.getElementById('claude-api-key-input');
  if (!inp) return;
  S.claudeApiKey = inp.value.trim();
  guardarDatos();
  const status = document.getElementById('claude-key-status');
  if (status) {
    if (S.claudeApiKey.startsWith('sk-ant-')) {
      status.textContent = '✓ Clave guardada — IA semántica activa';
      status.style.color = 'var(--green)';
    } else if (S.claudeApiKey) {
      status.textContent = '⚠ Formato incorrecto (debe comenzar con sk-ant-)';
      status.style.color = 'var(--red)';
    } else {
      status.textContent = 'Clave eliminada — usando analizador local';
      status.style.color = 'var(--text3)';
    }
  }
  showToast(S.claudeApiKey ? '✨ IA semántica activada' : '🔧 Usando NLP local');
}

/* ═══════════════════════════════════════════════════════════════
   FUNCIONALIDAD 3 — HABIT BATTERY + NÚCLEO GLOBAL + BLACKOUT
═══════════════════════════════════════════════════════════════ */

// Añadir batería a cada hábito si no existe
function ensureHabitBattery(h) {
  if (typeof h.battery === 'undefined') h.battery = 100;
}

// Llamado en checkIn diario — degrada hábitos no completados
function chargeHabitBatteries() {
  (S.habits || []).forEach(h => {
    ensureHabitBattery(h);
    if (!h.completedToday) {
      h.battery = Math.max(0, h.battery - 25);
    } else {
      h.battery = Math.min(100, h.battery + 25); // recarga al completar
    }
  });
}

function getBatteryState(pct) {
  if (pct >= 75) return 'high';
  if (pct >= 50) return 'med';
  if (pct > 0)   return 'low';
  return 'dead';
}

/* ═══════════════════════════════════════════════════════════════
   HÁBITOS — funciones auxiliares de batería
═══════════════════════════════════════════════════════════════ */
function updateGlobalCore() {
  const totalH   = (S.habits || []).length;
  const doneH    = (S.habits || []).filter(h => h.completedToday).length;
  const todayStr = today();
  const todayTasks = (S.tasks || []).filter(t => !t.date || t.date === todayStr);
  const doneT    = todayTasks.filter(t => t.done).length;
  const totalT   = todayTasks.length;
  const combined = (totalH + totalT) > 0
    ? Math.round(((doneH + doneT) / (totalH + totalT)) * 100)
    : 0;

  const xpHoy    = S.xpHistory[todayStr] || 0;
  const racha    = S.checkInStreak || 0;
  const habPct   = totalH > 0 ? Math.round((doneH / totalH) * 100) : 0;
  const taskPct  = totalT > 0 ? Math.round((doneT / totalT) * 100) : 0;
  const xpMaxDay = 300; // reference max for the bar

  // ── Determine state ──────────────────────────────
  let state, badgeClass, labelText, badgeText;
  const hasData = (totalH + totalT) > 0;
  const enRecuperacion = S.modoRecuperacion && S.modoRecuperacionFecha === today();

  if (enRecuperacion) {
    // Modo Recuperación: estado pacífico independiente del progreso real
    state='recovery'; badgeClass='state-recovery';
    labelText='MODO RECUPERACIÓN'; badgeText='💜 DESCANSANDO';
  } else if (!hasData || S.primeraSesion) {
    // Sin datos aún, o primera sesión activa: nunca Blackout
    state='idle'; badgeClass='state-idle'; labelText='SIN ACTIVIDAD'; badgeText='NÚCLEO INACTIVO';
  } else if (combined === 0) {
    state='blackout'; badgeClass='state-blackout'; labelText='SYSTEM BLACKOUT'; badgeText='⚠ BLACKOUT ACTIVO';
  } else if (combined >= 100) {
    state='complete'; badgeClass='state-complete'; labelText='¡NÚCLEO COMPLETO!'; badgeText='🏆 MULTIPLICADOR ×2';
  } else if (combined >= 60) {
    state='flow'; badgeClass='state-flow'; labelText='EN FLUJO'; badgeText='🔥 NÚCLEO EN FLUJO';
  } else {
    state='active'; badgeClass='state-active'; labelText=`${doneH+doneT}/${totalH+totalT} COMPLETADOS`; badgeText='⚡ ACTIVANDO NÚCLEO';
  }

  // ── Update FULL widget (SaaS) ─────────────────────
  const circumFull = 552.9;
  const ringFull = document.getElementById('nucleo-progress-ring');
  if (ringFull) {
    const offset = circumFull * (1 - combined / 100);
    ringFull.style.strokeDashoffset = offset;
    ringFull.style.stroke = state === 'blackout' ? 'url(#nucleo-gradient-bo)' : state === 'recovery' ? '#a855f7' : 'url(#nucleo-gradient)';
    if (state === 'blackout') {
      ringFull.style.filter = 'drop-shadow(0 0 4px rgba(248,113,113,.4))';
    } else if (state === 'recovery') {
      ringFull.style.filter = 'drop-shadow(0 0 12px rgba(168,85,247,.6))';
    } else if (state === 'complete') {
      ringFull.style.filter = 'drop-shadow(0 0 14px rgba(74,222,128,.8))';
    } else {
      ringFull.style.filter = 'drop-shadow(0 0 8px rgba(0,229,255,.7))';
    }
  }

  const glowEl = document.getElementById('nucleo-inner-glow');
  if (glowEl) {
    const alpha = combined > 0 ? (0.02 + (combined/100)*0.1) : 0.01;
    const col   = state === 'blackout' ? `rgba(248,113,113,${alpha})` : `rgba(0,229,255,${alpha})`;
    glowEl.setAttribute('fill', col);
  }

  const dotEl = document.getElementById('nucleo-center-dot');
  if (dotEl) {
    const dc = state === 'blackout' ? '#f87171' : state === 'recovery' ? '#c084fc' : state === 'complete' ? '#4ade80' : 'var(--accent)';
    dotEl.setAttribute('fill', dc);
    dotEl.style.filter = `drop-shadow(0 0 6px ${dc})`;
  }

  const pctMain = document.getElementById('nucleo-pct-main');
  if (pctMain) pctMain.textContent = combined + '%';

  const lblMain = document.getElementById('nucleo-label-main');
  if (lblMain) lblMain.textContent = labelText;

  const badgeMain = document.getElementById('nucleo-badge-main');
  if (badgeMain) { badgeMain.className = 'nucleo-badge ' + badgeClass; badgeMain.textContent = badgeText; }

  const cardMain = document.getElementById('nucleo-card-main');
  if (cardMain) {
    cardMain.classList.toggle('complete', state === 'complete');
    cardMain.style.borderColor = state === 'complete' ? 'rgba(74,222,128,.4)'
      : state === 'blackout' ? 'rgba(248,113,113,.3)'
      : state === 'recovery' ? 'rgba(168,85,247,.4)'
      : state === 'flow' ? 'rgba(0,229,255,.3)'
      : 'var(--border)';
    cardMain.style.boxShadow = state === 'complete' ? '0 0 40px rgba(74,222,128,.12)'
      : state === 'blackout' ? '0 0 30px rgba(248,113,113,.08)'
      : state === 'recovery' ? '0 0 35px rgba(168,85,247,.1)'
      : state === 'flow' ? '0 0 30px rgba(0,229,255,.06)' : '';
  }

  // Sub-metrics
  function setMetric(valId, barId, text, pct) {
    const v = document.getElementById(valId); if (v) v.textContent = text;
    const b = document.getElementById(barId);  if (b) b.style.width = Math.min(100, pct) + '%';
  }
  setMetric('nm-habitos',  'nmb-habitos', `${doneH}/${totalH}`,  habPct);
  setMetric('nm-tareas',   'nmb-tareas',  `${doneT}/${totalT}`,  taskPct);
  setMetric('nm-xp-hoy',  'nmb-xp',     `${xpHoy}`,             Math.min(100, (xpHoy/xpMaxDay)*100));
  setMetric('nm-racha',    'nmb-racha',  `${racha}d`,            Math.min(100, (racha/30)*100));

  // ── Update COMPACT widget (Análisis) ──────────────
  const circumSm = 263.9;
  const ringSm = document.getElementById('nucleo-progress-ring-sm');
  if (ringSm) ringSm.style.strokeDashoffset = circumSm * (1 - combined / 100);

  const pctSm = document.getElementById('nucleo-pct-sm');
  if (pctSm) pctSm.textContent = combined + '%';
  const lblSm = document.getElementById('nucleo-label-sm');
  if (lblSm) lblSm.textContent = state === 'complete' ? '¡COMPLETO!' : 'NÚCLEO';
  const badgeSm = document.getElementById('nucleo-badge-sm');
  if (badgeSm) { badgeSm.className = 'nucleo-badge ' + badgeClass; badgeSm.textContent = badgeText; }

  function setSmMetric(valId, barId, text, pct) {
    const v = document.getElementById(valId); if (v) v.textContent = text;
    const b = document.getElementById(barId);  if (b) b.style.width = Math.min(100, pct) + '%';
  }
  setSmMetric('nm-habitos-sm', 'nmb-h-sm', `${doneH}/${totalH}`, habPct);
  setSmMetric('nm-tareas-sm',  'nmb-t-sm', `${doneT}/${totalT}`, taskPct);
  setSmMetric('nm-xp-sm',     'nmb-xp-sm', `${xpHoy} XP`, Math.min(100, (xpHoy/xpMaxDay)*100));
  // Pill del multiplicador en header comunitario
  const multPill = document.getElementById('nucleo-mult-pill-display');
  if (multPill) {
    const mult = state === 'complete' ? '×2' : state === 'flow' ? '×1.5' : '×1';
    multPill.textContent = '⚡ ' + mult + ' XP';
    multPill.style.color = state === 'complete' ? '#4ade80' : state === 'flow' ? '#fbbf24' : '#ffd700';
    multPill.style.background = state === 'complete' ? 'rgba(74,222,128,.12)' : state === 'flow' ? 'rgba(251,191,36,.12)' : 'rgba(255,215,0,.12)';
    multPill.style.borderColor = state === 'complete' ? 'rgba(74,222,128,.35)' : state === 'flow' ? 'rgba(251,191,36,.3)' : 'rgba(255,215,0,.3)';
  }

  // ── SYSTEM BLACKOUT ──────────────────────────────
  const enRecuperacionCheck = S.modoRecuperacion && S.modoRecuperacionFecha === today();
  const shouldBlackout = state === 'blackout' && !enRecuperacionCheck;
  if (shouldBlackout && !document.body.classList.contains('blackout')) {
    document.body.classList.add('blackout');
    S.xp = Math.max(0, S.xp - 50);
    updateXP();
    showToast('⚠️ SYSTEM BLACKOUT — −50 XP · Núcleo al 0%');
  } else if (!shouldBlackout) {
    document.body.classList.remove('blackout');
  }

  // ── WEEKLY BONUS ─────────────────────────────────
  if (combined >= 100 && !S._weeklyBonusGiven) {
    S._weeklyBonusGiven = true;
    gainXP(200);
    // Toast se muestra solo después del check-in, no durante el boot
    if (!window._suppressNucleoToast) {
      showToast('🏆 ¡NÚCLEO AL 100%! Multiplicador ×2 activado +200 XP');
      spawnConfetti();
    }
  }
}

/* ═══════════════════════════════════════════════════════════════
   CÁMARA DE ENFOQUE — Focus Chamber (accessible only from Settings)
═══════════════════════════════════════════════════════════════ */
/* ═══════════════════════════════════════════════════════════════
   CÁMARA DE ENFOQUE — Timer + Partículas
═══════════════════════════════════════════════════════════════ */
let _fcMinutes     = 25;
let _fcSeconds     = 25 * 60;
let _fcRunning     = false;
let _fcInterval    = null;
let _fcSessions    = 0;
let _fcParticles   = [];
let _fcAnimFrame   = null;

function activateFocusChamber() {
  const taskInput = document.getElementById('focus-chamber-task');
  const taskName  = (taskInput?.value || '').trim() || 'ENFOQUE TOTAL';
  const overlay   = document.getElementById('focus-chamber-overlay');
  const label     = document.getElementById('fc-task-label');
  if (!overlay) return;

  label.textContent = taskName.toUpperCase();

  // Apply user accent color to arc
  const accent = S.accent || '#00e5ff';
  const acR=parseInt(accent.slice(1,3),16),acG=parseInt(accent.slice(3,5),16),acB=parseInt(accent.slice(5,7),16);
  const arc    = document.getElementById('fc-arc');
  if (arc) { arc.style.stroke = accent; arc.style.filter = 'drop-shadow(0 0 10px rgba('+acR+','+acG+','+acB+',.5))'; }
  const stateEl = document.getElementById('fc-state-label');
  if (stateEl) stateEl.style.color = accent;
  const bgGlow = document.getElementById('fc-bg-glow');
  if (bgGlow) bgGlow.style.background = 'radial-gradient(ellipse 70% 60% at 50% 45%,rgba('+acR+','+acG+','+acB+',.08) 0%,transparent 70%)';
  const fcToggle = document.getElementById('fc-toggle-btn');
  if (fcToggle) {
    fcToggle.style.background  = 'rgba('+acR+','+acG+','+acB+',.15)';
    fcToggle.style.borderColor = 'rgba('+acR+','+acG+','+acB+',.4)';
    fcToggle.style.boxShadow   = '0 0 20px rgba('+acR+','+acG+','+acB+',.15)';
  }

  // Reset timer
  _fcRunning = false; _fcMinutes = 25; _fcSeconds = 25 * 60;
  clearInterval(_fcInterval);
  updateFCDisplay(); setFCTimeBtn(25);
  const btn = document.getElementById('fc-toggle-btn');
  if (btn) btn.textContent = '▶ INICIAR';

  // Sessions count
  const scEl = document.getElementById('fc-sessions-count');
  if (scEl) scEl.textContent = _fcSessions;

  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';
  if (taskInput) taskInput.value = '';
  initFCParticles();
}

function setFCTime(min) {
  if (_fcRunning) return;
  _fcMinutes = min;
  _fcSeconds = min * 60;
  setFCTimeBtn(min);
  updateFCDisplay();
}

function setFCTimeBtn(active) {
  const accent = S.accent || '#00e5ff';
  const acR=parseInt(accent.slice(1,3),16),acG=parseInt(accent.slice(3,5),16),acB=parseInt(accent.slice(5,7),16);
  [25,35,45,60].forEach(m => {
    const btn = document.getElementById('fc-btn-'+m);
    if (!btn) return;
    if (m === active) {
      btn.style.background  = 'rgba('+acR+','+acG+','+acB+',.18)';
      btn.style.borderColor = accent;
      btn.style.color       = accent;
    } else {
      btn.style.background  = 'transparent';
      btn.style.borderColor = 'rgba(255,255,255,.1)';
      btn.style.color       = 'rgba(255,255,255,.3)';
    }
  });
}

/* ── Motor de partículas compartido entre los 3 overlays ── */
function spawnParticles(canvasId, hexColor) {
  const canvas = document.getElementById(canvasId); if (!canvas) return null;
  canvas.width  = window.innerWidth;
  canvas.height = window.innerHeight;
  const particles = [];
  for (let i = 0; i < 55; i++) {
    particles.push({ x:Math.random()*canvas.width, y:Math.random()*canvas.height,
      r:Math.random()*1.4+0.4, speed:Math.random()*.35+.1,
      angle:Math.random()*Math.PI*2, opacity:Math.random()*.4+.08 });
  }
  let raf = null;
  function draw() {
    if (!document.getElementById(canvasId)) return;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0,0,canvas.width,canvas.height);
    particles.forEach(p => {
      p.x += Math.cos(p.angle)*p.speed; p.y += Math.sin(p.angle)*p.speed*.5-.18;
      if(p.y<-10){p.y=canvas.height+10;p.x=Math.random()*canvas.width;}
      if(p.x<-10)p.x=canvas.width+10; if(p.x>canvas.width+10)p.x=-10;
      ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      const alpha = Math.round(p.opacity*255).toString(16).padStart(2,'0');
      ctx.fillStyle = hexColor+alpha; ctx.fill();
    });
    raf = requestAnimationFrame(draw);
  }
  draw();
  return () => cancelAnimationFrame(raf);
}

function initFCParticles() {
  if (_fcStopParticles) { _fcStopParticles(); _fcStopParticles = null; }
  _fcStopParticles = spawnParticles('fc-particles', S.accent || '#00e5ff');
}
let _fcStopParticles = null;

function drawFCParticles(){} // legacy stub — spawnParticles handles it now

/* ══════════════════════════════════════════════════════════════
   GYM FOCUS OVERLAY
══════════════════════════════════════════════════════════════ */
let _gfSession = null;
let _gfIdx     = 0;
let _gfStop    = null;

function openGymFocusOverlay(session) {
  _gfSession = session;
  _gfIdx     = session.currentIdx || 0;
  const overlay = document.getElementById('gym-focus-overlay');
  if (!overlay) return;
  overlay.style.display = 'flex';
  document.body.style.overflow = 'hidden';
  const accent = S.accent || '#00e5ff';
  const acR=parseInt(accent.slice(1,3),16),acG=parseInt(accent.slice(3,5),16),acB=parseInt(accent.slice(5,7),16);
  const bgGlow = document.getElementById('gf-bg-glow');
  if (bgGlow) bgGlow.style.background = 'radial-gradient(ellipse 60% 50% at 50% 50%,rgba('+acR+','+acG+','+acB+',.06) 0%,transparent 70%)';
  _gfStop = spawnParticles('gf-particles', accent);
  renderGymFocusScreen();
}

function renderGymFocusScreen() {
  const ex = _gfSession?.exercises[_gfIdx]; if (!ex) return;
  const done = ex.completedSets.length, total = ex.targetSets;
  const accent = S.accent || '#00e5ff';
  const acR=parseInt(accent.slice(1,3),16),acG=parseInt(accent.slice(3,5),16),acB=parseInt(accent.slice(5,7),16);
  document.getElementById('gf-exercise-name').textContent = ex.emoji+' '+ex.name.toUpperCase();
  document.getElementById('gf-set-info').textContent = `Serie ${done+1} de ${total} · ${ex.targetReps} reps`;
  const navLbl = document.getElementById('gf-nav-label');
  if (navLbl) navLbl.textContent = `${_gfIdx+1} / ${_gfSession.exercises.length}`;
  const setsDisp = document.getElementById('gf-sets-display');
  if (setsDisp) setsDisp.innerHTML = Array.from({length:total},(_,i)=>{
    const borderC = i<done ? accent : 'rgba(255,255,255,.15)';
    const bgC     = i<done ? 'rgba('+acR+','+acG+','+acB+',.18)' : 'transparent';
    const textC   = i<done ? accent : 'rgba(255,255,255,.25)';
    const shadow  = i<done ? '0 0 8px rgba('+acR+','+acG+','+acB+',.3)' : 'none';
    return '<div style="width:36px;height:36px;border-radius:50%;display:flex;align-items:center;justify-content:center;'
      +'font-size:14px;font-weight:900;font-family:\'Orbitron\',monospace;'
      +'border:2px solid '+borderC+';background:'+bgC+';color:'+textC+';box-shadow:'+shadow+'">'
      +(i<done?'✓':i+1)+'</div>';
  }).join('');
  const mainBtn = document.getElementById('gf-main-btn');
  if (mainBtn) {
    if (done >= total) {
      const isLast = _gfIdx >= _gfSession.exercises.length-1;
      mainBtn.innerHTML = '<span style="font-size:28px">→</span><span>'+(isLast?'TERMINAR':'SIGUIENTE')+'</span>';
      mainBtn.style.background   = 'radial-gradient(circle,rgba(74,222,128,.2) 0%,rgba(74,222,128,.06) 70%)';
      mainBtn.style.borderColor  = 'rgba(74,222,128,.5)';
      mainBtn.style.boxShadow    = '0 0 40px rgba(74,222,128,.15)';
      mainBtn.onclick = () => { if(!isLast){gymFocusNav(1);}else{_doExitGymFocus();finishGymSession();} };
    } else {
      mainBtn.innerHTML = '<span style="font-size:36px">✓</span><span>SET LISTO</span><span style="font-size:12px;opacity:.6;font-family:\'JetBrains Mono\',monospace">'+ex.targetReps+' reps</span>';
      mainBtn.style.background  = 'radial-gradient(circle,rgba('+acR+','+acG+','+acB+',.2) 0%,rgba('+acR+','+acG+','+acB+',.06) 70%)';
      mainBtn.style.borderColor = 'rgba('+acR+','+acG+','+acB+',.4)';
      mainBtn.style.boxShadow   = '0 0 40px rgba('+acR+','+acG+','+acB+',.15),0 0 80px rgba('+acR+','+acG+','+acB+',.06)';
      mainBtn.onclick = gymFocusMarkSet;
    }
  }
}

function gymFocusMarkSet() {
  const ex = _gfSession?.exercises[_gfIdx]; if(!ex||ex.completedSets.length>=ex.targetSets) return;
  const btn = document.getElementById('gf-main-btn');
  if(btn){btn.style.transform='scale(.92)';setTimeout(()=>btn.style.transform='scale(1)',130);}
  ex.completedSets.push({reps:ex.targetReps,ts:Date.now()});
  gainXP(5); if(ex.completedSets.length>=ex.targetSets)spawnConfetti();
  _gymSession = _gfSession; renderGymFocusScreen();
}

function gymFocusNav(dir) {
  const n = _gfIdx+dir;
  if(n<0||n>=(_gfSession?.exercises.length||0))return;
  _gfIdx=n; if(_gymSession)_gymSession.currentIdx=n; renderGymFocusScreen();
}

/* ─── Dispatcher unificado de salida de modos enfoque ─── */
function salirModoEnfoque(modoId) {
  const map = {
    gym:    exitGymMode,
    gymFocus:  exitGymFocus,
    book:   exitBookFocus,
    pomo:   exitPomoAscension,
    focus:  exitFocusChamber
  };
  const fn = map[modoId];
  if (typeof fn === 'function') fn();
}

function exitGymFocus() {
  // Check if there are incomplete exercises in the session
  const _hasWork = _gfSession && _gfSession.exercises && _gfSession.exercises.some(function(ex){ return ex.completedSets.length < ex.targetSets; });
  if (_hasWork) {
    showFrictionModal(function(){ _doExitGymFocus(); });
    return;
  }
  _doExitGymFocus();
}
function _doExitGymFocus() {
  const o=document.getElementById('gym-focus-overlay'); if(o)o.style.display='none';
  document.body.style.overflow='';
  if(_gfStop){_gfStop();_gfStop=null;}
}

/* ══════════════════════════════════════════════════════════════
   BOOK FOCUS OVERLAY
══════════════════════════════════════════════════════════════ */
let _bfBookId=null,_bfSeconds=25*60,_bfMinutes=25,_bfRunning=false,_bfInterval=null,_bfSessionXP=0,_bfStop=null;

function openBookFocusOverlay(bookId) {
  const b=S.biblioteca.find(x=>x.id===bookId); if(!b)return;
  _bfBookId=bookId;_bfSeconds=25*60;_bfMinutes=25;_bfRunning=false;_bfSessionXP=0;
  clearInterval(_bfInterval);
  const overlay=document.getElementById('book-focus-overlay'); if(!overlay)return;
  overlay.style.display='flex'; document.body.style.overflow='hidden';
  const accent = S.accent || '#00e5ff';
  const acR=parseInt(accent.slice(1,3),16),acG=parseInt(accent.slice(3,5),16),acB=parseInt(accent.slice(5,7),16);
  const bgGlow = document.getElementById('bf-bg-glow');
  if (bgGlow) bgGlow.style.background = 'radial-gradient(ellipse 60% 50% at 50% 50%,rgba('+acR+','+acG+','+acB+',.06) 0%,transparent 70%)';
  const toggleBtn = document.getElementById('bf-toggle-btn');
  if (toggleBtn) {
    toggleBtn.style.background  = 'rgba('+acR+','+acG+','+acB+',.15)';
    toggleBtn.style.borderColor = 'rgba('+acR+','+acG+','+acB+',.4)';
    toggleBtn.style.boxShadow   = '0 0 16px rgba('+acR+','+acG+','+acB+',.12)';
  }
  const pagesBtn = document.querySelector('#book-focus-overlay button[onclick="bookFocusLogPages()"]');
  if (pagesBtn) {
    pagesBtn.style.background  = 'rgba('+acR+','+acG+','+acB+',.1)';
    pagesBtn.style.borderColor = 'rgba('+acR+','+acG+','+acB+',.25)';
  }
  const arc = document.getElementById('bf-arc');
  if (arc) arc.style.filter = 'drop-shadow(0 0 8px rgba('+acR+','+acG+','+acB+',.5))';
  _bfStop=spawnParticles('bf-particles',accent);
  document.getElementById('bf-book-title').textContent=b.titulo.toUpperCase();
  document.getElementById('bf-toggle-btn').textContent='▶ INICIAR';
  document.getElementById('bf-state').textContent='LISTO';
  document.getElementById('bf-session-xp').textContent='0';
  updateBFDisplay(); updateBFBookProgress(b);
}

function updateBFBookProgress(b) {
  const pct=b.readPct||0;
  document.getElementById('bf-pages-label').textContent=`${b.currentPage||0} / ${b.totalPages||'?'} págs.`;
  document.getElementById('bf-pct-label').textContent=pct+'% leído';
  document.getElementById('bf-progress-bar').style.width=pct+'%';
}

function toggleBFTimer() {
  const btn=document.getElementById('bf-toggle-btn');
  if(_bfRunning){clearInterval(_bfInterval);_bfRunning=false;if(btn)btn.textContent='▶ CONTINUAR';document.getElementById('bf-state').textContent='PAUSADO';}
  else{_bfInterval=setInterval(tickBF,1000);_bfRunning=true;if(btn)btn.textContent='⏸ PAUSAR';document.getElementById('bf-state').textContent='▶ LEYENDO';}
}

function tickBF() {
  if(_bfSeconds<=0){clearInterval(_bfInterval);_bfRunning=false;document.getElementById('bf-state').textContent='✅ COMPLETA';document.getElementById('bf-toggle-btn').textContent='▶ NUEVA';gainXP(15);_bfSessionXP+=15;document.getElementById('bf-session-xp').textContent=_bfSessionXP;spawnConfetti();return;}
  _bfSeconds--; updateBFDisplay();
}

function resetBFTimer(){clearInterval(_bfInterval);_bfRunning=false;_bfSeconds=_bfMinutes*60;document.getElementById('bf-toggle-btn').textContent='▶ INICIAR';document.getElementById('bf-state').textContent='LISTO';updateBFDisplay();}

function updateBFDisplay(){
  const mm=String(Math.floor(_bfSeconds/60)).padStart(2,'0'),ss=String(_bfSeconds%60).padStart(2,'0');
  const el=document.getElementById('bf-timer'); if(el)el.textContent=mm+':'+ss;
  const arc=document.getElementById('bf-arc'); if(arc)arc.style.strokeDashoffset=490*(1-_bfSeconds/(_bfMinutes*60));
}

/* ═══════════════════════════════════════════════════════════════
   PLANES SOCIALES — Sistema de Compromisos Grupales con XP
═══════════════════════════════════════════════════════════════ */

// ── State helpers ──
if (!S.socialPlans) S.socialPlans = [];
if (!S.socialPlanXPBonus) S.socialPlanXPBonus = 0;

// ── Abrir modal Nuevo Plan ──
function openModalNuevoPlan() {
  // Prellenar aliados como checkboxes
  const list = document.getElementById('np-aliados-list');
  if (list) {
    const aliados = S.aliados || [];
    if (!aliados.length) {
      list.innerHTML = '<div style="font-size:11px;color:var(--text3)">No tienes aliados aún. Agrégalos en Mente & Poder → Red de Aliados.</div>';
    } else {
      list.innerHTML = aliados.map(a => {
        return '<label style="display:flex;align-items:center;gap:6px;padding:5px 10px;border-radius:8px;cursor:pointer;background:rgba(168,85,247,.06);border:1px solid rgba(168,85,247,.15);font-size:12px;color:var(--text)">'
          +'<input type="checkbox" value="'+escHtml(a.id)+'" data-nombre="'+escHtml(a.nombre||a.name||'Aliado')+'" style="accent-color:#a855f7"> '
          +'<span>'+escHtml(a.nombre||a.name||'Aliado')+'</span></label>';
      }).join('');
    }
  }
  // Default fecha = 7 días
  const d = new Date(); d.setDate(d.getDate()+7);
  const el = document.getElementById('np-fecha');
  if (el) el.value = d.toISOString().split('T')[0];
  openModal('modal-nuevo-plan');
}

// ── Crear Plan Social ──
function crearPlanSocial() {
  const nombre = (document.getElementById('np-nombre').value||'').trim();
  if (!nombre) { showToast('⚠️ El plan necesita un nombre'); return; }
  const desc     = (document.getElementById('np-desc').value||'').trim();
  const fechaFin = document.getElementById('np-fecha').value || '';
  const xpReq    = parseInt(document.getElementById('np-xp').value) || 200;
  const objRaw   = (document.getElementById('np-objetivos').value||'').trim();
  const objetivos = objRaw ? objRaw.split('\n').map(o=>o.trim()).filter(Boolean) : [];

  // Aliados seleccionados
  const checks = document.querySelectorAll('#np-aliados-list input[type=checkbox]:checked');
  const invitados = Array.from(checks).map(c => ({
    id: c.value, nombre: c.dataset.nombre, objetivos:[], checkins:[], xpGanado:0, unido:false
  }));

  const plan = {
    id: uid(), nombre, desc, fechaFin, xpReq, objetivos,
    creador: { id:'yo', nombre: S.userName||'Tú' },
    participantes: invitados,
    checkins: [],   // checkins del creador [{fecha, xpSesion, multiplicador, xpFinal}]
    xpSesionAcum: 0,
    estado: 'activo',
    creadoEn: today()
  };

  if (!S.socialPlans) S.socialPlans = [];
  S.socialPlans.unshift(plan);

  // Marcar en el calendario
  if (fechaFin) {
    if (!S.calEvents[fechaFin]) S.calEvents[fechaFin] = [];
    S.calEvents[fechaFin].push({ id: uid(), text: '🤝 Plan: '+nombre, tipo:'plan', planId:plan.id });
  }

  guardarDatos();
  closeModal('modal-nuevo-plan');
  renderSocialPlans();
  renderCalendar();
  showToast('🤝 Plan "'+nombre+'" creado — invitaciones enviadas a '+invitados.length+' aliados');
}

// ── Render lista de planes ──
function renderSocialPlans() {
  const el = document.getElementById('social-plans-list'); if (!el) return;
  if (!S.socialPlans) S.socialPlans = [];
  if (!S.socialPlans.length) {
    el.innerHTML = '<div style="text-align:center;padding:20px;font-size:12px;color:var(--text3)">Crea tu primer plan social para comprometer a tus aliados 🤝</div>';
    return;
  }
  el.innerHTML = S.socialPlans.map(p => {
    const terminado = p.estado==='terminado' || (p.fechaFin && p.fechaFin < today());
    const checkinHoy = (p.checkins||[]).some(c => c.fecha === today());
    const totalCheckins = (p.checkins||[]).length;
    const xpAcum = (p.checkins||[]).reduce((a,c)=>a+(c.xpFinal||0),0);
    return '<div class="plan-card '+(terminado?'':'activo')+'" style="cursor:pointer" onclick="verDetallePlan(\''+p.id+'\')">'
      +'<div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px;margin-bottom:8px">'
        +'<div>'
          +'<div style="font-size:14px;font-weight:700;color:var(--text);margin-bottom:3px">'+escHtml(p.nombre)+'</div>'
          +(p.desc?'<div style="font-size:11px;color:var(--text3)">'+escHtml(p.desc)+'</div>':'')
        +'</div>'
        +'<span class="plan-badge '+(terminado?'terminado':'activo')+'">'+(terminado?'✅ TERMINADO':'⚡ ACTIVO')+'</span>'
      +'</div>'
      +'<div style="display:flex;gap:16px;font-size:11px;color:var(--text3);flex-wrap:wrap;margin-bottom:10px">'
        +(p.fechaFin?'<span>📅 Hasta '+p.fechaFin+'</span>':'')
        +'<span>👥 '+(p.participantes||[]).length+' aliados</span>'
        +'<span>✅ '+totalCheckins+' check-ins</span>'
        +'<span style="color:#ffd700">⚡ '+xpAcum+' XP ganado</span>'
      +'</div>'
      +(!terminado && !checkinHoy
        ? '<button onclick="event.stopPropagation();abrirCheckinPlan(\''+p.id+'\')" style="width:100%;padding:10px;background:rgba(168,85,247,.15);border:1px solid rgba(168,85,247,.4);border-radius:10px;color:#a855f7;font-family:\'Orbitron\',monospace;font-size:12px;font-weight:700;cursor:pointer;transition:all .2s">🎯 CHECK-IN DEL DÍA → GIRAR RULETA</button>'
        : (!terminado ? '<div style="text-align:center;padding:8px;font-size:11px;color:var(--accent);opacity:.7">✅ Check-in completado hoy</div>' : '')
      )
    +'</div>';
  }).join('');
}

