// ── Abrir check-in del plan → abre ruleta si cumplió objetivos ──
let _checkinPlanId = null;
function abrirCheckinPlan(planId) {
  _checkinPlanId = planId;
  const p = S.socialPlans.find(x=>x.id===planId); if(!p) return;
  // XP ganado hoy
  const xpHoy = S.xpHistory[today()] || 0;
  const cumplioXP = xpHoy >= (p.xpReq||200);
  if (!cumplioXP) {
    showToast('⚠️ Necesitas '+p.xpReq+' XP hoy para girar. Llevas '+xpHoy+' XP.');
    // Aun así abre pero informa
  }
  abrirRuleta(p.nombre, xpHoy, cumplioXP);
}

// ── Unirse a plan (aliado) — modal de objetivos propios ──
let _unirsePlanId = null;
function abrirModalUnirsePlan(planId) {
  _unirsePlanId = planId;
  const p = S.socialPlans.find(x=>x.id===planId); if(!p) return;
  const info = document.getElementById('mup-plan-info');
  if (info) info.innerHTML = 'Plan: <strong style="color:var(--accent)">'+escHtml(p.nombre)+'</strong>'
    +(p.xpReq?' · '+p.xpReq+' XP mínimo':'')
    +(p.fechaFin?' · Hasta '+p.fechaFin:'');
  openModal('modal-unirse-plan');
}
function confirmarUnirsePlan() {
  if (!_unirsePlanId) return;
  const p = S.socialPlans.find(x=>x.id===_unirsePlanId); if(!p) return;
  const objRaw = (document.getElementById('mup-objetivos').value||'').trim();
  const objetivos = objRaw ? objRaw.split('\n').map(o=>o.trim()).filter(Boolean) : [];
  // Buscar al participante (simula que el aliado actual es "yo" uniéndome a un plan ajeno)
  // En esta implementación local: se marca en participantes si existe, o se agrega como "yo me uno"
  let me = (p.participantes||[]).find(m=>m.id==='yo');
  if (!me) {
    if (!p.participantes) p.participantes = [];
    p.participantes.push({ id:'yo', nombre:S.userName||'Tú', objetivos, checkins:[], xpGanado:0, unido:true });
  } else {
    me.objetivos = objetivos; me.unido = true;
  }
  guardarDatos();
  closeModal('modal-unirse-plan');
  renderSocialPlans();
  showToast('✅ ¡Te uniste al plan "'+p.nombre+'"!');
}

// ── Eliminar plan ──
function eliminarPlan(planId, e) {
  if(e) e.stopPropagation();
  const p = S.socialPlans.find(x=>x.id===planId); if(!p) return;
  if (!confirm('¿Eliminar el plan "'+p.nombre+'"?')) return;
  S.socialPlans = S.socialPlans.filter(x=>x.id!==planId);
  guardarDatos(); renderSocialPlans(); renderCalendar();
  showToast('🗑️ Plan eliminado');
}

/* ═══════════════════════════════════════════════════════════════
   RULETA DE MULTIPLICADOR XP
═══════════════════════════════════════════════════════════════ */
const RULETA_SEGMENTS = [
  { label:'×1.5', mult:1.5, color:'#0080cc', prob:0.45 },
  { label:'×2.0', mult:2.0, color:'#a855f7', prob:0.35 },
  { label:'×2.5', mult:2.5, color:'#ffd700', prob:0.20 }
];
const RULETA_XP_CAP = 1000;
let _ruletaSpun = false;
let _ruletaXPSesion = 0;
let _ruletaStopParticles = null;

function dibujarRuleta(rotacionDeg) {
  const canvas = document.getElementById('ruleta-canvas'); if(!canvas) return;
  const ctx = canvas.getContext('2d');
  const cx=130, cy=130, r=120;
  ctx.clearRect(0,0,260,260);
  // Calcular ángulos según probabilidad
  const totalSegments = 12; // 12 sectores: 5-6 ×1.5, 4 ×2.0, 2-3 ×2.5
  const distribution = [
    ...Array(6).fill(RULETA_SEGMENTS[0]),
    ...Array(4).fill(RULETA_SEGMENTS[1]),
    ...Array(2).fill(RULETA_SEGMENTS[2])
  ];
  const angleStep = (Math.PI*2) / distribution.length;
  const offset = (rotacionDeg * Math.PI/180);
  distribution.forEach((seg,i) => {
    const startA = i*angleStep + offset - Math.PI/2;
    const endA   = startA + angleStep;
    ctx.beginPath();
    ctx.moveTo(cx,cy);
    ctx.arc(cx,cy,r,startA,endA);
    ctx.closePath();
    ctx.fillStyle = seg.color;
    ctx.fill();
    ctx.strokeStyle = 'rgba(0,0,0,.25)';
    ctx.lineWidth = 2;
    ctx.stroke();
    // Label
    const midA = startA + angleStep/2;
    ctx.save();
    ctx.translate(cx + Math.cos(midA)*(r*0.65), cy + Math.sin(midA)*(r*0.65));
    ctx.rotate(midA + Math.PI/2);
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 14px Orbitron,monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText(seg.label, 0, 0);
    ctx.restore();
  });
  // Center cap
  ctx.beginPath(); ctx.arc(cx,cy,22,0,Math.PI*2);
  ctx.fillStyle = '#0a0f1e'; ctx.fill();
  ctx.strokeStyle = 'rgba(0,229,255,.4)'; ctx.lineWidth = 2; ctx.stroke();
  ctx.fillStyle = '#fff'; ctx.font = 'bold 11px Orbitron,monospace';
  ctx.textAlign='center'; ctx.textBaseline='middle';
  ctx.fillText('XP', cx, cy);
}

function abrirRuleta(planNombre, xpSesion, cumplioXP) {
  _ruletaSpun = false;
  _ruletaXPSesion = xpSesion;
  const overlay = document.getElementById('xp-ruleta-overlay'); if(!overlay) return;
  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';
  document.getElementById('ruleta-plan-nombre').textContent = planNombre.toUpperCase();
  document.getElementById('ruleta-xp-earned').textContent = 'XP ganado hoy: '+xpSesion+(cumplioXP?' ✅':' ⚠️ (no cumpliste el mínimo)');
  document.getElementById('ruleta-multiplier').style.display = 'none';
  document.getElementById('ruleta-xp-final').style.display = 'none';
  document.getElementById('ruleta-spin-btn').style.display = cumplioXP ? 'block' : 'none';
  document.getElementById('ruleta-close-btn').style.display = cumplioXP ? 'none' : 'block';
  if (!cumplioXP) {
    document.getElementById('ruleta-xp-earned').textContent += '\n\nGana '+((S.socialPlans.find(p=>p.id===_checkinPlanId)||{}).xpReq||200)+' XP primero para activar la ruleta.';
  }
  dibujarRuleta(0);
  if(_ruletaStopParticles){_ruletaStopParticles();_ruletaStopParticles=null;}
  _ruletaStopParticles = spawnParticles('ruleta-particles', S.accent||'#00e5ff');
}

function girarRuleta() {
  if (_ruletaSpun) return;
  _ruletaSpun = true;
  document.getElementById('ruleta-spin-btn').disabled = true;
  document.getElementById('ruleta-spin-btn').textContent = '⏳ Girando...';

  // Elegir multiplicador según probabilidad
  const rand = Math.random();
  let chosen = RULETA_SEGMENTS[0];
  if (rand < 0.20) chosen = RULETA_SEGMENTS[2];       // 20% → ×2.5
  else if (rand < 0.55) chosen = RULETA_SEGMENTS[1];  // 35% → ×2.0
  // else ×1.5

  // Calcular ángulo final donde debe parar
  const distribution = [
    ...Array(6).fill(0), // ×1.5 → slots 0-5
    ...Array(4).fill(1), // ×2.0 → slots 6-9
    ...Array(2).fill(2)  // ×2.5 → slots 10-11
  ];
  const targetSlots = distribution.reduce((acc,v,i)=>{if(v===RULETA_SEGMENTS.indexOf(chosen))acc.push(i);return acc;},[]);
  const targetSlot  = targetSlots[Math.floor(Math.random()*targetSlots.length)];
  const angleStep   = 360/12;
  const targetAngle = 360 - (targetSlot * angleStep + angleStep/2);
  const totalSpin   = 1440 + targetAngle; // 4 vueltas + posición exacta

  let start = null;
  const duration = 3200;
  let currentAngle = 0;

  function animate(ts) {
    if (!start) start = ts;
    const elapsed = ts - start;
    const progress = Math.min(elapsed/duration, 1);
    const eased = 1 - Math.pow(1-progress, 4); // ease-out quart
    currentAngle = eased * totalSpin;
    dibujarRuleta(currentAngle % 360);
    if (progress < 1) {
      requestAnimationFrame(animate);
    } else {
      // Terminó
      setTimeout(() => mostrarResultadoRuleta(chosen), 300);
    }
  }
  requestAnimationFrame(animate);
}

function mostrarResultadoRuleta(segment) {
  const xpBase = Math.min(_ruletaXPSesion, RULETA_XP_CAP);
  const xpFinal = Math.min(Math.round(xpBase * segment.mult), RULETA_XP_CAP);

  // Mostrar resultado
  const multEl = document.getElementById('ruleta-multiplier');
  const finalEl = document.getElementById('ruleta-xp-final');
  multEl.textContent = segment.label;
  multEl.style.color = segment.color;
  multEl.style.display = 'block';
  finalEl.textContent = '+'+xpFinal+' XP (cap: '+RULETA_XP_CAP+')';
  finalEl.style.display = 'block';
  document.getElementById('ruleta-spin-btn').style.display = 'none';
  document.getElementById('ruleta-close-btn').style.display = 'block';

  // Aplicar XP
  gainXP(xpFinal);
  S.socialPlanXPBonus = (S.socialPlanXPBonus||0) + xpFinal;

  // Registrar check-in en el plan
  if (_checkinPlanId) {
    const p = S.socialPlans.find(x=>x.id===_checkinPlanId);
    if (p) {
      if (!p.checkins) p.checkins = [];
      p.checkins.push({ fecha:today(), xpSesion:_ruletaXPSesion, multiplicador:segment.mult, xpFinal });
      // Impacto en radar: incrementar un bonus social
      S.socialPlanXPBonus = (S.socialPlanXPBonus||0);
    }
  }

  // Actualizar radar
  updateRadarColors && updateRadarColors();
  guardarDatos();
  spawnConfetti();
  showToast('🎰 '+segment.label+' — ¡+'+xpFinal+' XP al plan!');
}

function cerrarRuleta() {
  const overlay = document.getElementById('xp-ruleta-overlay'); if(overlay) overlay.classList.remove('active');
  document.body.style.overflow = '';
  if(_ruletaStopParticles){_ruletaStopParticles();_ruletaStopParticles=null;}
  renderSocialPlans();
  // Marcar check-in del día en el plan
  if(_checkinPlanId){
    const p = S.socialPlans.find(x=>x.id===_checkinPlanId);
    if(p && p.checkins && !p.checkins.slice(-1)[0]?.fecha===today()){
      // ya guardado
    }
    _checkinPlanId = null;
  }
}

/* Hook: radar Social ahora también cuenta check-ins de planes */
const _origGetRadarData = getRadarData;
function getRadarData(mode) {
  // Call the internal logic inline (can't re-call to avoid recursion)
  const muscleVals = Object.values(S.muscleMap || {});
  const fisico = muscleVals.length ? Math.round(muscleVals.reduce((a,b)=>a+b,0)/muscleVals.length) : 50;
  const mental = Math.round(S.claridad * 0.4 + S.energia * 0.3 + S.productividad * 0.3);
  const totalIn  = (S.transactions||[]).filter(t=>t.type==='entrada').reduce((a,t)=>a+t.amount,0);
  const totalOut = (S.transactions||[]).filter(t=>t.type==='salida').reduce((a,t)=>a+t.amount,0);
  const finanzas = totalIn+totalOut > 0 ? Math.min(100, Math.round((totalIn/(totalIn+totalOut))*100)) : 50;
  const habTotal = (S.habits||[]).length || 1;
  const habDone  = (S.habits||[]).filter(h=>h.completedToday).length;
  const habitos  = Math.round((habDone/habTotal)*100);
  const trabajo  = S.productividad || 50;
  // Social: check-in streak + participación activa en planes sociales
  const planCheckins = (S.socialPlans||[]).reduce((a,p)=>a+(p.checkins||[]).length,0);
  const socialBase   = Math.min(100, (S.checkInStreak||0) * 12 + planCheckins * 8);
  const social = Math.min(100, socialBase);
  const daily   = [fisico, mental, finanzas, habitos, trabajo, social];
  const monthly = daily.map(v => Math.min(100, Math.round(v * 0.85 + 12)));
  return mode === 'daily' ? daily : monthly;
}

