const AG_COLS_AGENCY   = ['fechaIda','fechaRegreso','cliente','pasajeros','pasAdicionales','origen','destino','precioReal','precioVenta'];
const AG_COLS_EXTERNAL = ['fechaIda','fechaRegreso','cliente','pasajeros','pasAdicionales','origen','destino','costoProveedor','precioVenta'];
const AG_LABELS = {
  fechaIda:'F. Ida', fechaRegreso:'F. Regreso', cliente:'Cliente',
  pasajeros:'#Pax', pasAdicionales:'Pax Adic.', origen:'Origen', destino:'Destino',
  precioReal:'P. Real', costoProveedor:'C. Proveedor', precioVenta:'P. Venta',
  separacionInversion:'Sep. Inv.', reservaLey:'Reserva Ley', gananciaNeta:'G. Neta'
};
const AG_DISPLAY_AGENCY = ['fechaIda','fechaRegreso','cliente','pasajeros','origen','destino','precioReal','costoProveedor','precioVenta','separacionInversion','reservaLey','gananciaNeta'];
const AG_DISPLAY_EXT   = ['fechaIda','fechaRegreso','cliente','pasajeros','origen','destino','costoProveedor','precioVenta','reservaLey','gananciaNeta'];

function calcAgencyRow(row, isExt) {
  const pv = parseFloat(row.precioVenta)||0;
  const pr = parseFloat(row.precioReal)||0;
  const cp = parseFloat(row.costoProveedor)||0;
  if (isExt) {
    const rl = pv * .20;
    return { ...row, reservaLey: rl, gananciaNeta: pv - cp - rl };
  } else {
    const cpC = pr * .40, si = pv * .2976, rl = pv * .20;
    return { ...row, costoProveedor: cpC, separacionInversion: si, reservaLey: rl, gananciaNeta: pv - si - rl };
  }
}

function switchAgencyTab(idx) {
  S.currentAgencyTab = idx;
  document.querySelectorAll('#agency-tabs .tab-btn').forEach((b, i) => {
    b.className = 'tab-btn ' + (i === idx ? 'on' : 'off');
  });
  renderAgencyTable();
}

function openAgencyForm() {
  const isExt = S.currentAgencyTab === 2;
  const cols  = isExt ? AG_COLS_EXTERNAL : AG_COLS_AGENCY;
  document.getElementById('ag-modal-title').textContent =
    'NUEVO REGISTRO — ' + ['Vuelos Agencia','Hoteles Agencia','Vuelos Externos'][S.currentAgencyTab];
  const ff = document.getElementById('ag-form-fields');
  ff.innerHTML = cols.map(c => `
    <div>
      <div style="font-size:10px;color:var(--text3);margin-bottom:3px">${AG_LABELS[c]}</div>
      <input class="inp" id="ag-f-${c}"
        type="${c.startsWith('fecha') ? 'date' : (c==='pasajeros'||c==='precioReal'||c==='precioVenta'||c==='costoProveedor' ? 'number' : 'text')}"
        placeholder="${AG_LABELS[c]}"/>
    </div>`).join('');
  document.getElementById('ag-calc-preview').style.display = 'none';
  openModal('modal-agency');
  ['precioReal','precioVenta','costoProveedor'].forEach(c => {
    const el = document.getElementById('ag-f-' + c);
    if (el) el.addEventListener('input', updateAgencyPreview);
  });
}

function updateAgencyPreview() {
  const isExt = S.currentAgencyTab === 2;
  const pv = parseFloat(document.getElementById('ag-f-precioVenta')?.value) || 0;
  const pr = parseFloat(document.getElementById('ag-f-precioReal')?.value)  || 0;
  const cp = parseFloat(document.getElementById('ag-f-costoProveedor')?.value) || 0;
  const prev = document.getElementById('ag-calc-preview');
  if (!prev) return;
  if (pv > 0) {
    prev.style.display = 'block';
    if (isExt) {
      const rl = pv * .20;
      prev.innerHTML = `<span style="color:var(--accent);font-family:Syne;font-weight:700">CÁLCULO AUTO:</span><br>
        Reserva Ley = ${fmt(rl)}<br>
        <span style="color:var(--green)">Ganancia Neta = ${fmt(pv - cp - rl)}</span>`;
    } else {
      const cpC = pr * .40, si = pv * .2976, rl = pv * .20;
      prev.innerHTML = `<span style="color:var(--accent);font-family:Syne;font-weight:700">CÁLCULO AUTO:</span><br>
        C. Proveedor = ${fmt(cpC)}<br>
        Sep. Inversión = ${fmt(si)}<br>
        Reserva Ley = ${fmt(rl)}<br>
        <span style="color:var(--green)">Ganancia Neta = ${fmt(pv - si - rl)}</span>`;
    }
  } else {
    prev.style.display = 'none';
  }
}

function submitAgencyRow() {
  const isExt = S.currentAgencyTab === 2;
  const cols  = isExt ? AG_COLS_EXTERNAL : AG_COLS_AGENCY;
  const base  = { id: uid() };
  cols.forEach(c => { const el = document.getElementById('ag-f-' + c); if (el) base[c] = el.value; });
  const row = calcAgencyRow(base, isExt);
  S.agencyTabs[S.currentAgencyTab].push(row);
  guardarDatos();
  closeModal('modal-agency');
  renderAgencyTable();
}

function renderAgencyTable() {
  if (!document.getElementById('agency-thead')) return; // page not yet in DOM
  const isExt  = S.currentAgencyTab === 2;
  const rows   = S.agencyTabs[S.currentAgencyTab];
  const disp   = isExt ? AG_DISPLAY_EXT : AG_DISPLAY_AGENCY;
  const thead  = document.getElementById('agency-thead');
  const tbody  = document.getElementById('agency-tbody');
  const tfoot  = document.getElementById('agency-tfoot');
  const totalV = rows.reduce((a, r) => a + (parseFloat(r.precioVenta)  || 0), 0);
  const totalG = rows.reduce((a, r) => a + (parseFloat(r.gananciaNeta) || 0), 0);
  document.getElementById('ag-ventas').textContent   = fmt(totalV);
  document.getElementById('ag-ganancia').textContent = fmt(totalG);
  document.getElementById('ag-count').textContent    = rows.length;
  thead.innerHTML = `<tr>${disp.map(c => `<th>${AG_LABELS[c] || c}</th>`).join('')}<th>ACCIONES</th></tr>`;
  if (!rows.length) {
    tbody.innerHTML = `<tr><td colspan="${disp.length + 1}" style="text-align:center;padding:36px;font-size:13px;color:var(--text3)">📭 Sin registros. La tabla iniciará vacía.</td></tr>`;
  } else {
    tbody.innerHTML = rows.map(r => `<tr>${disp.map(c => {
      const monC = ['gananciaNeta','precioVenta','costoProveedor','reservaLey','separacionInversion','precioReal'].includes(c);
      const style = `color:${c==='gananciaNeta'||c==='precioVenta' ? 'var(--green)' : ['costoProveedor','reservaLey','separacionInversion'].includes(c) ? 'var(--red)' : 'inherit'};font-family:${monC ? "'JetBrains Mono',monospace" : "'Syne',sans-serif"}`;
      return `<td style="${style}">${monC ? fmt(r[c]) : (r[c] || '—')}</td>`;
    }).join('')}<td><div style="display:flex;gap:6px">
      <button class="btn btn-g btn-sm" onclick="openEditAgency('${r.id}')">✏️</button>
      <button class="btn btn-d" onclick="deleteAgencyRow('${r.id}')">🗑</button>
    </div></td></tr>`).join('');
  }
  const span = Math.max(0, disp.length - 2);
  tfoot.innerHTML = `<tr>
    <td colspan="${span}" style="font-size:12px;color:var(--text2);font-weight:700">TOTALES</td>
    <td style="color:var(--green);font-family:'JetBrains Mono',monospace;font-weight:700">${fmt(totalV)}</td>
    <td style="color:var(--accent);font-family:'JetBrains Mono',monospace;font-weight:700">${fmt(totalG)}</td>
    <td></td></tr>`;
}

function deleteAgencyRow(id) {
  if (!confirm('¿Eliminar este registro?')) return;
  S.agencyTabs[S.currentAgencyTab] = S.agencyTabs[S.currentAgencyTab].filter(r => r.id !== id);
  guardarDatos();
  renderAgencyTable();
}

function openEditAgency(id) {
  const isExt = S.currentAgencyTab === 2;
  const cols  = isExt ? AG_COLS_EXTERNAL : AG_COLS_AGENCY;
  const row   = S.agencyTabs[S.currentAgencyTab].find(r => r.id === id);
  if (!row) return;
  S.editingAgencyRow = id;
  const ff = document.getElementById('ag-edit-fields');
  ff.innerHTML = cols.map(c => `
    <div>
      <div style="font-size:10px;color:var(--text3);margin-bottom:3px">${AG_LABELS[c]}</div>
      <input class="inp" id="age-f-${c}"
        type="${c.startsWith('fecha') ? 'date' : 'text'}"
        value="${row[c] || ''}"/>
    </div>`).join('');
  openModal('modal-edit-agency');
}

function saveAgencyEdit() {
  const isExt = S.currentAgencyTab === 2;
  const cols  = isExt ? AG_COLS_EXTERNAL : AG_COLS_AGENCY;
  const rows  = S.agencyTabs[S.currentAgencyTab];
  const idx   = rows.findIndex(r => r.id === S.editingAgencyRow);
  if (idx < 0) return;
  const updated = { ...rows[idx] };
  cols.forEach(c => { const el = document.getElementById('age-f-' + c); if (el) updated[c] = el.value; });
  rows[idx] = calcAgencyRow(updated, isExt);
  guardarDatos();
  closeModal('modal-edit-agency');
  renderAgencyTable();
}

/* ═══════════════════════════════════════════
   INNER-PAGE TAB SWITCHER
═══════════════════════════════════════════ */
const _innerTabState = {};

/* ═══════════════════════════════════════════════════════════════
   IDEAS RÁPIDAS — render, filter, actions
═══════════════════════════════════════════════════════════════ */

let _ideasFilter = 'all';

// ── Visual identity per idea ─────────────────────────
function _ideaHash(text) {
  let h = 0;
  for (let i = 0; i < text.length; i++) h = (Math.imul(31, h) + text.charCodeAt(i)) | 0;
  return Math.abs(h);
}

const _IDEA_PALETTES = [
  ['#0d1f3c','#00e5ff','rgba(0,229,255,.25)'],
  ['#1a0d2e','#a855f7','rgba(168,85,247,.28)'],
  ['#0d2218','#4ade80','rgba(74,222,128,.22)'],
  ['#2d1a00','#ffd700','rgba(255,215,0,.22)'],
  ['#2d0d1a','#f472b6','rgba(244,114,182,.22)'],
  ['#0d1a2d','#60a5fa','rgba(96,165,250,.22)'],
  ['#1f1200','#ff6b35','rgba(255,107,53,.22)'],
  ['#001a1a','#00e5ff','rgba(0,229,255,.2)'],
];

function getIdeaVisual(text) {
  const n = (text || '').toLowerCase();
  const hash = _ideaHash(text);
  const palette = _IDEA_PALETTES[hash % _IDEA_PALETTES.length];

  // Primary emoji from content
  let primary = '💡';
  let secondary = '';
  if (/app|web|código|code|software|feature|bug|diseño|design|ui|ux/.test(n))      { primary='💻'; secondary='✨'; }
  else if (/negocio|startup|empresa|cliente|venta|market|product|money/.test(n))   { primary='🚀'; secondary='💰'; }
  else if (/salud|ejercicio|gym|correr|dieta|nutricion|bienestar/.test(n))          { primary='💪'; secondary='🌿'; }
  else if (/libro|leer|aprender|curso|estudi|conocimiento|skill/.test(n))           { primary='📚'; secondary='🧠'; }
  else if (/viaje|lugar|ciudad|pais|país|explorar|conocer/.test(n))                 { primary='🌍'; secondary='✈️'; }
  else if (/música|musica|arte|pintura|creatividad|crear|diseñ/.test(n))            { primary='🎨'; secondary='✨'; }
  else if (/dinero|ahorro|inversion|inversión|finanza|pasivo/.test(n))              { primary='💰'; secondary='📈'; }
  else if (/relacion|relación|amigo|familia|social|comunidad/.test(n))             { primary='🤝'; secondary='❤️'; }
  else if (/idea|concepto|proyecto|plan|estrateg|innovar/.test(n))                  { primary='💡'; secondary='🔥'; }
  else if (/comida|receta|cocin|restauran/.test(n))                                 { primary='🍽️'; secondary='✨'; }
  else if (/mode|oscuro|dark|color|tema|theme|visual/.test(n))                      { primary='🎨'; secondary='🌙'; }
  else { primary='💡'; secondary=['⚡','🌟','✨','🔮','🎯'][hash % 5]; }

  const [bg, accent, glow] = palette;
  const gradient = `linear-gradient(135deg, ${bg} 0%, ${bg}dd 40%, ${glow} 100%)`;

  return { primary, secondary, gradient, accent };
}

// ── Format date for cards ─────────────────────────────
function _fmtIdeaDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr + 'T12:00:00');
  const days = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
  const ms = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  if (dateStr === today()) return 'Hoy';
  const yesterday = new Date(); yesterday.setDate(yesterday.getDate()-1);
  if (dateStr === yesterday.toISOString().split('T')[0]) return 'Ayer';
  return `${days[d.getDay()]} ${d.getDate()} ${ms[d.getMonth()]}`;
}

// ── Main render ───────────────────────────────────────
function renderIdeas() {
  const grid = document.getElementById('ideas-grid');
  if (!grid) return;

  const ideas = S.ideas || [];
  const pendingCount = ideas.filter(i => !i.status || i.status === 'pending').length;

  // Update pending badge in tab
  const badge = document.getElementById('ideas-pending-badge');
  if (badge) {
    badge.textContent = pendingCount;
    badge.classList.toggle('show', pendingCount > 0);
    badge.style.display = pendingCount > 0 ? 'inline-block' : 'none';
  }
  // Dot on tab button
  const dot = document.getElementById('ideas-tab-dot');
  if (dot) dot.style.display = pendingCount > 0 ? 'inline-block' : 'none';

  // Update filter button badges
  const pfBtn = document.getElementById('idf-pending');
  if (pfBtn) {
    const spanEl = pfBtn.querySelector('.ideas-pending-badge');
    if (spanEl) { spanEl.textContent = pendingCount; spanEl.style.display = pendingCount > 0 ? 'inline-block' : 'none'; }
  }

  // Filter
  let visible = ideas;
  if (_ideasFilter === 'pending')   visible = ideas.filter(i => !i.status || i.status === 'pending');
  if (_ideasFilter === 'converted') visible = ideas.filter(i => i.status === 'task' || i.status === 'goal' || i.status === 'kept');

  if (!visible.length) {
    const msgs = {
      all:       ['💡','Aún no hay ideas capturadas','Usa el botón flotante y escribe "idea: tu idea"'],
      pending:   ['✅','Todo clasificado','No hay ideas pendientes de revisar'],
      converted: ['🎯','Sin conversiones aún','Convierte tus ideas en tareas o metas'],
    };
    const [ico, title, sub] = msgs[_ideasFilter];
    grid.innerHTML = `<div class="ideas-empty">
      <span class="ideas-empty-icon">${ico}</span>
      <div style="font-weight:700;font-size:15px;color:var(--text);margin-bottom:6px">${title}</div>
      <div>${sub}</div>
    </div>`;
    return;
  }

  grid.innerHTML = visible.map(idea => _renderIdeaCard(idea)).join('');
}

function _renderIdeaCard(idea) {
  const vis = getIdeaVisual(idea.text || '');
  const isPending = !idea.status || idea.status === 'pending';
  const isConverted = idea.status === 'task' || idea.status === 'goal';

  const statusDotCls = isPending ? 'pending' : isConverted ? 'converted' : 'kept';

  let convertedLabel = '';
  if (idea.status === 'task') {
    convertedLabel = `<div class="idea-card-converted-label" style="background:rgba(0,229,255,.1);color:var(--accent);border:1px solid rgba(0,229,255,.2)">✅ En Tareas</div>`;
  } else if (idea.status === 'goal') {
    convertedLabel = `<div class="idea-card-converted-label" style="background:rgba(168,85,247,.1);color:#a855f7;border:1px solid rgba(168,85,247,.2)">🎯 En Metas</div>`;
  } else if (idea.status === 'kept') {
    convertedLabel = `<div class="idea-card-converted-label" style="background:rgba(255,213,0,.08);color:#ffd700;border:1px solid rgba(255,213,0,.2)">💡 Guardada</div>`;
  }

  const dateLabel = _fmtIdeaDate(idea.date);
  const timeLabel = idea.time ? ` · ${idea.time}` : '';

  const actionArea = isConverted || idea.status === 'kept'
    ? `<button class="idea-action-btn btn-del" onclick="deleteIdea('${idea.id}')">🗑 Eliminar</button>`
    : `<button class="idea-action-btn btn-keep" onclick="keepIdea('${idea.id}')">💡 Mantener</button>
       <button class="idea-action-btn btn-task" onclick="ideaToTask('${idea.id}')">✅ Tarea</button>
       <button class="idea-action-btn btn-goal" onclick="ideaToGoal('${idea.id}')">🎯 Meta</button>`;

  return `<div class="idea-card" id="idea-card-${idea.id}">
    <div class="idea-card-art" style="background:${vis.gradient}">
      <div class="idea-card-art-noise"></div>
      <div class="idea-status-dot ${statusDotCls}"></div>
      <div class="idea-card-art-emojis">
        <span>${vis.primary}</span>
        ${vis.secondary ? `<span class="em-secondary">${vis.secondary}</span>` : ''}
      </div>
    </div>
    <div class="idea-card-body">
      <div class="idea-card-text">${escHtml(idea.text || '')}</div>
      <div class="idea-card-meta">
        <span>${dateLabel}${timeLabel}</span>
        ${convertedLabel}
      </div>
    </div>
    <div class="idea-card-actions">${actionArea}</div>
  </div>`;
}

// ── Filter ────────────────────────────────────────────
function filterIdeas(filter) {
  _ideasFilter = filter;
  document.querySelectorAll('.ideas-filter-btn').forEach(btn => {
    btn.classList.toggle('active', btn.id === 'idf-' + filter);
  });
  renderIdeas();
}

// ── Actions ───────────────────────────────────────────
function keepIdea(id) {
  const idea = (S.ideas||[]).find(i => i.id === id);
  if (!idea) return;
  idea.status = 'kept';
  guardarDatos();
  renderIdeas();
  showToast('💡 Idea guardada');
}

function ideaToTask(id) {
  const idea = (S.ideas||[]).find(i => i.id === id);
  if (!idea) return;
  S.tasks.unshift({ id:uid(), name:idea.text, desc:'', date:today(), time:'', done:false });
  idea.status = 'task';
  if (typeof renderTasks === 'function') renderTasks();
  if (typeof updateDashboardTaskCount === 'function') updateDashboardTaskCount();
  guardarDatos();
  renderIdeas();
  showToast('✅ Convertida en tarea');
}

function ideaToGoal(id) {
  const idea = (S.ideas||[]).find(i => i.id === id);
  if (!idea) return;
  S.goals.unshift({
    id:uid(), name:idea.text, desc:'', category:'Personal',
    deadline:'', objectives:[], xp:100, done:false, createdAt:today()
  });
  idea.status = 'goal';
  if (typeof renderGoals === 'function') renderGoals();
  guardarDatos();
  renderIdeas();
  showToast('🎯 Convertida en meta');
}

function deleteIdea(id) {
  S.ideas = (S.ideas||[]).filter(i => i.id !== id);
  guardarDatos();
  renderIdeas();
}

function switchInnerTab(pageId, tabId) {
  _innerTabState[pageId] = tabId;
  // Update tab buttons
  const tabsEl = document.getElementById('inner-tabs-' + pageId);
  if (tabsEl) {
    tabsEl.querySelectorAll('.inner-tab').forEach(btn => {
      const isActive = btn.getAttribute('onclick').includes("'" + tabId + "'");
      btn.classList.toggle('active', isActive);
    });
  }
  // Update panels
  const pageEl = document.getElementById('page-' + pageId);
  if (pageEl) {
    pageEl.querySelectorAll('.inner-panel').forEach(p => {
      p.classList.toggle('active', p.id === 'panel-' + tabId);
    });
  }
  // Fire init for the revealed tab
  _fireTabInit(pageId, tabId);
}

function _fireTabInit(pageId, tabId) {
  if (tabId === 'habits')   { buildHeatmap(); renderHabits(); }
  if (tabId === 'goals')    { renderGoals(); }
  if (tabId === 'ideas')    { renderIdeas(); }
  if (tabId === 'physical') { initVolumeChart(); buildMuscleMap(); buildFreqHeatmap(); _applyNPCVisibility(); applyMuscleHighlights(); updateBioMainBtn(); renderRutinasFrecuentes(); renderRoutines(); }
  if (tabId === 'salud')    { resetSaludIfNewDay(); updateSaludUI(); }
  if (tabId === 'brain')    { initGemelo(); }
  if (tabId === 'poder')    { renderPoderSections(); }
  if (tabId === 'analisis') {
    initAnalisisCharts();
    updateGlobalCore();
    // Cargar XP Chart real desde Firestore user_activity
    const _uid = _auth?.currentUser?.uid;
    if (_uid) renderXPChart(_uid);
  }
  if (tabId === 'saas')     { renderLeaderboard(); renderWrapped(); updateGlobalCore(); }
  // Onboarding sub-card for inner tabs
  setTimeout(() => showSubCard(tabId), 300);
}

function _initInnerTab(pageId) {
  const activeTab = _innerTabState[pageId];
  if (activeTab) {
    // Restore last active tab
    switchInnerTab(pageId, activeTab);
  } else {
    // Fire init for the default (first) tab
    const pageEl = document.getElementById('page-' + pageId);
    if (pageEl) {
      const firstActive = pageEl.querySelector('.inner-panel.active');
      if (firstActive) {
        const tid = firstActive.id.replace('panel-', '');
        _fireTabInit(pageId, tid);
      }
    }
  }
}
/* ═══════════════════════════════════════════════════════════════
   FUNCIONALIDAD 1 — GAINXP WRAPPER
═══════════════════════════════════════════════════════════════ */
function gainXP(amount) {
  S.xp += amount;
  // Track daily XP history
  const t = today();
  S.xpHistory[t] = (S.xpHistory[t] || 0) + amount;
  updateXP();
  updateGlobalCore();
  guardarDatos();
}

/* togglePomo is unified above — no patch needed */

/* ═══════════════════════════════════════════════════════════════
   APARTMENT INTERIOR ENGINE
   ─ Drop image into #apt-bg src and update APT_ZONES coordinates
   ─ when the apartment image is ready.
═══════════════════════════════════════════════════════════════ */

/* Zone definitions — page = Life OS module to navigate */
const APT_ZONES = {
  'banco':       { label:'BANCO',      emoji:'🏦', page:'financial',    desc:'Caja fuerte — Gestiona tus finanzas' },
  'biblioteca-l':{ label:'AGENDA',     emoji:'📅', page:'calendar',     desc:'Armario — Calendario y agenda' },
  'config':      { label:'CONFIG',     emoji:'⚙️', page:'settings',     desc:'Escritorio — Ajustes del sistema' },
  'lab':         { label:'LAB',        emoji:'🔬', page:'stats',        desc:'Arcade — Análisis y estadísticas' },
  'biblioteca':  { label:'BIBLIOTECA', emoji:'📚', page:'mente',        desc:'Caballete — Mente & poder' },
  'gym':         { label:'GYM',        emoji:'🏋️', page:'cuerpo',       desc:'Pesas — Entrenamiento y cuerpo' },
};

let _aptCurrentZone = null;

/* ═══════════════════════════════════════════════════════════════
   SCENE SYSTEM — City ↔ Apartment
   Each user has their own apartment stored in S.apartments[userId]
═══════════════════════════════════════════════════════════════ */

// Per-user apartment state stored in S (persisted with guardarDatos)
// S.apartments = { 'Wences Mejia': { visited: true, lastZone: 'config' }, ... }
const SCENE = { current: 'city' }; // 'city' | 'apt'

/* Called when user clicks APT zone in city — show confirm dialog */
function aptShowConfirm() {
  const dlg = document.getElementById('apt-confirm');
  if (!dlg) return;
  // Personalize with current user
  const userName = S.userName || 'Usuario';
  const userEl = document.getElementById('apt-confirm-user');
  if (userEl) userEl.textContent = '👤 ' + userName + ' · Apt 1B';
  dlg.classList.add('open');
}

/* User cancelled */
function aptConfirmCancel() {
  document.getElementById('apt-confirm')?.classList.remove('open');
  // Return bubble to previous position
  W.currentZone = null;
}

/* User confirmed — transition to apartment scene */
function aptConfirmEnter() {
  document.getElementById('apt-confirm')?.classList.remove('open');
  _transitionToScene('apt');
}

/* Exit apartment — go back to city */
function exitApartment() {
  _transitionToScene('city');
}

/* Core scene transition */
function _transitionToScene(target) {
  const cityEl = document.getElementById('city-scene');
  const aptEl  = document.getElementById('apt-scene');
  if (!cityEl || !aptEl) return;

  if (target === 'apt') {
    // City slides left, apt comes from right
    cityEl.className = 'scene scene-hidden-left';
    aptEl.className  = 'scene scene-active';
    SCENE.current = 'apt';
    // Sync apt bubble with user's bubble
    _syncAptBubble();
    // Update owner badge
    const badge = document.getElementById('apt-owner-badge');
    if (badge) badge.textContent = '👤 ' + (S.userName || 'Usuario');
    // Update status bar
    // status via toast
    // Save visited flag per user
    if (!S.apartments) S.apartments = {};
    const uid = S.userName || 'default';
    S.apartments[uid] = S.apartments[uid] || {};
    S.apartments[uid].visited = true;
    guardarDatos();
    applyEquippedRoom();
  showToast('🏠 Bienvenido a tu apartamento, ' + (S.userName || '') + '!');
  } else {
    // Apt slides right, city comes back from left
    aptEl.className  = 'scene scene-hidden-right';
    cityEl.className = 'scene scene-active';
    SCENE.current = 'city';
    // Move city bubble back to APT zone
    _moveBubbleTo('apt');
    // status via toast
    showToast('🌆 De vuelta en Life OS World');
  }
  // Resize scene wrapper to active scene height
  _syncSceneHeight();
}

function _syncAptBubble() {
  const ab = document.getElementById('apt-bubble');
  if (!ab) return;
  ab.textContent = W.bubble.emoji;
  ab.style.background = W.bubble.color;
  ab.style.boxShadow = `0 0 0 2px #fff, 0 0 14px ${W.bubble.color}`;
  // Also center bubble on entry
  ab.style.left = '50%';
  ab.style.top  = '50%';
}

function _syncSceneHeight() {
  // Let CSS handle it — active scene is position:relative so it dictates height
  // Just trigger a small reflow for the wrapper
  const wrapper = document.getElementById('world-scene');
  if (wrapper) wrapper.style.minHeight = '';
}

