/* ── Get friends at a zone — integrado con sistema real de Aliados ──
   Reglas de privacidad:
     Mi privacidad = 'private'  → invisible, tampoco veo a nadie
     Amigo privacy = 'private'  → invisible para mí
     Amigo privacy = 'friends'  → solo visible si es mi aliado real
     Amigo privacy = 'public'   → visible para todos (nombre anónimo)
*/
const MOCK_FRIENDS = [
  { id:'rodolfo', realName:'Rodolfo',   anonName:'Cyber_Nomad_42', zone:'banco',     color:'#f87171', emoji:'🚀', privacy:'friends', status:'Gestionando finanzas' },
  { id:'ana',     realName:'Ana K.',    anonName:'Pixel_Wave_07',  zone:'gym',       color:'#4ade80', emoji:'🦾', privacy:'friends', status:'Entrenando' },
  { id:'isom',    realName:'Isom_99',   anonName:'Flux_Agent_21',  zone:'biblioteca',color:'#a855f7', emoji:'📚', privacy:'public',  status:'Leyendo' },
];

// Cache rápido de UIDs/nombres aliados para el World
function _getAliadosSet() {
  // Incluye Cloud Allies (por UID) + contactos locales (por nombre)
  const set = new Set(S.aliadosUids || []);
  // Para MOCK_FRIENDS (demo), chequear por nombre real
  (S.aliados || []).forEach(a => { if (a.nombre) set.add(a.nombre.toLowerCase()); });
  return set;
}

function _getFriendsAtZone(zoneId) {
  // Si mi privacidad es 'private', soy invisible → tampoco veo a nadie
  if (W && W.privacy === 'private') return [];

  const aliadosSet = _getAliadosSet();

  return MOCK_FRIENDS
    .filter(f => f.zone === zoneId)
    .filter(f => f.privacy !== 'private') // invisibles en privado
    .filter(f => {
      // Si este amigo está en 'friends', solo aparece si es mi aliado
      if (f.privacy === 'friends') {
        return aliadosSet.has(f.id) ||
               aliadosSet.has(f.realName.toLowerCase()) ||
               (f.uid && aliadosSet.has(f.uid));
      }
      // 'public' → visible para todos
      return true;
    })
    .map(f => {
      const displayName = (f.privacy === 'public') ? f.anonName : f.realName;
      return { ...f, displayName };
    });
}

