/* ── Init: ensure defaults in S ── */
function initRoomShopState() {
  if (!S.unlockedRooms) S.unlockedRooms = ['starter_basic','starter_soft'];
  if (!S.equippedRoom)  S.equippedRoom  = 'starter_basic';
}

/* ── Open shop ── */
function openRoomShop() {
  initRoomShopState();
  renderShop();
  const el = document.getElementById('room-shop-overlay');
  if (el) el.classList.add('open');
  document.getElementById('shop-exp-display').textContent = S.xp || 0;
}

function closeRoomShop() {
  document.getElementById('room-shop-overlay')?.classList.remove('open');
}

function shopOverlayClick(e) {
  if (e.target === document.getElementById('room-shop-overlay')) closeRoomShop();
}

/* ── Render shop grid ── */
function renderShop() {
  initRoomShopState();
  const container = document.getElementById('shop-content');
  if (!container) return;

  // Group by tier
  const tiers = {};
  ROOMS_STORE.forEach(r => { (tiers[r.tier] = tiers[r.tier]||[]).push(r); });

  let html = '';
  Object.keys(tiers).sort().forEach(tier => {
    const meta = TIER_META[tier];
    html += `<div class="shop-tier-label" style="color:${meta.color}">${meta.label}</div>`;
    html += '<div class="shop-grid">';
    tiers[tier].forEach(room => {
      const unlocked  = S.unlockedRooms.includes(room.id);
      const equipped  = S.equippedRoom === room.id;
      const canAfford = (S.xp || 0) >= room.precio;
      const free      = room.precio === 0;
      const imgSrc    = ROOM_IMAGES[room.id] || '';

      let btnHtml = '';
      if (equipped) {
        btnHtml = `<button class="room-btn room-btn-equipped" disabled>✅ Equipada</button>`;
      } else if (unlocked || free) {
        btnHtml = `<button class="room-btn room-btn-equip" onclick="equipRoom('${room.id}')">🏠 Equipar</button>`;
      } else if (canAfford) {
        btnHtml = `<button class="room-btn room-btn-unlock" onclick="unlockRoom('${room.id}',${room.precio})">
          🔓 Desbloquear · ${room.precio.toLocaleString()} XP</button>`;
      } else {
        btnHtml = `<button class="room-btn room-btn-locked" disabled>
          🔒 ${room.precio.toLocaleString()} XP</button>`;
      }

      html += `
        <div class="room-card ${equipped?'equipped':''} ${!unlocked&&!free?'locked':''}" id="rcard-${room.id}">
          ${equipped ? '<div class="equipped-badge">EQUIPADA</div>' : ''}
          ${room.exotic ? '<div class="exotic-badge">★ EXÓTICA</div>' : ''}
          ${imgSrc
            ? `<img class="room-thumb" src="${imgSrc}" alt="${room.nombre}" loading="lazy"/>`
            : `<div class="room-thumb-placeholder">${room.emoji}</div>`}
          <div class="room-info">
            <div class="room-name">${room.emoji} ${room.nombre}</div>
            <div class="room-tipo ${TIPO_CLS[room.tipo]||''}">${room.tipo}</div>
            ${btnHtml}
          </div>
        </div>`;
    });
    html += '</div>';
  });

  container.innerHTML = html;
  document.getElementById('shop-exp-display').textContent = (S.xp||0).toLocaleString();
}

/* ── Equip a room (already unlocked) ── */
function equipRoom(roomId) {
  initRoomShopState();
  S.equippedRoom = roomId;
  // Change apartment background
  const img = document.getElementById('apt-bg');
  if (img && ROOM_IMAGES[roomId]) img.src = ROOM_IMAGES[roomId];
  guardarDatos();
  renderShop();
  showToast('🏠 Habitación equipada');
}

/* ── Unlock + equip a room ── */
function unlockRoom(roomId, precio) {
  initRoomShopState();
  if ((S.xp||0) < precio) { showToast('❌ XP insuficiente'); return; }
  S.xp -= precio;
  S.unlockedRooms.push(roomId);
  updateXP();
  guardarDatos();
  equipRoom(roomId);
  showToast(`🔓 ¡Habitación desbloqueada! −${precio.toLocaleString()} XP`);
}

/* ── Apply equipped room on apartment open ── */
function applyEquippedRoom() {
  initRoomShopState();
  const img = document.getElementById('apt-bg');
  if (img && S.equippedRoom && ROOM_IMAGES[S.equippedRoom]) {
    img.src = ROOM_IMAGES[S.equippedRoom];
  }
}

/* ═══════════════════════════════════════════════════
   DEMO FRIEND BUBBLES — example presence on city map
═══════════════════════════════════════════════════ */
const DEMO_FRIENDS = [
  { id:'f-rodolfo', name:'Rodolfo',     anonName:'Cyber_Nomad_42', emoji:'🚀', color:'#f87171',
    zones:['banco','gym','estadio','banco'], privacy:'friends' },
  { id:'f-ana',     name:'Ana K.',      anonName:'Pixel_Wave_07',  emoji:'🦾', color:'#4ade80',
    zones:['gym','biblioteca','cafe','gym'], privacy:'friends' },
  { id:'f-isom',    name:'Isom_99',     anonName:'Flux_Agent_21',  emoji:'📚', color:'#c084fc',
    zones:['lab','banco','config','lab'],    privacy:'public' },
];

// Zone center positions (% of map image)
const ZONE_CENTERS = {
  gym:        { l:24, t:26 },
  banco:      { l:18, t:37 },
  apt:        { l:44, t:21 },
  estadio:    { l:84, t:52 },
  lab:        { l: 5, t:47 },
  cafe:       { l:19, t:76 },
  biblioteca: { l:57, t:63 },
  config:     { l:80, t:79 },
};

let _friendTimers = [];

function spawnFriendBubbles() {
  const mapArea = document.getElementById('world-map-area');
  if (!mapArea) return;
  // Remove any existing
  document.querySelectorAll('.friend-bubble').forEach(el => el.remove());
  _friendTimers.forEach(t => clearTimeout(t));
  _friendTimers = [];

  // Si la privacidad del usuario es 'private', no mostrar ninguna burbuja de amigos
  if (W && W.privacy === 'private') return;

  DEMO_FRIENDS.forEach((f, fi) => {
    // Determine display name based on privacy
    const myFriendIds = ['f-rodolfo','f-ana','f-isom']; // all are "friends" in demo
    const displayName = (f.privacy === 'public') ? f.anonName : f.name;

    // Create bubble element
    const el = document.createElement('div');
    el.className = 'friend-bubble';
    el.id = f.id;
    el.dataset.name = displayName;
    el.textContent = f.emoji;
    el.style.width  = '30px';
    el.style.height = '30px';
    el.style.background = f.color;
    el.style.boxShadow = `0 0 0 2px #fff, 0 0 12px ${f.color}`;
    // Start at first zone
    const startZone = ZONE_CENTERS[f.zones[0]] || ZONE_CENTERS.banco;
    el.style.left = startZone.l + '%';
    el.style.top  = startZone.t + '%';
    mapArea.appendChild(el);

    // Animate through zones with staggered timing
    let zoneIdx = 0;
    const moveNext = () => {
      zoneIdx = (zoneIdx + 1) % f.zones.length;
      const z = ZONE_CENTERS[f.zones[zoneIdx]];
      if (!z) return;
      el.style.left = (z.l + (fi * 1.5 - 1)) + '%'; // slight offset so they don't overlap
      el.style.top  = (z.t + (fi * 1.2 - 1)) + '%';
      // update MOCK_FRIENDS zone for tooltip
      const mock = MOCK_FRIENDS.find(m => m.realName === f.name || m.anonName === f.anonName);
      if (mock) mock.zone = f.zones[zoneIdx];
      const t = setTimeout(moveNext, 5000 + fi * 1800 + Math.random() * 2000);
      _friendTimers.push(t);
    };
    // stagger initial start
    const t0 = setTimeout(moveNext, 2000 + fi * 2200);
    _friendTimers.push(t0);
  });
}

