/* ═══════════════════════════════════════════════
   APT ZONE ENGINE — move bubble, tooltip, nav
═══════════════════════════════════════════════ */
function aptZoneClick(id) {
  const zone = APT_ZONES[id];
  if (!zone) return;
  _aptCurrentZone = id;
  _moveAptBubbleTo(id);
  showToast(`${zone.emoji} ${zone.label}`);
  _showAptTooltip(id, zone);
}

function _moveAptBubbleTo(id) {
  const b   = document.getElementById('apt-bubble');
  const zEl = document.getElementById('apt-zone-' + id);
  if (!b || !zEl) return;
  const l  = parseFloat(zEl.style.left);
  const t  = parseFloat(zEl.style.top);
  const zw = zEl.offsetWidth  || 64;
  const bw = 26;
  const parent = b.parentElement;
  if (!parent) return;
  b.style.left = (l + (zw / 2 - bw / 2) / parent.offsetWidth  * 100) + '%';
  b.style.top  = (t + (zEl.offsetHeight || 64) * 0.05 / parent.offsetHeight * 100) + '%';
}

function _showAptTooltip(id, zone) {
  const tt  = document.getElementById('apt-tooltip');
  const zEl = document.getElementById('apt-zone-' + id);
  if (!tt || !zEl) return;
  const titleEl = document.getElementById('apt-tt-title');
  const descEl  = document.getElementById('apt-tt-desc');
  if (titleEl) titleEl.textContent = zone.emoji + ' ' + zone.label;
  if (descEl)  descEl.textContent  = zone.desc;
  const mapW = zEl.parentElement ? zEl.parentElement.offsetWidth  : 300;
  const mapH = zEl.parentElement ? zEl.parentElement.offsetHeight : 300;
  let ttL = parseFloat(zEl.style.left) / 100 * mapW + 72;
  let ttT = parseFloat(zEl.style.top)  / 100 * mapH;
  if (ttL + 170 > mapW) ttL = parseFloat(zEl.style.left) / 100 * mapW - 175;
  if (ttT + 90  > mapH) ttT = mapH - 96;
  tt.style.left = Math.max(4, ttL) + 'px';
  tt.style.top  = Math.max(4, ttT) + 'px';
  tt.classList.remove('hidden');
  clearTimeout(tt._timer);
  tt._timer = setTimeout(() => tt.classList.add('hidden'), 4000);
}

function aptNavToZone() {
  if (!_aptCurrentZone) return;
  const zone = APT_ZONES[_aptCurrentZone];
  if (!zone) return;
  closeApartment();
  navigate(zone.page);
}

