function confirmAccountDeletion() {
  const overlay = document.getElementById('delete-confirm-overlay');
  if (overlay) overlay.remove();

  let userEmail = '—';
  try {
    const session = JSON.parse(localStorage.getItem('lifeos_session') || '{}');
    userEmail = session.email || _auth?.currentUser?.email || '—';
  } catch(e) {}

  // ── Borrar datos locales — limpieza completa ──
  try {
    // Datos principales
    localStorage.removeItem('lifeos_cache_v3');
    localStorage.removeItem('lifeos_session');
    localStorage.removeItem('lifeos_users');
    sessionStorage.removeItem('lifeos_session_temp');
    // Flags de onboarding (_onbc_*)
    Object.keys(localStorage).filter(k => k.startsWith('_onbc_')).forEach(k => localStorage.removeItem(k));
    // Flags de módulos
    ['_aprende_welcomed','_plan_aliados_explained','_seed_completed',
     '_gemelo_consent','lifeos_accent','lifeos_theme'].forEach(k => localStorage.removeItem(k));
    // Cualquier otra clave con prefijo lifeos_
    Object.keys(localStorage).filter(k => k.startsWith('lifeos_')).forEach(k => localStorage.removeItem(k));
  } catch(e) {}

  showToast('🗑️ Datos locales eliminados');

  // ── Borrar datos en Firestore + cuenta Firebase ──
  if (CLOUD_ENABLED && _auth?.currentUser) {
    const fbUser = _auth.currentUser;
    const uid    = fbUser.uid;
    Promise.all([
      _userRef(uid).delete().catch(e => { console.warn('Firestore user delete error:', e); }),
      _profileRef(uid).delete().catch(e => { console.warn('Firestore profile delete error:', e); }),
    ]).then(() => {
      return fbUser.delete();
    }).then(() => {
      showToast('✅ Cuenta eliminada completamente del servidor');
    }).catch(err => {
      // Firebase Auth delete can fail if session is old — send email fallback
      console.warn('Firebase Auth delete error:', err);
      showToast('⚠️ Datos locales eliminados. Solicitud de cancelación enviada al servidor.');
      const subject = encodeURIComponent('Solicitud de Eliminación de Cuenta — Life OS');
      const body    = encodeURIComponent('Nombre: \nCorreo registrado: ' + userEmail +
        '\n\nSolicito la eliminación total e irreversible de mi cuenta y toda mi información almacenada en el servidor, conforme al Art. 22–35 de la LFPDPPP.\n\nError técnico al intentar eliminación automática: ' + (err?.message || 'desconocido'));
      setTimeout(() => {
        window.location.href = 'mailto:privacidad@lifeos.app?subject=' + subject + '&body=' + body;
      }, 1200);
    });
  } else {
    // Sin Firebase — enviar solicitud por email
    showToast('⚠️ Datos locales eliminados. Revisa tu correo para confirmar la solicitud al servidor.');
    const subject = encodeURIComponent('Solicitud de Eliminación de Cuenta — Life OS');
    const body    = encodeURIComponent('Nombre: \nCorreo registrado: ' + userEmail +
      '\n\nSolicito la eliminación total e irreversible de mi cuenta y toda mi información almacenada en el servidor, conforme al Art. 22–35 de la LFPDPPP.');
    setTimeout(() => {
      window.location.href = 'mailto:privacidad@lifeos.app?subject=' + subject + '&body=' + body;
    }, 600);
  }

  setTimeout(() => {
    try { doLogout(); } catch(e) { location.reload(); }
  }, 2000);
}

async function exportLocalData() {
  try {
    let userData = JSON.parse(localStorage.getItem('lifeos_cache_v3') || '{}');
    // Si hay nube activa, obtener datos frescos
    if (CLOUD_ENABLED && _auth?.currentUser) {
      showToast('☁️ Descargando datos desde la nube...');
      try {
        const snap = await _userRef(_auth.currentUser.uid).get();
        if (snap.exists) {
          userData = snap.data();
          delete userData._updatedAt;
        }
      } catch(e) { /* usar caché local */ }
    }
    // Asegurar que xpHistory y campos adicionales estén incluidos
    if (userData && S.xpHistory && !userData.xpHistory) userData.xpHistory = S.xpHistory;
    if (userData && S.gymDays   && !userData.gymDays)   userData.gymDays   = S.gymDays;
    const data = {
      exportDate: new Date().toISOString(),
      app: 'Life OS',
      version: '3.1',
      source: CLOUD_ENABLED ? 'Firebase Firestore' : 'localStorage',
      notice: 'Exportación completa de datos personales conforme a Derechos ARCO — LFPDPPP Art. 22. Incluye todos los datos registrados por el usuario.',
      userData,
      sessionInfo: { email: _auth?.currentUser?.email || (JSON.parse(localStorage.getItem('lifeos_session')||'{}')).email || '—' },
      localFlags: {
        onboardingDismissed: Object.keys(localStorage).filter(k => k.startsWith('_onbc_')),
        aprendeWelcomed: !!localStorage.getItem('_aprende_welcomed'),
      },
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href     = url;
    a.download = 'lifeos_mis_datos_' + new Date().toISOString().slice(0, 10) + '.json';
    a.click();
    URL.revokeObjectURL(url);
    showToast('💾 Datos exportados — revisa tus descargas');
  } catch(e) {
    showToast('⚠️ Error al exportar datos');
  }
}
