/* ═══════════════════════════════════════════════════════════════
   NOTIFICACIONES PUSH — Service Worker + Web Push API
═══════════════════════════════════════════════════════════════ */

/**
 * registerPushNotifications — suscribe al usuario a notificaciones push
 * y guarda el fcm_token en Firestore users/{uid}
 */
async function registerPushNotifications(uid) {
  // Verificar soporte del navegador
  if (!('Notification' in window) || !('serviceWorker' in navigator)) {
    showToast('⚠️ Tu navegador no soporta notificaciones push.');
    return false;
  }
  if (!CLOUD_ENABLED || !uid) {
    showToast('⚠️ Notificaciones push requieren conexión a Firebase.');
    return false;
  }

  try {
    // Registrar Service Worker
    const registration = await navigator.serviceWorker.register('/sw.js');
    await navigator.serviceWorker.ready;

    // Solicitar permiso al usuario
    const permission = await Notification.requestPermission();

    if (permission === 'denied') {
      // Actualizar Firestore y notificar al usuario
      await _authDocRef(uid).update({ notifications_enabled: false }).catch(() => {});
      showToast('🔕 Notificaciones bloqueadas. Actívalas desde la configuración de tu navegador.');
      _updateNotifStatusUI('denied');
      return false;
    }

    if (permission !== 'granted') {
      _updateNotifStatusUI('default');
      return false;
    }

    // Suscribir con VAPID key
    const subscription = await registration.pushManager.subscribe({
      userVisibleOnly:      true,
      applicationServerKey: _urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
    });

    // Guardar token en Firestore (usar p256dh como identificador de sesión)
    const token = subscription.endpoint;
    await _authDocRef(uid).update({
      fcm_token:             token,
      notifications_enabled: true,
    });

    showToast('🔔 Notificaciones activadas — recibirás tu Daily Briefing cada mañana');
    _updateNotifStatusUI('granted');
    return true;

  } catch(e) {
    console.error('[Life OS] registerPushNotifications error:', e);
    showToast('⚠️ Error al activar notificaciones. Intenta de nuevo.');
    return false;
  }
}

// ── Helper: convertir VAPID key de base64 a Uint8Array ──
function _urlBase64ToUint8Array(base64String) {
  const padding  = '='.repeat((4 - base64String.length % 4) % 4);
  const base64   = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  const rawData  = window.atob(base64);
  const output   = new Uint8Array(rawData.length);
  for (let i = 0; i < rawData.length; ++i) output[i] = rawData.charCodeAt(i);
  return output;
}

/**
 * initNotificationsToggle — inicializa el toggle de notificaciones en Settings
 * uid: string — UID del usuario autenticado
 * userData: object — doc raíz users/{uid} de Firestore (puede ser null)
 */
function initNotificationsToggle(uid, userData) {
  const toggle   = document.getElementById('notifications-toggle');
  const statusEl = document.getElementById('notification-permission-status');
  const blockedMsg = document.getElementById('notif-blocked-msg');
  if (!toggle) return;

  // Reflejar estado guardado en Firestore
  const isEnabled = userData?.notifications_enabled === true;
  toggle.checked  = isEnabled;

  // Mostrar estado real del permiso del navegador
  const permission = ('Notification' in window) ? Notification.permission : 'unsupported';
  _updateNotifStatusUI(permission);

  // Si están bloqueadas en el navegador, deshabilitar el toggle y mostrar instrucciones
  if (permission === 'denied') {
    toggle.disabled = true;
    toggle.checked  = false;
    if (blockedMsg) blockedMsg.style.display = 'block';
    return;
  }

  // Al activar: llamar a registerPushNotifications
  toggle.addEventListener('change', async function() {
    if (this.checked) {
      const success = await registerPushNotifications(uid);
      if (!success) this.checked = false;
    } else {
      // Desactivar: desuscribir y actualizar Firestore
      try {
        if ('serviceWorker' in navigator) {
          const reg = await navigator.serviceWorker.ready;
          const sub = await reg.pushManager.getSubscription();
          if (sub) await sub.unsubscribe();
        }
        if (CLOUD_ENABLED && uid) {
          await _authDocRef(uid).update({ notifications_enabled: false }).catch(() => {});
        }
        _updateNotifStatusUI(Notification.permission);
        showToast('🔕 Notificaciones desactivadas');
      } catch(e) {
        console.warn('[Life OS] Desactivar notificaciones error:', e);
        showToast('⚠️ Error al desactivar notificaciones');
      }
    }
  });
}

/** Llama directamente a registerPushNotifications desde el botón de settings */
async function activarNotificaciones() {
  const uid = _auth?.currentUser?.uid;
  if (!uid) { showToast('⚠️ Inicia sesión primero'); return; }
  await registerPushNotifications(uid);
}

// ── Helper: actualizar texto de estado y botón en el UI ──
function _updateNotifStatusUI(permission) {
  const statusEl = document.getElementById('notification-permission-status');
  const btn      = document.getElementById('notif-activate-btn');
  if (!statusEl) return;
  const states = {
    granted: { text: '✓ Notificaciones activas', color: 'var(--green)' },
    denied:  { text: '🔕 Bloqueadas en el dispositivo', color: 'var(--red)' },
    default: { text: 'Permiso pendiente', color: 'var(--text3)' },
  };
  const s = states[permission] || states.default;
  statusEl.textContent = s.text;
  statusEl.style.color = s.color;
  if (btn) {
    if (permission === 'granted') {
      btn.textContent  = '✓ Activadas';
      btn.disabled     = true;
      btn.style.opacity = '.5';
      btn.style.cursor  = 'default';
    } else if (permission === 'denied') {
      btn.textContent  = '🔕 Bloqueadas';
      btn.disabled     = true;
      btn.style.opacity = '.4';
      btn.style.cursor  = 'default';
    } else {
      btn.textContent  = '🔔 Activar';
      btn.disabled     = false;
      btn.style.opacity = '1';
      btn.style.cursor  = 'pointer';
    }
  }
}

/* ═══════════════════════════════════════════════════════════════
   STRIPE — PAGO
═══════════════════════════════════════════════════════════════ */
// URL estática de respaldo (se usa si Cloud Functions no está disponible)
const STRIPE_CHECKOUT_URL = 'https://buy.stripe.com/REEMPLAZA_CON_TU_LINK';

/**
 * Reserva una ventana en blanco SINCRÓNICAMENTE (durante el gesto del usuario)
 * y devuelve una función que la redirige a la URL cuando esté lista.
 *
 * iOS Safari bloquea window.open() si se llama dentro de un callback async/Promise
 * porque ya no hay contexto de gesto. La solución: abrir la ventana antes del await
 * y redirigirla después.
 *
 * En PWA standalone iOS/Android, window.open no funciona en absoluto →
 * se usa un <a target="_blank"> programático que sí respeta el sistema.
 */
function _preparePaymentWindow() {
  const isStandalone = window.navigator.standalone === true ||
                       window.matchMedia('(display-mode: standalone)').matches;
  if (isStandalone) {
    // PWA standalone: window.open() está bloqueado en iOS.
    // window.location.href es el único método fiable para redirigir en este contexto.
    return function(url) { window.location.href = url; };
  }
  // Navegador normal: abrir ventana en blanco ahora (contexto síncrono)
  const win = window.open('', '_blank');
  return function(url) {
    if (win) { win.location.href = url; }
    else { window.open(url, '_blank'); } // fallback si fue bloqueada
  };
}

async function irAPagarStripe() {
  closeModal('modal-pago');
  showToast('🔐 Preparando sesión de pago...');
  // ⚠️ DEBE llamarse antes de cualquier await (contexto síncrono del click)
  const openUrl = _preparePaymentWindow();
  if (CLOUD_ENABLED && _functions && _auth?.currentUser) {
    try {
      const createSession = _functions.httpsCallable('createStripeCheckoutSession');
      const result        = await createSession({ priceId: STRIPE_PRICE_GENERAL });
      if (result.data?.url) { openUrl(result.data.url); return; }
    } catch(e) {
      console.warn('[Life OS] createStripeCheckoutSession error:', e);
      showToast('⚠️ Error al iniciar pago. Intenta de nuevo.');
      return;
    }
  }
  // Fallback: URL estática con referencia del usuario
  const _uid = S.userId || (_auth?.currentUser?.uid) || 'anonimo';
  openUrl(STRIPE_CHECKOUT_URL + '?client_reference_id=' + encodeURIComponent(_uid));
}

