/* ═══════════════════════════════════════════════════════════════
   RETENCIÓN DE DATOS — 30 DÍAS
═══════════════════════════════════════════════════════════════ */
/* ─── checkUserAccess — verifica si el usuario puede acceder a módulos premium ─── */
// Recibe el doc raíz users/{uid} (Firestore) y retorna { hasAccess, reason, daysRemaining }
function checkUserAccess(userData) {
  if (!userData) {
    // Sin datos de Firestore: fallback al estado local
    if (S.plan === 'pro') return { hasAccess: true, reason: 'pro', daysRemaining: null };
    return { hasAccess: true, reason: 'trial_active', daysRemaining: null };
  }
  // Usuario Pro — acceso total
  if (userData.is_pro === true || userData.role === 'premium' || userData.role === 'admin') {
    return { hasAccess: true, reason: 'pro', daysRemaining: null };
  }
  // Usuario bloqueado
  if (userData.role === 'blocked') {
    return { hasAccess: false, reason: 'blocked', daysRemaining: null };
  }
  // Verificar si el trial sigue activo
  if (userData.trial_ends_at) {
    const trialEnd = userData.trial_ends_at.toDate ? userData.trial_ends_at.toDate() : new Date(userData.trial_ends_at);
    const now      = new Date();
    const msLeft   = trialEnd - now;
    if (msLeft > 0) {
      const daysRemaining = Math.ceil(msLeft / 86400000);
      return { hasAccess: true, reason: 'trial_active', daysRemaining };
    }
    return { hasAccess: false, reason: 'trial_expired', daysRemaining: 0 };
  }
  // Sin campo trial_ends_at (usuario anterior a esta versión) → acceso libre
  return { hasAccess: true, reason: 'trial_active', daysRemaining: null };
}

/* ─── _logActivity — escribe a user_activity para alimentar el XP Chart ─── */
// type: 'task' | 'habit' | 'workout' | 'finance'
async function _logActivity(type, xpEarned, label) {
  if (!CLOUD_ENABLED || !_auth?.currentUser) return;
  try {
    await _activityRef(_auth.currentUser.uid).add({
      type,
      xp_earned:    xpEarned,
      completed_at: firebase.firestore.FieldValue.serverTimestamp(),
      label:        label || type,
    });
  } catch(e) {
    // Silencioso — no interrumpir flujo principal si falla el log
    console.warn('[Life OS] _logActivity error:', e);
  }
}

function checkTrialAndRetention() {
  if (S.plan === 'pro') return;
  // Si Firestore ya confirmó que el trial expiró, mostrar paywall directamente
  if (S.trialExpired) { showPaywallLockdown(); return; }
  if (!S.createdAt) { S.createdAt = today(); guardarDatos(); return; }
  const diffDays = Math.floor((Date.now() - new Date(S.createdAt)) / 86400000);
  // Ventana total: 60 días desde creación antes de purga automática
  const TOTAL_DAYS = 60;
  const TRIAL      = 7;   // Días de prueba antes de marcar expirado
  const trialEl    = document.getElementById('saas-trial-days');
  if (diffDays < TRIAL) {
    const rem = TRIAL - diffDays;
    if (trialEl) trialEl.textContent = rem + ' día' + (rem!==1?'s':'') + ' restante' + (rem!==1?'s':'');
    return;
  }
  if (!S.trialExpired) { S.trialExpired = true; guardarDatos(); }
  dismissTrialBanner();
  if (trialEl) { trialEl.textContent = '⚠️ Prueba expirada'; trialEl.style.color = 'var(--red)'; }
  // Mostrar el Paywall Lockdown inmersivo del Gemelo Potenciado
  setTimeout(showPaywallLockdown, 500);
  // Días restantes = 60 días desde creación menos los días transcurridos
  const daysLeft = Math.max(0, TOTAL_DAYS - diffDays);
  const alertEl  = document.getElementById('retention-alert');
  const daysNumEl = document.getElementById('retention-days');
  if (alertEl && daysNumEl) { daysNumEl.textContent = daysLeft; setTimeout(function(){ alertEl.classList.add('show'); }, 2000); }
  // Activar modo consulta
  setTimeout(function(){ activateConsultaMode(daysLeft); }, 600);
}

/* ═══════════════════════════════════════════════════════════════
   GEMELO — FLUJO DE OBSERVACIÓN DÍA 29 / DÍA 30
   Día 29 → badge no bloqueante + pre-generación del análisis
   Día 30 → leer gancho_intriga de Firestore e inyectar en paywall
═══════════════════════════════════════════════════════════════ */
async function checkGemeloObservationDay() {
  if (S.plan === 'pro') return;
  if (!S.createdAt) return;
  const diffDays = Math.floor((Date.now() - new Date(S.createdAt)) / 86400000);

  if (diffDays === 29) {
    // Día 29: badge informativo + pre-generar análisis en la nube (no bloqueante)
    setTimeout(_showGemeloDay29Badge, 3000);
    if (CLOUD_ENABLED && _functions && _auth?.currentUser) {
      _functions.httpsCallable('generateGemeloAnalysis')({}).catch(() => {});
    }
  } else if (diffDays >= 30) {
    // Día 30+: cargar gancho_intriga desde Firestore para el paywall
    if (CLOUD_ENABLED && _functions && _auth?.currentUser) {
      try {
        const res = await _functions.httpsCallable('getGemelo')({});
        if (res.data?.gancho_intriga) {
          S.gemelo.ganchoIntriga = res.data.gancho_intriga;
        }
      } catch(e) { /* fallback: _buildPaywallHookText usa datos locales */ }
    }
  }
}

function _showGemeloDay29Badge() {
  if (document.getElementById('gemelo-day29-badge')) return;
  const badge = document.createElement('div');
  badge.id = 'gemelo-day29-badge';
  badge.style.cssText = [
    'position:fixed;bottom:88px;left:50%;transform:translateX(-50%);',
    'background:rgba(212,175,55,.1);border:1px solid rgba(212,175,55,.35);',
    'border-radius:12px;padding:10px 20px;z-index:1200;',
    'color:rgba(212,175,55,.9);font-family:\'JetBrains Mono\',monospace;',
    'font-size:12px;text-align:center;backdrop-filter:blur(8px);',
    'animation:fadeInUp .5s ease;pointer-events:none;',
    'max-width:340px;line-height:1.5;',
  ].join('');
  badge.textContent = '✦ Tu Gemelo está terminando de procesar tu comportamiento de los últimos 30 días...';
  document.body.appendChild(badge);
  setTimeout(() => badge.remove(), 9000);
}

