// ── Helpers ───────────────────────────────────────────
function _isFirstWeek() {
  if (!S.createdAt) return true;
  return Math.floor((Date.now() - new Date(S.createdAt)) / 86400000) <= 7;
}

function _onbKey(id) { return '_onbc_' + id; }

// ── Build card HTML ───────────────────────────────────
function _buildOnbCard(id, isSub) {
  const d = _ONB_DATA[id]; if (!d) return null;
  const sub = isSub || d.isTab;
  const div = document.createElement('div');
  div.className = 'onb-card' + (sub ? ' onb-sub' : '');
  div.id = '_onbc_' + id;
  div.innerHTML = `
    <div class="onb-card-art" style="background:${d.grad}">
      <div class="onb-card-art-shine"></div>
      <div class="onb-card-art-inner">
        <span class="onb-em1">${d.em1}</span>
        <span class="onb-em2">${d.em2}</span>
      </div>
      <button class="onb-card-dismiss" onclick="dismissModuleCard('${id}')">✓ Entendido</button>
    </div>
    <div class="onb-card-body">
      <div class="onb-card-title" style="color:${d.color}">${d.title}</div>
      <div class="onb-card-sub">${d.sub}</div>
    </div>`;
  return div;
}

// ── Show card in a page or panel ──────────────────────
function showModuleCard(pageId) {
  if (!_isFirstWeek() && localStorage.getItem(_onbKey(pageId))) return;
  if (localStorage.getItem(_onbKey(pageId))) return;
  if (!_ONB_DATA[pageId]) return;
  const page = document.getElementById('page-' + pageId); if (!page) return;
  if (page.querySelector('.onb-card')) return;
  const card = _buildOnbCard(pageId, false); if (!card) return;
  const intro = page.querySelector('.module-intro-card');
  const header = page.querySelector('.page-header');
  const anchor = intro || header;
  if (anchor && anchor.nextSibling) page.insertBefore(card, anchor.nextSibling);
  else page.prepend(card);
}

function showSubCard(tabId) {
  if (!_isFirstWeek() && localStorage.getItem(_onbKey(tabId))) return;
  if (localStorage.getItem(_onbKey(tabId))) return;
  if (!_ONB_DATA[tabId]) return;
  const panel = document.getElementById('panel-' + tabId); if (!panel) return;
  if (panel.querySelector('.onb-card')) return;
  const card = _buildOnbCard(tabId, true); if (!card) return;
  const header = panel.querySelector('.page-header');
  if (header && header.nextSibling) panel.insertBefore(card, header.nextSibling);
  else panel.prepend(card);
}

// ── Dismiss ───────────────────────────────────────────
function dismissModuleCard(id) {
  localStorage.setItem(_onbKey(id), '1');
  const el = document.getElementById('_onbc_' + id);
  if (el) {
    el.style.transition = 'opacity .3s, transform .3s';
    el.style.opacity = '0'; el.style.transform = 'translateY(-10px)';
    setTimeout(() => el.remove(), 320);
  }
}

// ── Navigate hook (replaces old _hookNavigateTips) ────
function _hookNavigateTips(pageId) {
  setTimeout(() => showModuleCard(pageId), 250);
}

// ── ? Help panel ──────────────────────────────────────
function openHelpPanel() {
  const pageId = S.currentPage || 'dashboard';
  const d = _ONB_DATA[pageId];
  const panel = document.getElementById('help-panel');
  const backdrop = document.getElementById('help-backdrop');
  const label = document.getElementById('help-panel-label');
  if (!panel) return;
  if (label && d) label.textContent = 'AYUDA — ' + d.title;
  // Clear dynamic areas
  document.getElementById('help-panel-module-card').innerHTML = '';
  document.getElementById('help-panel-tutorial').innerHTML = '';
  panel.classList.add('open');
  backdrop.style.display = 'block';
}

function closeHelpPanel() {
  document.getElementById('help-panel')?.classList.remove('open');
  document.getElementById('help-backdrop').style.display = 'none';
  document.getElementById('help-panel-tutorial').innerHTML = '';
}

function reopenModuleCard() {
  const pageId = S.currentPage || 'dashboard';
  const d = _ONB_DATA[pageId]; if (!d) return;
  const container = document.getElementById('help-panel-module-card');
  document.getElementById('help-panel-tutorial').innerHTML = '';
  // Re-build card inline inside panel (no dismiss button — just info)
  container.innerHTML = `
    <div class="onb-card onb-sub" style="margin-top:4px;margin-bottom:0">
      <div class="onb-card-art" style="background:${d.grad};height:80px">
        <div class="onb-card-art-shine"></div>
        <div class="onb-card-art-inner">
          <span class="onb-em1" style="font-size:32px">${d.em1}</span>
          <span class="onb-em2" style="font-size:18px">${d.em2}</span>
        </div>
      </div>
      <div class="onb-card-body">
        <div class="onb-card-title" style="color:${d.color};font-size:11px">${d.title}</div>
        <div class="onb-card-sub" style="font-size:12px">${d.sub}</div>
      </div>
    </div>`;
}

function showTutorial() {
  const pageId = S.currentPage || 'dashboard';
  const d = _ONB_DATA[pageId]; if (!d || !d.tut) return;
  const container = document.getElementById('help-panel-tutorial');
  document.getElementById('help-panel-module-card').innerHTML = '';
  const steps = d.tut.map((s, i) =>
    `<div class="tut-step tut-s${i+1}"><span style="color:var(--accent);margin-right:4px">${i+1}.</span>${s.t}</div>`
  ).join('');
  container.innerHTML = `
    <div class="tut-scene">
      <div style="font-size:11px;color:var(--text3);margin-bottom:4px;font-family:'Orbitron',monospace;letter-spacing:.06em">TUTORIAL — ${d.title}</div>
      ${steps}
      <div class="tut-result">${d.res}</div>
    </div>`;
}

/* ═══════════════════════════════════════════════════════════════
   CORRECCIÓN ORTOGRÁFICA + CATEGORIZACIÓN + EMOJI EN TAREAS
═══════════════════════════════════════════════════════════════ */
const _SPELL = {
  'cosinar':'cocinar','cosinando':'cocinando','acer':'hacer','aser':'hacer',
  'exersicio':'ejercicio','esercicio':'ejercicio','empesar':'empezar',
  'empeçar':'empezar','nesecito':'necesito','nesesito':'necesito',
  'complar':'comprar','conprar':'comprar','reunion':'reunión',
  'trbajo':'trabajo','trabjo':'trabajo','conpletar':'completar','konpletar':'completar',
  'habia':'había','tambien':'también','despues':'después',
  'llavado':'lavado','yavado':'lavado','berde':'verde','baso':'vaso',
};

const _TASK_CATS = {
  'Físico':     [/gym|ejerci|entrena|corr|nadar|yoga|deporte|pesas|workout|cuerpo|salud/i],
  'Financiero': [/pagar|banco|transfer|cobrar|factura|presupuest|ahorro|invert|dinero|deuda|gasto/i],
  'Educación':  [/estudi|leer|libro|curso|aprender|clase|idioma|inglés/i],
  'Trabajo':    [/trabaj|reuni|proyecto|cliente|entrega|deadline|presentaci/i],
  'Espiritual': [/meditar|orar|reflexion|gratitud/i],
};

function _corregir(texto) {
  return texto.split(' ').map(function(w) {
    const l = w.toLowerCase().replace(/[.,!?;:]/g,'');
    if (_SPELL[l]) { const c = _SPELL[l]; return w[0]===w[0].toUpperCase() ? c[0].toUpperCase()+c.slice(1) : c; }
    return w;
  }).join(' ');
}

function _categorizarTarea(texto) {
  for (const cat in _TASK_CATS) { for (const p of _TASK_CATS[cat]) { if (p.test(texto)) return cat; } }
  return 'Personal';
}

function _tareaEmoji(texto) {
  const n = texto.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9\s]/g,'');
  const rules = [
    [/gym|ejerci|entrena|workout|pesas/,'🏋️'],[/corr|trotar|cardio/,'🏃'],[/camin|walk/,'🚶'],
    [/nada|swim|alberca/,'🏊'],[/bici|cicl/,'🚴'],[/yoga|medita|respira/,'🧘'],
    [/leer|libro|lectura/,'📖'],[/estudi|curso|aprender/,'🎓'],[/trabaj|reuni|proyecto/,'💼'],
    [/llamar|telefon/,'📞'],[/pagar|banco|cobrar/,'💳'],[/ahorrar|invert/,'💰'],
    [/comprar|mercado/,'🛒'],[/cocin|comer|desayun/,'🍽️'],[/dormir|sueno/,'😴'],
    [/escribir|diario|nota/,'📓'],[/doctor|cita/,'🏥'],[/limpiar|ordenar/,'🧹'],
    [/programar|codigo/,'💻'],[/familia|amigo|visitar/,'👨‍👩‍👧'],[/agua|hidratar/,'💧'],
    [/revisar|verificar|confirmar/,'✅'],[/planear|organizar/,'📌'],
  ];
  for (const [re, emoji] of rules) { if (re.test(n)) return emoji; }
  return '⭐';
}

function addTask() {
  const _inp = document.getElementById('t-name'); if (!_inp) return;
  const _raw = _inp.value.trim(); if (!_raw) return;
  const _cor = _corregir(_raw);
  if (_cor !== _raw) { _inp.value = _cor; showToast('✏️ Corregido: "' + _cor + '"'); }
  const _cat = _categorizarTarea(_cor);
  const _emo = _tareaEmoji(_cor);
  S.tasks.unshift({ id:uid(), name:_emo+' '+_cor, desc:document.getElementById('t-desc')&&document.getElementById('t-desc').value||'', date:document.getElementById('t-date')&&document.getElementById('t-date').value||'', time:document.getElementById('t-time')&&document.getElementById('t-time').value||'', done:false, categoria:_cat, originalInput:_raw });
  ['t-name','t-desc'].forEach(function(id){ const el=document.getElementById(id); if(el) el.value=''; });
  showToast(_emo + ' Tarea creada · ' + _cat);
  renderTasks(); updateDashboardTaskCount && updateDashboardTaskCount(); guardarDatos();
}

/* ═══════════════════════════════════════════════════════════════
   GEMELO POTENCIADO
═══════════════════════════════════════════════════════════════ */

// ── State helpers ─────────────────────────────────────
function _gState() {
  if (!S.gemelo) S.gemelo = { state:'idle', startDate:null, dataPoints:0, lastAnalysis:null, survivalTasks:{} };
  return S.gemelo;
}

function _countGemeloPoints() {
  return (S.habits||[]).length * 2 +
         (S.tasks||[]).filter(t=>t.done).length +
         (S.transactions||[]).length +
         (S.bitacora||[]).length +
         Math.min(30, S.checkInStreak||0);
}

function _gemeloDay() {
  const g = _gState();
  if (!g.startDate) return 0;
  return Math.min(30, Math.floor((Date.now() - new Date(g.startDate)) / 86400000));
}

function _gemeloWeekMsg(day) {
  if (day < 8)  return 'Tu Gemelo está conociendo tus patrones...';
  if (day < 16) return 'Detectando tendencias en tus decisiones...';
  if (day < 23) return 'Analizando áreas de crecimiento...';
  return 'Últimos ajustes — casi listo.';
}

function _gemPrecision() {
  const habits = S.habits||[];
  const rate = habits.length > 0 ? habits.filter(h=>(h.streak||0)>2).length/habits.length : 0;
  return Math.min(97, 58 +
    Math.round(rate*15) +
    ((S.transactions||[]).length > 4 ? 8 : 0) +
    ((S.checkInStreak||0) > 4 ? 9 : 0) +
    ((S.bitacora||[]).length > 1 ? 5 : 0) +
    Math.min(5, Math.floor((S.xp||0)/800)));
}

function _checkSurvival() {
  const g = _gState();
  if (g.state !== 'activated') return false;
  const habits = S.habits||[];
  const ratio = habits.length > 0 ? habits.filter(h=>h.completedToday).length/habits.length : 1;
  const weekXP = Object.entries(S.xpHistory||{}).slice(-7).reduce((s,[,v])=>s+v,0);
  return ratio < 0.2 && weekXP < 60;
}

// ── Init ──────────────────────────────────────────────
function initGemelo() {
  const g = _gState();
  // Advance state if observing and 30 days passed
  if (g.state === 'observing') {
    g.dataPoints = _countGemeloPoints();
    if (_gemeloDay() >= 30) g.state = 'ready';
  }
  renderGemelo();
}

// ── Main renderer ─────────────────────────────────────
function renderGemelo() {
  const c = document.getElementById('gemelo-container');
  if (!c) return;
  const g = _gState();
  if (_checkSurvival()) { c.innerHTML = _renderStateE(); return; }
  if (g.state === 'idle')       { c.innerHTML = _renderStateA(); return; }
  if (g.state === 'observing')  { c.innerHTML = _renderStateB(); return; }
  if (g.state === 'ready')      { c.innerHTML = _renderStateC(); return; }
  if (g.state === 'activated')  { c.innerHTML = _renderStateD(); return; }
}

// ── State A — Phases ──────────────────────────────────
function _renderStateA() {
  const phases = [
    { n:'FASE 01', em:'👁', title:'Observación silenciosa', sub:'30 días recopilando tus patrones reales.' },
    { n:'FASE 02', em:'🔗', title:'Cruce de datos', sub:'Hábitos, finanzas y check-ins analizados juntos.' },
    { n:'FASE 03', em:'💡', title:'La revelación', sub:'Un análisis narrativo que ninguna app puede replicar.' },
    { n:'FASE 04', em:'🪞', title:'Conversación continua', sub:'Tu Gemelo responde con contexto de tu historia real.' },
  ];
  const cards = phases.map(p=>`
    <div class="gemelo-phase-card">
      <div class="gemelo-phase-num">${p.n}</div>
      <div class="gemelo-phase-art">${p.em}</div>
      <div class="gemelo-phase-title">${p.title}</div>
      <div class="gemelo-phase-sub">${p.sub}</div>
    </div>`).join('');
  return `
    <div class="gemelo-header">
      <div class="gemelo-sigil">✦</div>
      <div class="gemelo-title">GEMELO POTENCIADO</div>
      <div class="gemelo-subtitle">Tu espejo inteligente. Observa en silencio y devuelve<br>un análisis que solo es posible con tu historia real.</div>
    </div>
    <div class="gemelo-phases">${cards}</div>
    <button class="gemelo-cta" onclick="activateGemeloObs()">✦ Activar período de observación</button>`;
}

// ── State B — Observation ─────────────────────────────
function _renderStateB() {
  const g = _gState();
  const day = _gemeloDay();
  const pct = Math.round((day/30)*100);
  const circ = 276.46; // 2π × 44
  const offset = circ * (1 - pct/100);
  const msg = _gemeloWeekMsg(day);
  const pts = g.dataPoints || _countGemeloPoints();
  const habits = S.habits||[];
  const txs = S.transactions||[];
  return `
    <div class="gemelo-header" style="padding-bottom:16px">
      <div class="gemelo-sigil" style="font-size:32px">✦</div>
      <div class="gemelo-title" style="font-size:15px">OBSERVANDO EN SILENCIO</div>
    </div>
    <div class="gemelo-ring-wrap">
      <svg class="gemelo-ring" viewBox="0 0 100 100">
        <circle class="gemelo-ring-track" cx="50" cy="50" r="44"/>
        <circle class="gemelo-ring-fill" cx="50" cy="50" r="44"
          stroke-dasharray="${circ}" stroke-dashoffset="${offset.toFixed(1)}"
          style="transform:rotate(-90deg);transform-origin:50% 50%"/>
        <text class="gemelo-ring-text" x="50" y="46" text-anchor="middle" dominant-baseline="middle" style="font-size:18px">${day}</text>
        <text class="gemelo-ring-sub" x="50" y="60" text-anchor="middle" style="font-size:7px">DE 30 DÍAS</text>
      </svg>
      <div class="gemelo-obs-msg">"${msg}"</div>
      <div class="gemelo-data-pills">
        <span class="gemelo-pill">🔥 ${habits.length} hábitos</span>
        <span class="gemelo-pill">📥 ${S.checkInStreak||0} check-ins</span>
        <span class="gemelo-pill">💰 ${txs.length} registros</span>
        <span class="gemelo-pill">📊 ${pts} puntos de datos</span>
      </div>
    </div>`;
}

// ── State C — Activation ──────────────────────────────
function _renderStateC() {
  const prec = _gemPrecision();
  const pts = _countGemeloPoints();
  const circ = 163.36; // 2π × 26
  const offset = circ * (1 - prec/100);
  return `
    <div class="gemelo-header">
      <div class="gemelo-sigil">✦</div>
      <div class="gemelo-title">TU GEMELO ESTÁ LISTO</div>
    </div>
    <div class="gemelo-precision">
      <svg width="100" height="100" viewBox="0 0 100 100" style="margin-bottom:12px">
        <circle cx="50" cy="50" r="26" fill="none" stroke="rgba(212,175,55,.1)" stroke-width="4"/>
        <circle cx="50" cy="50" r="26" fill="none" stroke="#d4af37" stroke-width="4"
          stroke-linecap="round" stroke-dasharray="${circ}" stroke-dashoffset="${offset.toFixed(1)}"
          style="transform:rotate(-90deg);transform-origin:50% 50%"/>
        <text x="50" y="50" text-anchor="middle" dominant-baseline="middle"
          style="font-family:Orbitron,monospace;font-size:14px;font-weight:900;fill:#d4af37">${prec}%</text>
      </svg>
      <div class="gemelo-precision-label">PRECISIÓN DEL ANÁLISIS</div>
      <div style="font-size:11px;color:rgba(212,175,55,.4);margin-top:4px">Basado en ${pts} puntos de datos de tu historial</div>
    </div>
    <div class="gemelo-reveal-quote">"Tu Gemelo ya sabe más de ti<br>de lo que crees."</div>
    <div class="gemelo-reveal-sub">El análisis está listo. Solo tú puedes verlo.</div>
    <button class="gemelo-cta" onclick="activateGemeloAnalysis()" style="margin-top:12px">✦ Revelar mi análisis</button>
    <button onclick="activateGemeloFree()" style="width:100%;margin-top:10px;background:none;border:none;color:rgba(212,175,55,.35);font-size:11px;cursor:pointer;padding:8px;font-family:Syne,sans-serif">Ver vista previa gratuita →</button>`;
}

// ── State D — Narrative analysis ──────────────────────
function _buildAnalysis() {
  const name = (S.userName||'').split(' ')[0] || 'tú';
  const habits = S.habits||[];
  const tasks  = S.tasks||[];
  const txs    = S.transactions||[];
  const topH   = [...habits].sort((a,b)=>(b.streak||0)-(a.streak||0))[0];
  const doneT  = tasks.filter(t=>t.done).length;
  const totalT = tasks.length;
  const compRate = totalT > 0 ? Math.round((doneT/totalT)*100) : 0;
  const totalGasto = txs.filter(t=>t.type==='salida').reduce((s,t)=>s+(t.amount||0),0);
  const streak = S.checkInStreak||0;
  const xp = S.xp||0;
  const goals = S.goals||[];

  return {
    fortalezas: [
      topH ? { icon:'🔥', title:'Una consistencia que pocos sostienen', body:`Tu hábito de "${topH.name}" acumula ${topH.streak||1} día${(topH.streak||1)>1?'s':''} consecutivos. En ese mismo período, la mayoría de personas que se proponen lo mismo ya abandonó. Tú no. Eso no es suerte — es identidad.` } : null,
      xp > 100 ? { icon:'⚡', title:'Energía acumulada que se ve', body:`${xp.toLocaleString()} XP no es un número de videojuego. Es la suma exacta de todas las decisiones pequeñas que tomaste cuando nadie te miraba, cuando no tenías ganas, cuando era más fácil no hacerlo.` } : null,
    ].filter(Boolean),

    patrones: [
      { icon:'🔍', title:`Tu ritmo real es del ${compRate}%`, body: compRate > 70
          ? `Completas ${compRate} de cada 100 cosas que te propones. Eso te ubica entre las personas más consistentes — pero también significa que el 100% te cuesta. ¿Qué pasa en ese ${100-compRate}% restante?`
          : compRate > 35
          ? `Completas el ${compRate}% de lo que te propones. La brecha del ${100-compRate}% no es flojera — suele ser un problema de cómo defines las tareas. ¿Son demasiado grandes? ¿Demasiado vagas?`
          : `El ${compRate}% de tus tareas llega a completarse. Tu Gemelo nota que creas más de lo que ejecutas. Eso no es malo — pero podría ser el patrón que más te cuesta en este momento.`
      },
      streak > 0 ? { icon:'📅', title:`${streak} días de presencia`, body:`Llevas ${streak} días haciendo check-in. Eso significa que ${streak} veces decidiste mirarte — lo cual ya es más de lo que la mayoría hace en un mes.` } : null,
    ].filter(Boolean),

    contradicciones: [
      goals.length > 0 && totalGasto > 0 ? {
        icon:'⚖️', title:'Lo que quieres vs. lo que haces',
        body:`Tienes ${goals.length} meta${goals.length>1?'s':''} registrada${goals.length>1?'s':''}. En paralelo, ${fmt(totalGasto)} en gastos documentados. Tu Gemelo no juzga ninguno de los dos — solo te muestra que existen al mismo tiempo. ¿Son consistentes?`
      } : {
        icon:'⚖️', title:'Aún sin suficientes datos aquí',
        body:`Registra metas y gastos para que tu Gemelo pueda detectar si tu dinero y tus objetivos van en la misma dirección.`
      },
    ],

    preguntas: [
      `¿Cuándo fue la última vez que completaste una semana perfecta? ¿Qué tenía ese período que no tiene este?`,
      tasks.filter(t=>!t.done).length > 0
        ? `Tienes ${tasks.filter(t=>!t.done).length} tareas pendientes ahora mismo. Si solo pudieras hacer una, ¿cuál cambiaría más las demás?`
        : `No tienes tareas pendientes en este momento. ¿Eso significa que estás al día, o que dejaste de capturar lo que tienes que hacer?`,
      `¿Tu Gemelo está viendo a la persona que quieres ser, o a la que has estado siendo?`,
    ],

    direccion: streak > 7
      ? `El próximo mes, tu único trabajo es proteger la racha de ${streak} días. Todo lo demás es secundario — la racha larga ya es tu activo más valioso en este momento.`
      : habits.length > 0
      ? `El próximo mes, elige un solo hábito y hazlo irrompible. Solo uno. La consistencia en una cosa no solo produce ese resultado — construye la confianza de que puedes hacer lo que te propones.`
      : `El próximo mes, crea tu primer hábito. No tres, no cinco — uno. Tan pequeño que te dé vergüenza lo fácil que es. Y hazlo todos los días.`,
  };
}

/** Renderiza el analisis_profundo como párrafos HTML con white-space:pre-wrap */
function _renderGemeloNarrativo(texto) {
  const paras = texto.split(/\n\n+/).filter(Boolean);
  const pHtml = paras.map(p =>
    `<p style="margin:0 0 26px;line-height:1.85;font-size:14.5px;color:rgba(255,255,255,.85);white-space:pre-wrap">${p}</p>`
  ).join('');
  return `
    <div class="gemelo-header" style="padding-bottom:20px">
      <div class="gemelo-sigil" style="font-size:36px">✦</div>
      <div class="gemelo-title" style="font-size:15px">TU ANÁLISIS</div>
      <div class="gemelo-subtitle" style="font-size:12px">Lo que tu Gemelo vio en estos 30 días</div>
    </div>
    <div style="padding:4px 0 8px">${pHtml}</div>
    <button onclick="resetGemelo()" style="width:100%;margin-top:12px;background:none;border:1px solid rgba(212,175,55,.15);border-radius:10px;color:rgba(212,175,55,.35);font-size:11px;cursor:pointer;padding:10px;font-family:Syne,sans-serif;transition:all .2s" onmouseover="this.style.color='rgba(212,175,55,.7)'" onmouseout="this.style.color='rgba(212,175,55,.35)'">↺ Iniciar nuevo ciclo de observación</button>`;
}

function _renderStateD() {
  // Usar análisis de IA si está disponible; si no, usar análisis local
  let a = null;
  const raw = S.gemelo?.analysisText;
  if (raw && typeof raw === 'string') {
    try { a = JSON.parse(raw); } catch(e) { /* fallback a análisis local */ }
  }

  // Nuevo formato del Gemelo Potenciado: {gancho_intriga, analisis_profundo}
  if (a && a.analisis_profundo) return _renderGemeloNarrativo(a.analisis_profundo);

  if (!a) a = _buildAnalysis();
  const forts = a.fortalezas.map(f=>`
    <div class="gemelo-insight">
      <div class="gemelo-insight-icon">${f.icon}</div>
      <div class="gemelo-insight-title">${f.title}</div>
      <div class="gemelo-insight-text">${f.body}</div>
    </div>`).join('') || `<div class="gemelo-insight"><div class="gemelo-insight-text">Agrega hábitos y tareas para desbloquear este análisis.</div></div>`;

  const pats = a.patrones.map(p=>`
    <div class="gemelo-insight">
      <div class="gemelo-insight-icon">${p.icon}</div>
      <div class="gemelo-insight-title">${p.title}</div>
      <div class="gemelo-insight-text">${p.body}</div>
    </div>`).join('');

  const cons = a.contradicciones.map(c=>`
    <div class="gemelo-insight">
      <div class="gemelo-insight-icon">${c.icon}</div>
      <div class="gemelo-insight-title">${c.title}</div>
      <div class="gemelo-insight-text">${c.body}</div>
    </div>`).join('');

  const qs = a.preguntas.map(q=>`<div class="gemelo-question">"${q}"</div>`).join('');

  return `
    <div class="gemelo-header" style="padding-bottom:20px">
      <div class="gemelo-sigil" style="font-size:36px">✦</div>
      <div class="gemelo-title" style="font-size:15px">TU ANÁLISIS</div>
      <div class="gemelo-subtitle" style="font-size:12px">Lo que tu Gemelo vio en estos 30 días</div>
    </div>
    <div class="gemelo-analysis">
      <div>
        <div class="gemelo-section-label">FORTALEZAS</div>
        ${forts}
      </div>
      <div>
        <div class="gemelo-section-label">PATRONES INVISIBLES</div>
        ${pats}
      </div>
      <div>
        <div class="gemelo-section-label">CONTRADICCIONES</div>
        ${cons}
      </div>
      <div>
        <div class="gemelo-section-label">PREGUNTAS DE CRECIMIENTO</div>
        ${qs}
      </div>
      <div>
        <div class="gemelo-section-label">DIRECCIÓN — PRÓXIMO MES</div>
        <div class="gemelo-direction">${a.direccion}</div>
      </div>
    </div>
    <button onclick="resetGemelo()" style="width:100%;margin-top:20px;background:none;border:1px solid rgba(212,175,55,.15);border-radius:10px;color:rgba(212,175,55,.35);font-size:11px;cursor:pointer;padding:10px;font-family:Syne,sans-serif;transition:all .2s" onmouseover="this.style.color='rgba(212,175,55,.7)'" onmouseout="this.style.color='rgba(212,175,55,.35)'">↺ Iniciar nuevo ciclo de observación</button>`;
}

// ── State E — Survival ────────────────────────────────
function _renderStateE() {
  const g = _gState();
  const tasks = ['Beber 2 vasos de agua', 'Salir a caminar 10 minutos', 'Una sola cosa importante'];
  const st = g.survivalTasks || {};
  const items = tasks.map((t,i)=>{
    const done = st[i];
    return `<div class="gemelo-survival-task" onclick="toggleSurvivalTask(${i})">
      <div class="gemelo-survival-check ${done?'done':''}">${done?'✓':''}</div>
      <span style="font-size:13px;color:${done?'rgba(255,149,128,.5)':'rgba(240,220,200,.85)'};${done?'text-decoration:line-through':''}">${t}</span>
    </div>`;
  }).join('');
  return `
    <div class="gemelo-survival">
      <div class="gemelo-survival-header">
        <div class="gemelo-survival-icon">🧡</div>
        <div>
          <div class="gemelo-survival-title">MODO SUPERVIVENCIA</div>
          <div class="gemelo-survival-sub">Tu Gemelo detectó una semana difícil. Solo lo esencial.</div>
        </div>
      </div>
      <div style="font-size:13px;color:rgba(255,149,128,.6);margin-bottom:14px;font-style:italic;line-height:1.6">"No tienes que ser perfecto esta semana.<br>Solo tienes que seguir."</div>
      ${items}
      <button onclick="exitSurvival()" style="width:100%;margin-top:16px;background:none;border:1px solid rgba(255,100,80,.2);border-radius:10px;color:rgba(255,149,128,.5);font-size:11px;cursor:pointer;padding:10px;font-family:Syne,sans-serif">Ya estoy mejor — salir del modo supervivencia</button>
    </div>`;
}

// ── Actions ───────────────────────────────────────────
function activateGemeloObs() {
  // Reset consent checkbox and show consent modal before activating (modo voluntario)
  window._gemeloForced = false;
  const cb = document.getElementById('gemelo-consent-cb');
  if (cb) cb.checked = false;
  const btn = document.getElementById('gemelo-consent-btn');
  if (btn) { btn.disabled = true; btn.style.opacity = '.45'; btn.style.cursor = 'not-allowed'; }
  const cancelBtn = document.getElementById('gemelo-cancel-btn');
  if (cancelBtn) cancelBtn.style.display = ''; // Mostrar botón cancelar en modo voluntario
  openModal('modal-gemelo-consent');
}
function toggleGemeloConsentBtn() {
  const cb  = document.getElementById('gemelo-consent-cb');
  const btn = document.getElementById('gemelo-consent-btn');
  if (!btn) return;
  const ok = !!(cb && cb.checked);
  btn.disabled      = !ok;
  btn.style.opacity = ok ? '1' : '.45';
  btn.style.cursor  = ok ? 'pointer' : 'not-allowed';
}
function openGemeloFirstSessionModal() {
  // Modo forzado: no permite cancelar, se muestra en primera sesión
  window._gemeloForced = true;
  const cb  = document.getElementById('gemelo-consent-cb');
  const btn = document.getElementById('gemelo-consent-btn');
  const cancelBtn = document.getElementById('gemelo-cancel-btn');
  if (cb)  cb.checked = false;
  if (btn) { btn.disabled = true; btn.style.opacity = '.45'; btn.style.cursor = 'not-allowed'; }
  if (cancelBtn) {
    cancelBtn.style.display   = 'none'; // Ocultar en modo forzado
  }
  openModal('modal-gemelo-consent');
}

function confirmGemeloActivation() {
  const cb = document.getElementById('gemelo-consent-cb');
  if (!cb || !cb.checked) return;
  closeModal('modal-gemelo-consent');
  S.gemelo = { state:'observing', startDate:today(), dataPoints:_countGemeloPoints(), lastAnalysis:null, survivalTasks:{}, consentDate:new Date().toISOString() };
  guardarDatos();
  renderGemelo();
  showToast('✦ Observación iniciada — 30 días');
  // Si era activación forzada de primera sesión, continuar al onboarding
  if (window._gemeloForced) {
    window._gemeloForced = false;
    const cancelBtn = document.getElementById('gemelo-cancel-btn');
    if (cancelBtn) cancelBtn.style.display = ''; // Restaurar para uso futuro
    setTimeout(() => {
      if (!S.onboardingDone && S.tasks.length === 0) openOnboarding();
    }, 400);
  }
}

async function activateGemeloAnalysis() {
  // Verificar acceso
  if (S.plan !== 'pro') { openModal('modal-pago'); return; }

  const g = _gState();

  // Si ya hay análisis generado, mostrar directamente
  if (g.analysisText) {
    g.state = 'activated';
    guardarDatos();
    renderGemelo();
    return;
  }

  // Sin Cloud Functions: fallback local
  if (!CLOUD_ENABLED || !_functions || !_auth?.currentUser) {
    g.state = 'activated';
    guardarDatos();
    renderGemelo();
    return;
  }

  // Mostrar pantalla de carga mientras Gemini procesa
  const c = document.getElementById('gemelo-container');
  if (c) c.innerHTML = `
    <div class="gemelo-header" style="padding:40px 20px;text-align:center">
      <div class="gemelo-sigil" style="font-size:48px;opacity:.7">✦</div>
      <div class="gemelo-title" style="margin-top:16px;font-size:14px">PROCESANDO</div>
      <div class="gemelo-subtitle" style="margin-top:8px;line-height:1.7">Tu Gemelo está analizando<br>${g.dataPoints||30} días de datos contigo...</div>
      <div style="margin-top:20px;width:60px;height:2px;background:linear-gradient(90deg,transparent,rgba(212,175,55,.6),transparent);margin-inline:auto;animation:pulse 1.5s ease-in-out infinite"></div>
    </div>`;

  try {
    const fn = _functions.httpsCallable('generateGemeloAnalysis');
    await fn({});
    // Cargar y mostrar el análisis generado
    await loadGemeloData();
  } catch(e) {
    console.error('[Life OS] generateGemeloAnalysis:', e);
    showToast('⚠️ No se pudo conectar con el Gemelo. Mostrando análisis local.');
    g.state = 'activated';
    guardarDatos();
    renderGemelo();
  }
}

async function activateGemeloFree() {
  // Verificar acceso mediante Cloud Function (anti-bypass server-side)
  await loadGemeloData();
}

/**
 * loadGemeloData — carga el análisis del Gemelo desde la Cloud Function getGemelo
 * Si status='ok':     renderiza el análisis en el contenedor existente
 * Si status='locked': muestra estado bloqueado y activa el paywall
 */
/* ── Terminal de transición post-pago (cubre la latencia de Gemini) ── */
function _showGemeloTerminalTransition(onComplete) {
  if (document.getElementById('gemelo-terminal')) return;
  const el = document.createElement('div');
  el.id = 'gemelo-terminal';
  el.style.cssText = [
    'position:fixed;inset:0;z-index:10000;',
    'background:#030509;display:flex;flex-direction:column;',
    'align-items:center;justify-content:center;padding:40px;',
  ].join('');
  el.innerHTML = `
    <div style="font-size:40px;margin-bottom:28px;animation:pwl-glyph-pulse 3s infinite">✦</div>
    <div id="gt-lines" style="font-family:'JetBrains Mono',monospace;font-size:13px;
      color:#00c17a;text-align:left;max-width:380px;width:100%;line-height:2"></div>`;
  document.body.appendChild(el);

  const msgs = [
    '> Sincronizando redes neuronales del Gemelo Potenciado...',
    '> Decodificando 30 días de patrones de comportamiento...',
    '> Cruzando variables: hábitos × finanzas × energía...',
    '> Generando análisis personalizado...',
    '> Casi listo...',
  ];
  const linesEl = el.querySelector('#gt-lines');
  let idx = 0;
  function next() {
    if (idx >= msgs.length) { onComplete && onComplete(); return; }
    const div = document.createElement('div');
    div.textContent = msgs[idx++];
    linesEl.appendChild(div);
    setTimeout(next, 1100);
  }
  next();
}

function _hideGemeloTerminalTransition(cb) {
  const el = document.getElementById('gemelo-terminal');
  if (!el) { cb && cb(); return; }
  el.style.transition = 'opacity .55s';
  el.style.opacity = '0';
  setTimeout(() => { el.remove(); cb && cb(); }, 560);
}

async function loadGemeloData() {
  const c = document.getElementById('gemelo-container');
  if (!c) return;

  // Sin Firebase Functions disponible: comportamiento previo (solo para desarrollo local)
  if (!CLOUD_ENABLED || !_functions || !_auth?.currentUser) {
    renderGemelo();
    return;
  }

  // Mostrar loader mientras se consulta la Function
  c.innerHTML = `
    <div style="text-align:center;padding:40px 20px">
      <div style="font-size:36px;margin-bottom:12px;animation:pulse 1.5s infinite">✦</div>
      <div style="font-family:'Orbitron',monospace;font-size:12px;color:var(--accent);letter-spacing:.08em">CONSULTANDO TU GEMELO...</div>
    </div>`;

  try {
    const getGemeloFn = _functions.httpsCallable('getGemelo');
    const result      = await getGemeloFn();
    const res         = result.data;

    if (res.status === 'locked') {
      c.innerHTML = `
        <div style="text-align:center;padding:32px 20px">
          <div style="font-size:48px;margin-bottom:14px">🔐</div>
          <div style="font-family:'Orbitron',monospace;font-size:14px;font-weight:900;color:var(--accent);margin-bottom:10px">GEMELO BLOQUEADO</div>
          <div style="font-size:13px;color:var(--text2);line-height:1.7;margin-bottom:20px;max-width:320px;margin-left:auto;margin-right:auto">
            ${res.message}
          </div>
          <button class="btn btn-a" onclick="openModal('modal-pago')" style="padding:12px 24px;font-size:13px">
            🔓 Activar Life OS Pro
          </button>
        </div>`;
      openModal('modal-pago');
      return;
    }

    if (res.status === 'ok') {
      if (res.analysis_ready && res.data) {
        // Análisis ya generado — mostrar directamente
        S.gemelo.state        = 'activated';
        S.gemelo.analysisText = res.data;
        renderGemelo();
      } else if (S.plan === 'pro') {
        // Usuario Pro pero análisis aún no generado → pantalla de transición + generar
        _showGemeloTerminalTransition(async () => {
          try {
            const genFn = _functions.httpsCallable('generateGemeloAnalysis');
            await genFn({});
            // Releer resultado recién guardado
            const r2 = await _functions.httpsCallable('getGemelo')({});
            if (r2.data?.analysis_ready && r2.data?.data) {
              S.gemelo.state        = 'activated';
              S.gemelo.analysisText = r2.data.data;
            }
          } catch(genErr) {
            console.error('[Life OS] generateGemeloAnalysis error:', genErr);
            // Mostrar error amigable con reintento — usuario ya pagó
            _hideGemeloTerminalTransition(() => {
              if (c) c.innerHTML = `
                <div style="text-align:center;padding:36px 20px">
                  <div style="font-size:40px;margin-bottom:14px">⚠️</div>
                  <div style="font-family:'Orbitron',monospace;font-size:13px;color:var(--accent);margin-bottom:10px">
                    ERROR AL GENERAR EL ANÁLISIS
                  </div>
                  <div style="font-size:13px;color:var(--text2);line-height:1.7;margin-bottom:20px;max-width:300px;margin:0 auto 20px">
                    Hubo un problema al conectar con el Gemelo. Tu acceso Pro está activo — puedes reintentar.
                  </div>
                  <button class="btn btn-a" onclick="loadGemeloData()" style="padding:12px 24px;font-size:13px">
                    ↺ Reintentar
                  </button>
                </div>`;
            });
            return;
          }
          _hideGemeloTerminalTransition(() => renderGemelo());
        });
      } else {
        S.gemelo.state           = res.observation_days >= 30 ? 'ready' : 'observing';
        S.gemelo.observationDays = res.observation_days || 0;
        renderGemelo();
      }
    }

  } catch(e) {
    console.error('[Life OS] loadGemeloData error:', e);
    showToast('⚠️ No se pudo cargar el Gemelo. Usando modo local.');
    renderGemelo();
  }
}

function resetGemelo() {
  S.gemelo = { state:'idle', startDate:null, dataPoints:0, lastAnalysis:null, survivalTasks:{} };
  guardarDatos();
  renderGemelo();
}

function toggleSurvivalTask(idx) {
  if (!S.gemelo.survivalTasks) S.gemelo.survivalTasks = {};
  S.gemelo.survivalTasks[idx] = !S.gemelo.survivalTasks[idx];
  guardarDatos();
  renderGemelo();
}

function exitSurvival() {
  // Force re-evaluate
  const habits = S.habits||[];
  const ratio = habits.length > 0 ? habits.filter(h=>h.completedToday).length/habits.length : 1;
  // Override: if user says they're ok, show analysis again
  renderGemelo();
  showToast('✦ Modo supervivencia desactivado');
}

