// ── State ─────────────────────────────────────────────
let _aprendeTab = 'conceptos';

// ── Init ──────────────────────────────────────────────
function initAprende() {
  const welcomed = localStorage.getItem('_aprende_welcomed');
  const welcome = document.getElementById('aprende-welcome-screen');
  const main = document.getElementById('aprende-main');
  if (!welcomed) {
    welcome.style.display = 'flex';
    main.style.display = 'none';
  } else {
    welcome.style.display = 'none';
    main.style.display = 'block';
    renderAprendeLayer(_aprendeTab);
  }
}

function aprendeWelcomeDone() {
  localStorage.setItem('_aprende_welcomed', '1');
  document.getElementById('aprende-welcome-screen').style.display = 'none';
  document.getElementById('aprende-main').style.display = 'block';
  renderAprendeLayer('conceptos');
}

// ── Tab switch ────────────────────────────────────────
function switchAprendeTab(layer) {
  _aprendeTab = layer;
  document.querySelectorAll('.aprende-tab').forEach(b => {
    b.classList.toggle('active', b.dataset.layer === layer);
  });
  renderAprendeLayer(layer);
}

// ── Render layer ──────────────────────────────────────
function renderAprendeLayer(layer) {
  const container = document.getElementById('aprende-layer-content');
  if (!container) return;
  if (layer === 'conceptos') container.innerHTML = _renderConceptos();
  else if (layer === 'guias') container.innerHTML = _renderGuias();
  // Noticias se cargan desde Firestore de forma asíncrona
  else if (layer === 'noticias') loadNoticias();
}

/**
 * loadNoticias — carga noticias activas desde Firestore colección 'noticias'
 * Ordena por published_at desc, límite 10
 * Muestra skeletons mientras carga, vacío si no hay datos
 */
async function loadNoticias() {
  const container = document.getElementById('aprende-layer-content');
  if (!container) return;

  // Esqueleto de carga (usando estilo de la sección aprende)
  container.innerHTML = `
    <div class="aprende-layer-head">
      <div class="aprende-layer-title" style="color:#fbbf24">🟠 ¿QUÉ PASÓ ESTA SEMANA?</div>
      <div class="aprende-layer-sub">Cargando noticias de IA...</div>
    </div>
    <div class="aprende-feed" id="noticias-feed">
      ${Array(3).fill(`
        <div class="aprende-feed-card" style="opacity:.4">
          <div class="aprende-feed-stripe" style="background:rgba(251,191,36,.3)"></div>
          <div class="aprende-feed-body">
            <div style="height:14px;border-radius:6px;background:rgba(255,255,255,.08);margin-bottom:10px;width:80%"></div>
            <div style="height:10px;border-radius:6px;background:rgba(255,255,255,.06);margin-bottom:6px;width:95%"></div>
            <div style="height:10px;border-radius:6px;background:rgba(255,255,255,.06);width:70%"></div>
          </div>
        </div>`).join('')}
    </div>`;

  // Sin Firebase disponible: usar datos estáticos
  if (!CLOUD_ENABLED || !_db) {
    container.innerHTML = _renderNoticias();
    return;
  }

  try {
    const snap = await _db.collection('noticias')
      .where('is_active', '==', true)
      .orderBy('published_at', 'desc')
      .limit(10)
      .get();

    // Estado vacío si no hay documentos en Firestore
    if (snap.empty) {
      container.innerHTML = `
        <div class="aprende-layer-head">
          <div class="aprende-layer-title" style="color:#fbbf24">🟠 ¿QUÉ PASÓ ESTA SEMANA?</div>
          <div class="aprende-layer-sub">Noticias de IA explicadas para todos.</div>
        </div>
        <div style="text-align:center;padding:40px 20px">
          <div style="font-size:40px;margin-bottom:12px">📭</div>
          <div style="font-size:13px;color:var(--text2);margin-bottom:6px">No hay noticias publicadas esta semana.</div>
          <div style="font-size:11px;color:var(--text3)">Regresa pronto — actualizamos cada lunes.</div>
        </div>`;
      return;
    }

    // Renderizar noticias desde Firestore
    const categoryColors = {
      productividad: '#60a5fa',
      bienestar:     '#34d399',
      tecnologia:    '#a78bfa',
      finanzas:      '#f59e0b',
    };

    const feedItems = snap.docs.map(doc => {
      const n       = doc.data();
      const color   = categoryColors[n.category] || '#fbbf24';
      const dateStr = n.published_at?.toDate
        ? n.published_at.toDate().toLocaleDateString('es-MX', { day:'numeric', month:'short' })
        : 'Esta semana';
      return `
        <div class="aprende-feed-card">
          <div class="aprende-feed-stripe" style="background:${color}"></div>
          ${n.image_url ? `<img src="${escHtml(n.image_url)}" alt="" style="width:100%;height:120px;object-fit:cover;border-radius:8px 8px 0 0;margin-bottom:8px" loading="lazy" onerror="this.style.display='none'">` : ''}
          <div class="aprende-feed-body">
            <div style="margin-bottom:6px">
              <span style="font-size:10px;color:${color};font-family:'Orbitron',monospace;font-weight:700;letter-spacing:.06em;text-transform:uppercase">${escHtml(n.category || 'tecnología')}</span>
            </div>
            <div class="aprende-feed-title">${escHtml(n.title)}</div>
            <div class="aprende-feed-text">${escHtml(n.body)}</div>
            ${n.link ? `<a href="${escHtml(n.link)}" target="_blank" rel="noopener noreferrer"
              style="display:inline-block;margin-top:10px;font-size:11px;color:var(--accent);text-decoration:none;font-family:'JetBrains Mono',monospace">
              Ver artículo completo →
            </a>` : ''}
            <div class="aprende-feed-meta" style="margin-top:8px">
              <span class="aprende-chip chip-noticias">${dateStr}</span>
            </div>
          </div>
        </div>`;
    }).join('');

    container.innerHTML = `
      <div class="aprende-layer-head">
        <div class="aprende-layer-title" style="color:#fbbf24">🟠 ¿QUÉ PASÓ ESTA SEMANA?</div>
        <div class="aprende-layer-sub">Noticias de IA explicadas como si se las contaras a un familiar en la cena.</div>
      </div>
      <div class="aprende-feed">${feedItems}</div>`;

  } catch(e) {
    console.warn('[Life OS] loadNoticias error:', e);
    // Fallback a datos estáticos si Firestore falla
    container.innerHTML = _renderNoticias();
  }
}

// ── Layer 1 — Conceptos ───────────────────────────────
function _renderConceptos() {
  const cards = _CONCEPTOS.map(c => `
    <div class="aprende-card" onclick="openAprendeDetail('c','${c.id}')">
      <div class="aprende-card-art" style="background:${c.grad}">
        <div class="aprende-card-art-em">${c.em}</div>
      </div>
      <div class="aprende-card-body">
        <div class="aprende-card-title">${c.title}</div>
        <div class="aprende-card-sub">${c.sub}</div>
        <div class="aprende-card-meta">
          <span class="aprende-chip chip-conceptos">¿Qué es?</span>
          <span class="aprende-chip chip-time">⏱ ${c.time}</span>
        </div>
      </div>
    </div>`).join('');

  const feed = _CONCEPTOS.map(c => `
    <div class="aprende-feed-card" onclick="openAprendeDetail('c','${c.id}')" style="cursor:pointer">
      <div class="aprende-feed-stripe" style="background:#6366f1"></div>
      <div class="aprende-feed-body">
        <div class="aprende-feed-title">${c.em} ${c.title}</div>
        <div class="aprende-feed-text">${c.sub}</div>
        <div class="aprende-feed-meta">
          <span class="aprende-chip chip-conceptos">¿Qué es?</span>
          <span class="aprende-chip chip-time">⏱ ${c.time}</span>
        </div>
      </div>
    </div>`).join('');

  return `
    <div class="aprende-layer-head">
      <div class="aprende-layer-title" style="color:#818cf8">🔵 ¿QUÉ ES ESTO?</div>
      <div class="aprende-layer-sub">Conceptos básicos en lenguaje de todos los días — sin tecnicismos.</div>
    </div>
    <div class="aprende-hscroll">${cards}</div>
    <div class="aprende-feed">${feed}</div>`;
}

